import { describe, it, expect } from 'vitest';
import * as vscode from 'vscode';
import {
  getGraphViewUriKey,
  getGraphViewLocalResourceRoots,
} from '../../../src/extension/graphView/resourceRoots';

describe('graphView/resourceRoots', () => {
  describe('getGraphViewUriKey', () => {
    it('prefers fsPath over path and string conversion', () => {
      expect(
        getGraphViewUriKey({
          fsPath: '/test/fs-path',
          path: '/test/path',
          toString: () => 'uri-text',
        } as unknown as vscode.Uri)
      ).toBe('/test/fs-path');
    });

    it('falls back to path when fsPath is not available', () => {
      expect(
        getGraphViewUriKey({
          path: '/test/path',
          toString: () => 'uri-text',
        } as unknown as vscode.Uri)
      ).toBe('/test/path');
    });

    it('falls back to toString when neither fsPath nor path is available', () => {
      expect(
        getGraphViewUriKey({
          toString: () => 'uri-text',
        } as unknown as vscode.Uri)
      ).toBe('uri-text');
    });
  });

  describe('getGraphViewLocalResourceRoots', () => {
    it('includes the extension root', () => {
      const extensionUri = vscode.Uri.file('/test/extension');
      const roots = getGraphViewLocalResourceRoots(extensionUri, new Map(), undefined);

      expect(roots.map(uri => uri.fsPath)).toContain('/test/extension');
    });

    it('includes plugin extension roots', () => {
      const extensionUri = vscode.Uri.file('/test/extension');
      const roots = getGraphViewLocalResourceRoots(
        extensionUri,
        new Map([['plugin.external', vscode.Uri.file('/test/external-extension')]]),
        undefined
      );

      expect(roots.map(uri => uri.fsPath)).toContain('/test/external-extension');
    });

    it('includes workspace folder roots', () => {
      const extensionUri = vscode.Uri.file('/test/extension');
      const roots = getGraphViewLocalResourceRoots(
        extensionUri,
        new Map(),
        [{ uri: vscode.Uri.file('/test/workspace') }]
      );

      expect(roots.map(uri => uri.fsPath)).toContain('/test/workspace');
    });

    it('deduplicates roots that share the same URI key', () => {
      const extensionUri = vscode.Uri.file('/test/extension');
      const roots = getGraphViewLocalResourceRoots(
        extensionUri,
        new Map([
          ['plugin.same', extensionUri],
          ['plugin.external', vscode.Uri.file('/test/external-extension')],
        ]),
        [
          { uri: vscode.Uri.file('/test/workspace') },
          { uri: vscode.Uri.file('/test/workspace') },
        ]
      );

      expect(roots.map(uri => uri.fsPath)).toEqual([
        '/test/extension',
        '/test/external-extension',
        '/test/workspace',
      ]);
    });

    it('deduplicates roots using path keys when fsPath is not available', () => {
      const extensionUri = {
        path: '/test/extension',
        toString: () => 'extension-uri',
      } as unknown as vscode.Uri;
      const duplicatePluginUri = {
        path: '/test/extension',
        toString: () => 'plugin-uri',
      } as unknown as vscode.Uri;
      const workspaceUri = {
        path: '/test/workspace',
        toString: () => 'workspace-uri',
      } as unknown as vscode.Uri;

      const roots = getGraphViewLocalResourceRoots(
        extensionUri,
        new Map([['plugin.same', duplicatePluginUri]]),
        [{ uri: workspaceUri }],
      );

      expect(roots.map(getGraphViewUriKey)).toEqual([
        '/test/extension',
        '/test/workspace',
      ]);
    });

    it('handles undefined workspaceFolders gracefully', () => {
      const extensionUri = vscode.Uri.file('/test/extension');
      const roots = getGraphViewLocalResourceRoots(extensionUri, new Map(), undefined);

      expect(roots).toHaveLength(1);
    });
  });
});

import { describe, expect, it, vi } from 'vitest';
import { applyGraphControlMessage } from '../../../../../../src/extension/graphView/webview/settingsMessages/updates/graphControls';
import { createHandlers } from '../testSupport';

describe('settingsMessages/updates/graphControls', () => {
  it('updates graph control config maps and publishes refreshed controls', async () => {
    const handlers = createHandlers({
      getConfig: vi.fn(<T>(_: string, defaultValue: T): T => (
        ({ ...defaultValue, file: true } as T)
      )),
    });

    await expect(
      applyGraphControlMessage(
        { type: 'UPDATE_NODE_VISIBILITY', payload: { nodeType: 'package', visible: false } },
        handlers,
      ),
    ).resolves.toBe(true);

    expect(handlers.updateConfig).toHaveBeenCalledWith('nodeVisibility', {
      file: true,
      package: false,
    });
    expect(handlers.sendGraphControls).toHaveBeenCalledOnce();
  });

  it('updates each graph control message type with the matching config key', async () => {
    const handlers = createHandlers({
      getConfig: vi.fn(<T>(_: string, defaultValue: T): T => defaultValue),
    });

    await expect(
      applyGraphControlMessage(
        { type: 'UPDATE_EDGE_VISIBILITY', payload: { edgeKind: 'import', visible: false } },
        handlers,
      ),
    ).resolves.toBe(true);
    await expect(
      applyGraphControlMessage(
        { type: 'UPDATE_NODE_COLOR', payload: { nodeType: 'file', color: '#123456' } },
        handlers,
      ),
    ).resolves.toBe(true);
    await expect(
      applyGraphControlMessage(
        { type: 'UPDATE_EDGE_COLOR', payload: { edgeKind: 'import', color: '#abcdef' } },
        handlers,
      ),
    ).resolves.toBe(true);

    expect(handlers.updateConfig).toHaveBeenNthCalledWith(1, 'edgeVisibility', { import: false });
    expect(handlers.updateConfig).toHaveBeenNthCalledWith(2, 'nodeColors', { file: '#123456' });
    expect(handlers.updateConfig).toHaveBeenNthCalledWith(3, 'edgeColors', { import: '#abcdef' });
    expect(handlers.sendGraphControls).toHaveBeenCalledTimes(3);
  });

  it('returns false for unrelated messages without updating settings', async () => {
    const handlers = createHandlers();

    await expect(
      applyGraphControlMessage(
        { type: 'WEBVIEW_READY' } as never,
        handlers,
      ),
    ).resolves.toBe(false);

    expect(handlers.updateConfig).not.toHaveBeenCalled();
    expect(handlers.sendGraphControls).not.toHaveBeenCalled();
  });
});

