import { describe, expect, it, vi } from 'vitest';
import { runGraphViewTimelineIndex } from '../../../../../src/extension/graphView/timeline/indexing/run';

describe('graph view timeline execution', () => {
  it('indexes commit history, sends progress, and applies the resulting timeline state', async () => {
    const state = {
      gitAnalyzer: {
        indexHistory: vi.fn(async (onProgress, _signal, maxCommits) => {
          onProgress('scan', 1, maxCommits);
          return [
            { sha: '111', timestamp: 1, message: 'one', author: 'A', parents: [] },
            { sha: '222', timestamp: 2, message: 'two', author: 'B', parents: ['111'] },
          ];
        }),
      },
      indexingController: new AbortController(),
    };
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn((error: unknown) => String(error)),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(state, handlers);

    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'INDEX_PROGRESS',
      payload: { phase: 'scan', current: 1, total: 500 },
    });
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'TIMELINE_DATA',
      payload: {
        commits: [
          { sha: '111', timestamp: 1, message: 'one', author: 'A', parents: [] },
          { sha: '222', timestamp: 2, message: 'two', author: 'B', parents: ['111'] },
        ],
        currentSha: '222',
      },
    });
    expect(handlers.jumpToCommit).toHaveBeenCalledWith('222');
  });

  it('shows the no-commits message when indexing returns no commits', async () => {
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn((error: unknown) => String(error)),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(
      {
        gitAnalyzer: {
          indexHistory: vi.fn(async () => []),
        },
        indexingController: new AbortController(),
      },
      handlers,
    );

    expect(handlers.showInformationMessage).toHaveBeenCalledWith('No commits found to index');
    expect(handlers.jumpToCommit).not.toHaveBeenCalled();
  });

  it('reports non-abort indexing failures and invalidates the cache', async () => {
    const error = new Error('kaboom');
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn(() => 'kaboom'),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(
      {
        gitAnalyzer: {
          indexHistory: vi.fn(async () => {
            throw error;
          }),
        },
        indexingController: new AbortController(),
      },
      handlers,
    );

    expect(handlers.logError).toHaveBeenCalledWith('[CodeGraphy] Indexing failed:', error);
    expect(handlers.showErrorMessage).toHaveBeenCalledWith('Timeline indexing failed: kaboom');
    expect(handlers.sendMessage).toHaveBeenCalledWith({ type: 'CACHE_INVALIDATED' });
  });

  it('returns quietly for abort failures', async () => {
    const error = new Error('aborted');
    error.name = 'AbortError';
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn(() => 'aborted'),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(
      {
        gitAnalyzer: {
          indexHistory: vi.fn(async () => {
            throw error;
          }),
        },
        indexingController: new AbortController(),
      },
      handlers,
    );

    expect(handlers.logError).not.toHaveBeenCalled();
    expect(handlers.showErrorMessage).not.toHaveBeenCalled();
    expect(handlers.sendMessage).not.toHaveBeenCalledWith({ type: 'CACHE_INVALIDATED' });
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  sendGraphViewFavorites,
  toggleGraphViewFavorites,
} from '../../../src/extension/graphView/favorites';

describe('graphView/favorites', () => {
  it('delegates favorite toggles to the undoable action runner', async () => {
    const executeToggleFavoritesAction = vi.fn(async () => undefined);

    await toggleGraphViewFavorites(['src/app.ts'], {
      executeToggleFavoritesAction,
    });

    expect(executeToggleFavoritesAction).toHaveBeenCalledWith(['src/app.ts']);
  });

  it('sends the current favorites to the webview', () => {
    const sendMessage = vi.fn();
    const get = <T>(key: string, defaultValue: T): T => {
      if (key === 'favorites') {
        return ['src/app.ts'] as never as T;
      }

      return defaultValue;
    };

    sendGraphViewFavorites(
      {
        get,
      },
      sendMessage,
    );

    expect(sendMessage).toHaveBeenCalledWith({
      type: 'FAVORITES_UPDATED',
      payload: { favorites: ['src/app.ts'] },
    });
  });

  it('sends an empty favorites payload when no favorites are configured', () => {
    const sendMessage = vi.fn();
    const get = vi.fn(<T>(_key: string, defaultValue: T): T => defaultValue);

    sendGraphViewFavorites(
      {
        get,
      },
      sendMessage,
    );

    expect(get).toHaveBeenCalledWith('favorites', []);
    expect(get.mock.calls[0]?.[1]).toEqual([]);
    expect(sendMessage).toHaveBeenCalledWith({
      type: 'FAVORITES_UPDATED',
      payload: { favorites: [] },
    });
    expect(sendMessage.mock.calls[0]?.[0].payload.favorites).toEqual([]);
  });
});

import { describe, expect, it } from 'vitest';
import { buildGraphViewMergedGroups } from '../../../../src/extension/graphView/groups/merged';

describe('graphView/mergedGroups', () => {
  it('keeps user groups ahead of built-in and plugin defaults', () => {
    const groups = buildGraphViewMergedGroups(
      [{ id: 'user:src', pattern: 'src/**', color: '#ff0000' }],
      [{ id: 'default:*.json', pattern: '*.json', color: '#F9C74F' }],
      [
        {
          id: 'plugin:codegraphy.typescript:*.ts',
          pattern: '*.ts',
          color: '#3178C6',
        },
        {
          id: 'plugin:codegraphy.python:*.py',
          pattern: '*.py',
          color: '#3776AB',
        },
      ],
    );

    expect(groups).toEqual([
      { id: 'user:src', pattern: 'src/**', color: '#ff0000' },
      { id: 'default:*.json', pattern: '*.json', color: '#F9C74F' },
      { id: 'plugin:codegraphy.typescript:*.ts', pattern: '*.ts', color: '#3178C6' },
      { id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' },
    ]);
  });

  it('keeps plain ids untouched', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [{ id: 'plain', pattern: 'plain', color: '#123456' }],
      [],
    );

    expect(groups).toEqual([{ id: 'plain', pattern: 'plain', color: '#123456' }]);
  });

  it('does not infer a disabled empty section key from leading-colon ids', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [],
      [{ id: ':leading', pattern: ':leading', color: '#654321' }],
    );

    expect(groups).toEqual([{ id: ':leading', pattern: ':leading', color: '#654321' }]);
  });

  it('includes built-in and plugin defaults when no user groups exist', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [{ id: 'default:*.json', pattern: '*.json', color: '#F9C74F' }],
      [{ id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' }],
    );

    expect(groups).toEqual([
      { id: 'default:*.json', pattern: '*.json', color: '#F9C74F' },
      { id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' },
    ]);
  });

  it('applies persisted visibility overrides to built-in and plugin defaults', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [{ id: 'default:*.json', pattern: '*.json', color: '#F9C74F' }],
      [{ id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' }],
      {
        'default:*.json': false,
        'plugin:codegraphy.python:*.py': true,
      },
    );

    expect(groups).toEqual([
      { id: 'default:*.json', pattern: '*.json', color: '#F9C74F', disabled: true },
      { id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB', disabled: false },
    ]);
  });

  it('keeps unordered groups stable while moving ordered groups ahead of them', () => {
    const groups = buildGraphViewMergedGroups(
      [{ id: 'user:keep-first', pattern: 'src/**', color: '#111111' }],
      [
        { id: 'ordered', pattern: '*.ts', color: '#222222' },
        { id: 'default:keep-stable', pattern: '*.json', color: '#333333' },
      ],
      [{ id: 'plugin:keep-stable', pattern: '*.py', color: '#444444' }],
      {},
      ['ordered'],
    );

    expect(groups.map((group) => group.id)).toEqual([
      'ordered',
      'user:keep-first',
      'default:keep-stable',
      'plugin:keep-stable',
    ]);
  });

  it('preserves relative order when legend order does not mention either group', () => {
    const groups = buildGraphViewMergedGroups(
      [{ id: 'user:a', pattern: 'a/**', color: '#111111' }],
      [{ id: 'user:b', pattern: 'b/**', color: '#222222' }],
      [],
      {},
      ['ordered-only'],
    );

    expect(groups.map((group) => group.id)).toEqual(['user:a', 'user:b']);
  });
});

