import { describe, expect, it, vi } from 'vitest';
import {
  awaitGraphViewPluginActivation,
  ensureGraphViewAnalyzerInitialized,
} from '../../../../../src/extension/graphView/analysis/execution/initialize';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './fixtures';

describe('graph view analysis execution initialize', () => {
  it('returns true immediately when the analyzer is already initialized', async () => {
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer(),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(state.analyzer?.initialize).not.toHaveBeenCalled();
  });

  it('returns false when no analyzer exists', async () => {
    const state = createExecutionState();
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);
  });

  it('initializes the analyzer once and clears the cached promise', async () => {
    const initialize = vi.fn(async () => undefined);
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        initialize,
      }),
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(initialize).toHaveBeenCalledOnce();
    expect(state.analyzerInitialized).toBe(true);
    expect(state.analyzerInitPromise).toBeUndefined();
  });

  it('reuses an in-flight analyzer initialization promise', async () => {
    const initialize = vi.fn(async () => undefined);
    const analyzerInitPromise = Promise.resolve().then(() => undefined);
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        initialize,
      }),
      analyzerInitPromise,
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(initialize).not.toHaveBeenCalled();
    expect(state.analyzerInitialized).toBe(false);
    expect(state.analyzerInitPromise).toBe(analyzerInitPromise);
  });

  it('returns false when the request turns stale after plugin activation', async () => {
    const state = createExecutionState({
      installedPluginActivationPromise: Promise.resolve(),
    });
    const { handlers } = createExecutionHandlers({
      isAnalysisStale: vi.fn(() => true),
    });

    await expect(
      awaitGraphViewPluginActivation(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import { ensureGitAnalyzerForCachedTimeline } from '../../../../../src/extension/graphView/provider/timeline/warmup';

describe('ensureGitAnalyzerForCachedTimeline', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('skips warmup when the source already has a git analyzer', async () => {
    const createGitAnalyzer = vi.fn();
    const source = createSource({ _gitAnalyzer: { kind: 'git' } });

    await ensureGitAnalyzerForCachedTimeline(source as never, {
      createGitAnalyzer,
      getWorkspaceFolder: vi.fn(() => ({ uri: { fsPath: '/workspace' } } as never)),
    });

    expect(createGitAnalyzer).not.toHaveBeenCalled();
  });

  it('skips warmup when the source has no analyzer', async () => {
    const createGitAnalyzer = vi.fn();
    const getWorkspaceFolder = vi.fn(() => ({ uri: { fsPath: '/workspace' } } as never));

    await ensureGitAnalyzerForCachedTimeline(createSource() as never, {
      createGitAnalyzer,
      getWorkspaceFolder,
    });

    expect(getWorkspaceFolder).not.toHaveBeenCalled();
    expect(createGitAnalyzer).not.toHaveBeenCalled();
  });

  it('skips warmup when no git-analyzer factory is available', async () => {
    const getWorkspaceFolder = vi.fn(() => ({ uri: { fsPath: '/workspace' } } as never));
    const source = createSource({
      _analyzer: {
        initialize: vi.fn(async () => undefined),
        getPluginFilterPatterns: vi.fn(() => []),
        registry: { kind: 'registry' },
      },
      _analyzerInitialized: true,
    });

    await ensureGitAnalyzerForCachedTimeline(source as never, {
      createGitAnalyzer: undefined,
      getWorkspaceFolder,
    });

    expect(getWorkspaceFolder).not.toHaveBeenCalled();
    expect(source._gitAnalyzer).toBeUndefined();
  });

  it('skips warmup when no workspace folder is available', async () => {
    const createGitAnalyzer = vi.fn();
    const initialize = vi.fn(async () => undefined);
    const source = createSource({
      _analyzer: {
        initialize,
        getPluginFilterPatterns: vi.fn(() => []),
        registry: { kind: 'registry' },
      },
      _analyzerInitialized: true,
    });

    await ensureGitAnalyzerForCachedTimeline(source as never, {
      createGitAnalyzer,
      getWorkspaceFolder: vi.fn(() => undefined),
    });

    expect(initialize).not.toHaveBeenCalled();
    expect(createGitAnalyzer).not.toHaveBeenCalled();
  });

  it('creates the cached git analyzer without reinitializing an analyzer that is already ready', async () => {
    const initialize = vi.fn(async () => undefined);
    const analyzer = {
      registry: { kind: 'registry' },
      initialize,
      getPluginFilterPatterns: vi.fn(() => ['plugin-cache/**']),
    };
    const createGitAnalyzer = vi.fn(() => ({ kind: 'git-analyzer' } as never));
    const source = createSource({
      _analyzer: analyzer,
      _analyzerInitialized: true,
      _filterPatterns: ['dist/**'],
    });

    await ensureGitAnalyzerForCachedTimeline(source as never, {
      createGitAnalyzer,
      getWorkspaceFolder: vi.fn(() => ({ uri: { fsPath: '/workspace' } } as never)),
    });

    expect(initialize).not.toHaveBeenCalled();
    expect(createGitAnalyzer).toHaveBeenCalledOnce();
  });

  it('initializes the analyzer and creates a cached git analyzer with merged excludes', async () => {
    const initialize = vi.fn(async () => undefined);
    const analyzer = {
      registry: { kind: 'registry' },
      initialize,
      getPluginFilterPatterns: vi.fn(() => ['plugin-cache/**']),
    };
    const createGitAnalyzer = vi.fn(() => ({ kind: 'git-analyzer' } as never));
    const source = createSource({
      _analyzer: analyzer,
      _analyzerInitialized: false,
      _analyzerInitPromise: undefined,
      _installedPluginActivationPromise: Promise.resolve(),
      _filterPatterns: ['dist/**'],
    });

    await ensureGitAnalyzerForCachedTimeline(source as never, {
      createGitAnalyzer,
      getWorkspaceFolder: vi.fn(() => ({ uri: { fsPath: '/workspace' } } as never)),
    });

    expect(initialize).toHaveBeenCalledOnce();
    expect(createGitAnalyzer).toHaveBeenCalledWith(
      source._context,
      analyzer.registry,
      '/workspace',
      expect.arrayContaining(['plugin-cache/**', 'dist/**']),
    );
    expect(source._analyzerInitialized).toBe(true);
    expect(source._analyzerInitPromise).toBeUndefined();
    expect(source._gitAnalyzer).toEqual({ kind: 'git-analyzer' });
  });

  it('reuses an in-flight analyzer initialization promise instead of starting a second one', async () => {
    const initialize = vi.fn(async () => undefined);
    const analyzer = {
      registry: { kind: 'registry' },
      initialize,
      getPluginFilterPatterns: vi.fn(() => []),
    };
    const createGitAnalyzer = vi.fn(() => ({ kind: 'git-analyzer' } as never));
    const source = createSource({
      _analyzer: analyzer,
      _analyzerInitialized: false,
    });
    (source as { _analyzerInitPromise: Promise<void> | undefined })._analyzerInitPromise = Promise.resolve().then(() => {
      source._analyzerInitialized = true;
    });

    await ensureGitAnalyzerForCachedTimeline(source as never, {
      createGitAnalyzer,
      getWorkspaceFolder: vi.fn(() => ({ uri: { fsPath: '/workspace' } } as never)),
    });

    expect(initialize).not.toHaveBeenCalled();
    expect(source._analyzerInitialized).toBe(true);
    expect(createGitAnalyzer).toHaveBeenCalledOnce();
  });
});

function createSource(overrides: Partial<Record<string, unknown>> = {}) {
  return {
    _context: { storageUri: { fsPath: '/storage' } } as never,
    _analyzer: undefined,
    _analyzerInitialized: true,
    _analyzerInitPromise: undefined,
    _gitAnalyzer: undefined,
    _installedPluginActivationPromise: undefined,
    _filterPatterns: [],
    _timelineActive: false,
    _currentCommitSha: undefined,
    _disabledPlugins: new Set<string>(),
    _rawGraphData: { nodes: [], edges: [] } satisfies IGraphData,
    _graphData: { nodes: [], edges: [] } satisfies IGraphData,
    _applyViewTransform: vi.fn(),
    _sendMessage: vi.fn(),
    ...overrides,
  };
}

import { describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import {
  assignGraphViewProviderPublicMethods,
  type GraphViewProviderPublicMethodsTarget,
} from '../../../../../src/extension/graphView/provider/wiring/publicApi';

function createTarget() {
  const graphData: IGraphData = {
    nodes: [{ id: 'src/app.ts', label: 'app.ts', color: '#ffffff' }],
    edges: [],
  };
  const disposable = { dispose: vi.fn() };
  const getGraphData = vi.fn(() => graphData);
  const onWebviewMessage = vi.fn(() => disposable as unknown as vscode.Disposable);
  const refreshMethods = {
    refresh: vi.fn(async () => undefined),
    refreshGroupSettings: vi.fn(),
    refreshPhysicsSettings: vi.fn(),
    refreshSettings: vi.fn(),
    refreshToggleSettings: vi.fn(),
    clearCacheAndRefresh: vi.fn(async () => undefined),
  };
  const commandMethods = {
    sendCommand: vi.fn(),
    undo: vi.fn(async () => 'undo'),
    redo: vi.fn(async () => 'redo'),
    canUndo: vi.fn(() => true),
    canRedo: vi.fn(() => false),
    requestExportPng: vi.fn(),
    requestExportSvg: vi.fn(),
    requestExportJpeg: vi.fn(),
    requestExportJson: vi.fn(),
    requestExportMarkdown: vi.fn(),
    emitEvent: vi.fn(),
  };
  const fileVisitMethods = {
    trackFileVisit: vi.fn(async () => undefined),
  };
  const pluginMethods = {
    registerExternalPlugin: vi.fn(),
  };
  const timelineMethods = {
    sendPlaybackSpeed: vi.fn(),
    invalidateTimelineCache: vi.fn(async () => undefined),
  };
  const viewContextMethods = {
    updateGraphData: vi.fn(),
    getGraphData,
  };
  const viewSelectionMethods = {
    setFocusedFile: vi.fn(),
    setDepthMode: vi.fn(async () => undefined),
    setDepthLimit: vi.fn(async () => undefined),
    getDepthLimit: vi.fn(() => 7),
  };
  const webviewMethods = {
    resolveWebviewView: vi.fn(),
    openInEditor: vi.fn(),
    sendToWebview: vi.fn(),
    onWebviewMessage,
  };

  const target = {
    refresh: vi.fn(async () => undefined),
    refreshGroupSettings: vi.fn(),
    refreshPhysicsSettings: vi.fn(),
    refreshSettings: vi.fn(),
    refreshToggleSettings: vi.fn(),
    clearCacheAndRefresh: vi.fn(async () => undefined),
    sendCommand: vi.fn(),
    undo: vi.fn(async () => undefined),
    redo: vi.fn(async () => undefined),
    canUndo: vi.fn(() => true),
    canRedo: vi.fn(() => false),
    requestExportPng: vi.fn(),
    requestExportSvg: vi.fn(),
    requestExportJpeg: vi.fn(),
    requestExportJson: vi.fn(),
    requestExportMarkdown: vi.fn(),
    emitEvent: vi.fn(),
    resolveWebviewView: vi.fn(),
    updateGraphData: vi.fn(),
    getGraphData,
    sendPlaybackSpeed: vi.fn(),
    invalidateTimelineCache: vi.fn(async () => undefined),
    trackFileVisit: vi.fn(async () => undefined),
    registerExternalPlugin: vi.fn(),
    setDepthMode: vi.fn(async () => undefined),
    setFocusedFile: vi.fn(),
    setDepthLimit: vi.fn(async () => undefined),
    getDepthLimit: vi.fn(() => 7),
    openInEditor: vi.fn(),
    sendToWebview: vi.fn(),
    onWebviewMessage,
    _methodContainers: {
      refresh: refreshMethods,
      command: commandMethods,
