import { describe, expect, it } from 'vitest';
import {
  createQualifiedSourceId,
  resolveEdgeSourceIdentity,
} from '../../../../../src/extension/pipeline/graph/edgeSources/identity';

describe('pipeline/graph/edgeSources/identity', () => {
  it('builds qualified source ids from the connection plugin id or plugin fallback', () => {
    expect(
      createQualifiedSourceId(
        { id: 'fallback-plugin' } as never,
        { pluginId: 'connection-plugin', sourceId: 'route' } as never,
      ),
    ).toBe('connection-plugin:route');

    expect(
      createQualifiedSourceId(
        { id: 'fallback-plugin' } as never,
        { pluginId: undefined, sourceId: 'route' } as never,
      ),
    ).toBe('fallback-plugin:route');
  });

  it('returns undefined when a connection does not have a source id', () => {
    expect(
      createQualifiedSourceId(
        { id: 'fallback-plugin' } as never,
        { pluginId: 'connection-plugin', sourceId: undefined } as never,
      ),
    ).toBeUndefined();
  });

  it('resolves plugin and source identities from explicit and fallback values', () => {
    expect(
      resolveEdgeSourceIdentity(
        { id: 'fallback-plugin' } as never,
        {
          pluginId: 'connection-plugin',
          sourceId: 'route',
        } as never,
      ),
    ).toEqual({
      pluginId: 'connection-plugin',
      qualifiedSourceId: 'connection-plugin:route',
      sourceId: 'route',
    });

    expect(
      resolveEdgeSourceIdentity(
        { id: 'fallback-plugin' } as never,
        {
          pluginId: undefined,
          sourceId: 'route',
        } as never,
      ),
    ).toEqual({
      pluginId: 'fallback-plugin',
      qualifiedSourceId: 'fallback-plugin:route',
      sourceId: 'route',
    });
  });

  it('rejects malformed or incomplete qualified source ids', () => {
    expect(
      resolveEdgeSourceIdentity(undefined, {
        pluginId: undefined,
        sourceId: undefined,
      } as never),
    ).toBeUndefined();

    expect(
      resolveEdgeSourceIdentity(undefined, {
        pluginId: undefined,
        sourceId: 'missing-plugin',
      } as never),
    ).toBeUndefined();

    expect(
      resolveEdgeSourceIdentity(undefined, {
        pluginId: '',
        sourceId: 'route',
      } as never),
    ).toBeUndefined();
  });
});

import { afterEach, describe, expect, it } from 'vitest';
import {
  readGoModuleName,
  resolveGoPackageDirectory,
} from '../../../../../src/extension/pipeline/plugins/treesitter/runtime/projectRoots/goModule';
import {
  cleanupProjectRootsWorkspaces,
  createProjectRootsWorkspace,
  writeProjectRootsFile,
} from './workspace';

afterEach(() => {
  cleanupProjectRootsWorkspaces();
});

describe('pipeline/plugins/treesitter/runtime/projectRoots/goModule', () => {
  it('reads the Go module name from go.mod', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(readGoModuleName(workspaceRoot)).toBe('github.com/acme/project');
  });

  it('trims module names and reuses the cached lookup for the same project root', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module   github.com/acme/project   \n');

    expect(readGoModuleName(workspaceRoot)).toBe('github.com/acme/project');

    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/other\n');
    expect(readGoModuleName(workspaceRoot)).toBe('github.com/acme/project');
  });

  it('returns the matching package directory for root and nested imports', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(resolveGoPackageDirectory(workspaceRoot, 'github.com/acme/project')).toBe(workspaceRoot);
    expect(resolveGoPackageDirectory(workspaceRoot, 'github.com/acme/project/pkg/api')).toBe(
      `${workspaceRoot}/pkg/api`,
    );
  });

  it('returns null when go.mod is missing or does not declare a root-level module line', () => {
    const workspaceRoot = createProjectRootsWorkspace();

    expect(resolveGoPackageDirectory(workspaceRoot, 'github.com/acme/project/pkg/api')).toBeNull();
    expect(resolveGoPackageDirectory(workspaceRoot, 'null/pkg/api')).toBeNull();
    expect(readGoModuleName(workspaceRoot)).toBeNull();

    const malformedWorkspaceRoot = createProjectRootsWorkspace();
    writeProjectRootsFile(
      malformedWorkspaceRoot,
      'go.mod',
      '// module github.com/acme/project\nrequire github.com/acme/project v1.0.0\n',
    );

    expect(readGoModuleName(malformedWorkspaceRoot)).toBeNull();
    expect(resolveGoPackageDirectory(malformedWorkspaceRoot, 'null/pkg/api')).toBeNull();
  });

  it('returns null for external imports even when the workspace has a valid module name', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(resolveGoPackageDirectory(workspaceRoot, 'github.com/other/project/pkg/api')).toBeNull();
  });
});

