    const statFile = vi.fn(async () => ({ size: 1, mtime: 2 }));
    const logError = vi.fn();
    const getVisitCountOverride = vi.fn(() => 9);
    const source: FileVisitSource = {
      _context: {
        workspaceState: {
          get: vi.fn(),
          update: vi.fn(() => Promise.resolve()),
