      sendWebviewMessage,
      onWebviewMessage,
      setWebviewMessageListener: vi.fn(),
      executeCommand: vi.fn(() => Promise.resolve()),
      createPanel: vi.fn() as never,
    });
    const handler = vi.fn();

    methods._sendMessage({ type: 'PING' });
    methods.sendToWebview({ type: 'PONG' });
    const result = methods.onWebviewMessage(handler);

    expect(sendWebviewMessage).toHaveBeenNthCalledWith(
      1,
      [source._view, source._timelineView],
      source._panels,
      { type: 'PING' },
    );
    expect(sendWebviewMessage).toHaveBeenNthCalledWith(
      2,
      [source._view, source._timelineView],
      source._panels,
      { type: 'PONG' },
    );
    expect(onWebviewMessage).toHaveBeenCalledWith(source._view, handler);
    expect(notifyExtensionMessage).toHaveBeenNthCalledWith(1, { type: 'PING' });
    expect(notifyExtensionMessage).toHaveBeenNthCalledWith(2, { type: 'PONG' });
    expect(result).toBe(disposable);
  });

  it('delegates listener wiring and html generation helpers', () => {
    const setWebviewMessageListener = vi.fn();
    const createHtml = vi.fn(() => '<html />');
    const source = {
      _extensionUri: vscode.Uri.file('/test/extension'),
      _view: undefined,
      _timelineView: undefined,
      _panels: [],
      _analyzeAndSendData: vi.fn(async () => undefined),
      _getLocalResourceRoots: vi.fn(() => []),
    };
    const methods = createGraphViewProviderWebviewMethods(source as never, {
      viewType: 'codegraphy.graphView',
      createHtml,
      resolveWebviewView: vi.fn(),
      openInEditor: vi.fn(),
      sendWebviewMessage: vi.fn(),
      onWebviewMessage: vi.fn(() => ({ dispose: () => {} })),
      setWebviewMessageListener,
      executeCommand: vi.fn(() => Promise.resolve()),
      createPanel: vi.fn() as never,
    });
    const webview = { kind: 'webview' } as unknown as vscode.Webview;

    methods._setWebviewMessageListener(webview);
    const html = methods._getHtmlForWebview(webview);

    expect(setWebviewMessageListener).toHaveBeenCalledWith(webview, source);
    expect(createHtml).toHaveBeenCalledWith(source._extensionUri, webview, 'graph');
    expect(html).toBe('<html />');
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  onGraphViewWebviewMessage,
  sendGraphViewWebviewMessage,
} from '../../../../src/extension/graphView/webview/bridge';

describe('graphView/webview/bridge', () => {
  it('sends messages to every sidebar view and every editor panel', () => {
    const graphViewWebview = { postMessage: vi.fn() };
    const timelineViewWebview = { postMessage: vi.fn() };
    const panelWebview = { postMessage: vi.fn() };

    sendGraphViewWebviewMessage(
      [
        { webview: graphViewWebview } as never,
        { webview: timelineViewWebview } as never,
      ],
      [{ webview: panelWebview }] as never,
      { type: 'GRAPH_DATA_UPDATED' },
    );

    expect(graphViewWebview.postMessage).toHaveBeenCalledWith({ type: 'GRAPH_DATA_UPDATED' });
    expect(timelineViewWebview.postMessage).toHaveBeenCalledWith({ type: 'GRAPH_DATA_UPDATED' });
    expect(panelWebview.postMessage).toHaveBeenCalledWith({ type: 'GRAPH_DATA_UPDATED' });
  });

  it('skips missing sidebar views while still sending to remaining views and panels', () => {
    const graphViewWebview = { postMessage: vi.fn() };
    const panelWebview = { postMessage: vi.fn() };

    sendGraphViewWebviewMessage(
      [undefined, { webview: graphViewWebview } as never],
      [{ webview: panelWebview }] as never,
      { type: 'GRAPH_DATA_UPDATED' },
    );

    expect(graphViewWebview.postMessage).toHaveBeenCalledWith({ type: 'GRAPH_DATA_UPDATED' });
    expect(panelWebview.postMessage).toHaveBeenCalledWith({ type: 'GRAPH_DATA_UPDATED' });
  });

  it('returns a no-op disposable when no sidebar view is available', () => {
    const disposable = onGraphViewWebviewMessage(undefined, vi.fn());

    expect(disposable).toEqual({ dispose: expect.any(Function) });
  });

  it('subscribes to messages when a sidebar view is available', () => {
    const handler = vi.fn();
    const disposable = { dispose: vi.fn() };
    const onDidReceiveMessage = vi.fn(() => disposable);

    expect(
      onGraphViewWebviewMessage(
        { webview: { onDidReceiveMessage } } as never,
        handler,
      ),
    ).toBe(disposable);
    expect(onDidReceiveMessage).toHaveBeenCalledWith(handler);
  });
});

