      } satisfies IViewContext),
    );
    const methods = createGraphViewProviderViewContextMethods(
      source as never,
      createDependencies({
        getConfiguration,
        buildViewContext,
        getWorkspaceFolders: vi.fn(() => workspaceFolders),
        getActiveTextEditor: vi.fn(() => activeEditor),
        asRelativePath,
      }),
    );

    methods._updateViewContext();

    expect(buildViewContext).toHaveBeenCalledOnce();
    expect(getConfiguration).toHaveBeenCalledWith('codegraphy');
    const options = buildViewContext.mock.calls[0]?.[0] as {
      analyzer: unknown;
      workspaceFolders: unknown;
      activeEditor: unknown;
      readSavedDepthLimit(): number;
      asRelativePath(uri: { fsPath: string }): string;
      defaultDepthLimit: number;
    };
    expect(options.analyzer).toBe(source._analyzer);
    expect(options.workspaceFolders).toBe(workspaceFolders);
    expect(options.activeEditor).toBe(activeEditor);
    expect(options.readSavedDepthLimit()).toBe(1);
    expect(options.asRelativePath({ fsPath: '/workspace/src/app.ts' })).toBe('src/app.ts');
    expect(options.defaultDepthLimit).toBe(1);
    expect(configuration.get).toHaveBeenCalledWith('depthLimit', 1);
    expect(asRelativePath).toHaveBeenCalledWith({ fsPath: '/workspace/src/app.ts' });
    expect(source._viewContext).toEqual({
      activePlugins: new Set<string>(['plugin.test']),
      depthLimit: 3,
      focusedFile: 'src/app.ts',
    });
  });

  it('uses the live vscode defaults to build the view context', () => {
    const source = createSource();
    const configurationGet = vi.fn(<T>(key: string, defaultValue: T): T => {
      if (key === 'depthLimit') {
        return 1 as T;
      }
      if (key === 'nodeColors') {
        return { folder: '#123456' } as T;
      }
      return defaultValue;
    });
    const getConfiguration = vi
      .spyOn(vscode.workspace, 'getConfiguration')
      .mockReturnValue({ get: configurationGet, update: vi.fn(() => Promise.resolve()) } as never);
    const workspaceFolder = { uri: vscode.Uri.file('/workspace') } as vscode.WorkspaceFolder;
    const workspaceFolders = vi
      .spyOn(vscode.workspace, 'workspaceFolders', 'get')
      .mockReturnValue([workspaceFolder]);
    const activeEditor = { document: { uri: vscode.Uri.file('/workspace/src/app.ts') } } as never;
    const originalActiveTextEditor = (vscode.window as { activeTextEditor?: unknown }).activeTextEditor;
    Object.defineProperty(vscode.window, 'activeTextEditor', {
      configurable: true,
      value: activeEditor,
    });
    const originalAsRelativePath = (vscode.workspace as { asRelativePath?: unknown }).asRelativePath;
    const asRelativePath = vi.fn(() => 'src/app.ts');
    Object.defineProperty(vscode.workspace, 'asRelativePath', {
      configurable: true,
      value: asRelativePath,
    });

    providerViewContextMethodMocks.buildViewContext.mockReturnValue({
      activePlugins: new Set<string>(['plugin.test']),
      depthLimit: 3,
      focusedFile: 'src/app.ts',
    } satisfies IViewContext);

    const methods = createGraphViewProviderViewContextMethods(source as never);

    methods._updateViewContext();

    expect(getConfiguration).toHaveBeenCalledWith('codegraphy');
    expect(providerViewContextMethodMocks.buildViewContext).toHaveBeenCalledOnce();
    const options = providerViewContextMethodMocks.buildViewContext.mock.calls[0]?.[0] as {
      analyzer: unknown;
      workspaceFolders: unknown;
      activeEditor: unknown;
      readSavedDepthLimit(): number;
      asRelativePath(uri: vscode.Uri): string;
      defaultDepthLimit: number;
    };
    expect(options.analyzer).toBe(source._analyzer);
    expect(options.workspaceFolders).toEqual([workspaceFolder]);
    expect(options.activeEditor).toBe(activeEditor);
    expect(options.readSavedDepthLimit()).toBe(1);
    expect(options.asRelativePath(vscode.Uri.file('/workspace/src/app.ts'))).toBe('src/app.ts');
    expect(options.defaultDepthLimit).toBe(1);
    expect(configurationGet).toHaveBeenCalledWith('depthLimit', 1);
    expect(asRelativePath).toHaveBeenCalledWith(vscode.Uri.file('/workspace/src/app.ts'));
    expect(source._viewContext).toEqual({
      activePlugins: new Set<string>(['plugin.test']),
      depthLimit: 3,
      focusedFile: 'src/app.ts',
    });

    if (originalAsRelativePath === undefined) {
      delete (vscode.workspace as { asRelativePath?: unknown }).asRelativePath;
    } else {
      Object.defineProperty(vscode.workspace, 'asRelativePath', {
        configurable: true,
        value: originalAsRelativePath,
      });
    }
    if (originalActiveTextEditor === undefined) {
      delete (vscode.window as { activeTextEditor?: unknown }).activeTextEditor;
    } else {
      Object.defineProperty(vscode.window, 'activeTextEditor', {
        configurable: true,
        value: originalActiveTextEditor,
      });
    }
    workspaceFolders.mockRestore();
    getConfiguration.mockRestore();
  });

  it('sends available views through the provider message bridge', () => {
    const source = createSource({
      _depthMode: true,
      _viewContext: {
        activePlugins: new Set<string>(['plugin.test']),
        depthLimit: 3,
      } satisfies IViewContext,
    });
    const sendDepthState = vi.fn(
      (
        _viewContext,
        _depthMode,
        _rawGraphData,
        _defaultDepthLimit,
        sendMessage,
      ) => {
        sendMessage({
          type: 'DEPTH_MODE_UPDATED',
          payload: { depthMode: true },
        });
      },
    );
    const methods = createGraphViewProviderViewContextMethods(
      source as never,
      createDependencies({
        sendDepthState,
      }),
    );

    methods._sendDepthState();

    expect(sendDepthState).toHaveBeenCalledWith(
      source._viewContext,
      true,
      source._rawGraphData,
      1,
      expect.any(Function),
    );
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'DEPTH_MODE_UPDATED',
      payload: { depthMode: true },
    });
  });

  it('applies the active transform without trying to persist a separate built-in view id', () => {
    const source = createSource();
    const applyViewTransform = vi.fn(() => ({
      graphData: {
        nodes: [{ id: 'transformed', label: 'transformed', color: '#93C5FD' }],
        edges: [],
      },
    } satisfies IGraphViewTransformResult));
    const sendDepthState = vi.fn();
    const dependencies = createDependencies({
      applyViewTransform,
      sendDepthState,
    });
    const methods = createGraphViewProviderViewContextMethods(
      source as never,
      dependencies,
    );

    methods._applyViewTransform();
    methods._sendDepthState();

    expect(applyViewTransform).toHaveBeenCalledWith(
      source._viewRegistry,
      source._viewContext,
      source._rawGraphData,
    );
    expect(source._graphData).toEqual({
      nodes: [{ id: 'transformed', label: 'transformed', color: '#93C5FD' }],
      edges: [],
    });
    const configuration = dependencies.getConfiguration('codegraphy');
    expect(configuration.update).not.toHaveBeenCalledWith(
      expect.stringMatching(/selectedView/),
      expect.anything(),
    );
    expect(sendDepthState).toHaveBeenCalledOnce();
  });

  it('uses the live default transform and view broadcast helpers', () => {
    const source = createSource({
      _depthMode: true,
      _viewContext: {
        activePlugins: new Set<string>(['plugin.test']),
        depthLimit: 2,
      } satisfies IViewContext,
    });
    providerViewContextMethodMocks.applyViewTransform.mockReturnValue({
      graphData: {
        nodes: [{ id: 'transformed', label: 'transformed', color: '#93C5FD' }],
        edges: [],
      },
    } satisfies IGraphViewTransformResult);
    providerViewContextMethodMocks.sendDepthState.mockImplementation(
      (
        _viewContext,
        _depthMode,
        _rawGraphData,
        _defaultDepthLimit,
        sendMessage,
      ) => {
        sendMessage({
          type: 'DEPTH_MODE_UPDATED',
          payload: { depthMode: true },
        });
      },
    );
    const update = vi.fn(() => Promise.resolve());
    vi.spyOn(vscode.workspace, 'getConfiguration')
      .mockReturnValue({ get: vi.fn((_: string, fallback: unknown) => fallback), update } as never);

    const methods = createGraphViewProviderViewContextMethods(source as never);

    methods._applyViewTransform();
    methods._sendDepthState();

    expect(providerViewContextMethodMocks.applyViewTransform).toHaveBeenCalledWith(
      source._viewRegistry,
      source._viewContext,
      source._rawGraphData,
    );
    expect(source._graphData).toEqual({
      nodes: [{ id: 'transformed', label: 'transformed', color: '#93C5FD' }],
      edges: [],
    });
    expect(update).not.toHaveBeenCalledWith(
      expect.stringMatching(/selectedView/),
      expect.anything(),
    );
    expect(providerViewContextMethodMocks.sendDepthState).toHaveBeenCalledWith(
      source._viewContext,
      true,
      source._rawGraphData,
      1,
      expect.any(Function),
    );
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'DEPTH_MODE_UPDATED',
      payload: { depthMode: true },
    });
  });

  it('keeps the current graph transform result when no persistence is requested', () => {
    const source = createSource();
    const applyViewTransform = vi.fn(() => ({
      graphData: {
        nodes: [{ id: 'transformed', label: 'transformed', color: '#93C5FD' }],
        edges: [],
      },
    } satisfies IGraphViewTransformResult));
    const dependencies = createDependencies({
      applyViewTransform,
    });
    const methods = createGraphViewProviderViewContextMethods(
      source as never,
      dependencies,
    );

    methods._applyViewTransform();

    expect(source._graphData).toEqual({
      nodes: [{ id: 'transformed', label: 'transformed', color: '#93C5FD' }],
      edges: [],
    });
    expect(dependencies.getConfiguration('codegraphy').update).not.toHaveBeenCalled();
  });
});

function createSource(
  overrides: Partial<{
    _context: { workspaceState: { get: typeof vi.fn; update: typeof vi.fn } };
    _analyzer: unknown;
    _viewRegistry: unknown;
    _viewContext: IViewContext;
    _depthMode: boolean;
    _rawGraphData: IGraphData;
    _graphData: IGraphData;
    _sendMessage: ReturnType<typeof vi.fn>;
  }> = {},
) {
  return {
    _context: {
      workspaceState: {
        get: vi.fn(() => 1),
        update: vi.fn(() => Promise.resolve()),
      },
    },
    _analyzer: { registry: { list: vi.fn(() => []) } },
    _viewRegistry: {
      get: vi.fn(() => ({ view: { id: 'codegraphy.graph' } })),
      isViewAvailable: vi.fn(() => true),
    },
    _viewContext: {
      activePlugins: new Set<string>(),
      depthLimit: 1,
    } satisfies IViewContext,
    _depthMode: false,
    _rawGraphData: { nodes: [], edges: [] } satisfies IGraphData,
    _graphData: { nodes: [], edges: [] } satisfies IGraphData,
    _sendMessage: vi.fn(),
    ...overrides,
  };
}

function createDependencies(
  overrides: Partial<GraphViewProviderViewContextMethodDependencies> = {},
): GraphViewProviderViewContextMethodDependencies {
  const configuration = {
    get: vi.fn((_: string, fallback: unknown) => fallback),
    update: vi.fn(() => Promise.resolve()),
  } as {
    get<T>(section: string, defaultValue: T): T;
    update(key: string, value: unknown, target?: unknown): Promise<void>;
  };
  const getConfiguration: GraphViewProviderViewContextMethodDependencies['getConfiguration'] = vi.fn(
    () => configuration,
  );
  const buildViewContext: GraphViewProviderViewContextMethodDependencies['buildViewContext'] =
    vi.fn((_options: Parameters<typeof buildGraphViewContext>[0]) => ({
      activePlugins: new Set<string>(),
      depthLimit: 1,
    } satisfies IViewContext));
  const applyViewTransform: GraphViewProviderViewContextMethodDependencies['applyViewTransform'] =
    vi.fn((...args: Parameters<typeof applyGraphViewTransform>) => {
      const [, , rawGraphData] = args;
      return {
        graphData: rawGraphData,
      } satisfies IGraphViewTransformResult;
    });
  return {
    getConfiguration,
    getWorkspaceFolders: vi.fn(() => []),
    getActiveTextEditor: vi.fn(() => undefined),
    asRelativePath: vi.fn((uri: { fsPath?: string }) => uri.fsPath ?? ''),
    buildViewContext,
    applyViewTransform,
    sendDepthState: vi.fn(),
    defaultDepthLimit: 1,
    ...overrides,
  };
}

import { describe, expect, it, vi } from 'vitest';
import { applyWebviewReady } from '../../../../../src/extension/graphView/webview/messages/ready';

function createHandlers() {
  return {
    getFilterPatterns: vi.fn(() => ['dist/**']),
    getPluginFilterPatterns: vi.fn(() => ['venv/**']),
    loadGroupsAndFilterPatterns: vi.fn(),
    loadDisabledRulesAndPlugins: vi.fn(),
    sendDepthState: vi.fn(),
    sendGraphControls: vi.fn(),
    loadAndSendData: vi.fn(),
    sendFavorites: vi.fn(),
    sendSettings: vi.fn(),
    sendPhysicsSettings: vi.fn(),
    sendGroupsUpdated: vi.fn(),
    sendMessage: vi.fn(),
    sendCachedTimeline: vi.fn(),
    sendDecorations: vi.fn(),
    sendContextMenuItems: vi.fn(),
    sendPluginWebviewInjections: vi.fn(),
    sendPluginToolbarActions: vi.fn(),
    sendActiveFile: vi.fn(),
    waitForFirstWorkspaceReady: vi.fn(() => Promise.resolve()),
    notifyWebviewReady: vi.fn(),
  };
}

describe('graph view ready message', () => {
  it('sends the initial webview payloads and notifies readiness', async () => {
    const handlers = createHandlers();

    const readyNotified = await applyWebviewReady(
      {
        maxFiles: 500,
        playbackSpeed: 1,
        dagMode: 'td',
        nodeSizeMode: 'connections',
        focusedFile: 'src/game/player.gd',
        hasWorkspace: false,
        firstAnalysis: false,
        readyNotified: false,
      },
      handlers
    );

    expect(handlers.loadGroupsAndFilterPatterns).toHaveBeenCalledOnce();
    expect(handlers.loadDisabledRulesAndPlugins).toHaveBeenCalledOnce();
    expect(handlers.sendDepthState).toHaveBeenCalledOnce();
    expect(handlers.sendGraphControls).toHaveBeenCalledOnce();
    expect(handlers.loadAndSendData).toHaveBeenCalledOnce();
    expect(handlers.sendFavorites).toHaveBeenCalledOnce();
    expect(handlers.sendSettings).toHaveBeenCalledOnce();
    expect(handlers.sendPhysicsSettings).toHaveBeenCalledOnce();
    expect(handlers.sendGroupsUpdated).toHaveBeenCalledOnce();
    expect(handlers.sendCachedTimeline).toHaveBeenCalledOnce();
    expect(handlers.sendDecorations).toHaveBeenCalledOnce();
    expect(handlers.sendContextMenuItems).toHaveBeenCalledOnce();
    expect(handlers.sendPluginWebviewInjections).toHaveBeenCalledOnce();
    expect(handlers.sendActiveFile).toHaveBeenCalledOnce();
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'FILTER_PATTERNS_UPDATED',
      payload: {
        patterns: ['dist/**'],
        pluginPatterns: ['venv/**'],
      },
    });
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'MAX_FILES_UPDATED',
      payload: { maxFiles: 500 },
    });
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'PLAYBACK_SPEED_UPDATED',
      payload: { speed: 1 },
    });
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'DAG_MODE_UPDATED',
      payload: { dagMode: 'td' },
    });
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'NODE_SIZE_MODE_UPDATED',
      payload: { nodeSizeMode: 'connections' },
    });
    expect(handlers.notifyWebviewReady).toHaveBeenCalledOnce();
    expect(readyNotified).toBe(true);
  });

  it('sends available views before kicking off analysis', async () => {
    const callOrder: string[] = [];
    const handlers = createHandlers();
    handlers.sendDepthState.mockImplementation(() => {
      callOrder.push('views');
    });
    handlers.loadAndSendData.mockImplementation(() => {
      callOrder.push('analyze');
    });

    await applyWebviewReady(
      {
        maxFiles: 500,
        playbackSpeed: 1,
        dagMode: null,
        nodeSizeMode: 'connections',
        focusedFile: undefined,
        hasWorkspace: true,
        firstAnalysis: true,
        readyNotified: false,
      },
      handlers
    );

    expect(callOrder.indexOf('views')).toBeGreaterThanOrEqual(0);
    expect(callOrder.indexOf('analyze')).toBeGreaterThanOrEqual(0);
    expect(callOrder.indexOf('views')).toBeLessThan(callOrder.indexOf('analyze'));
  });

  it('waits for workspace readiness during the first workspace-backed analysis', async () => {
    const handlers = createHandlers();

    await applyWebviewReady(
      {
        maxFiles: 500,
        playbackSpeed: 1,
        dagMode: null,
        nodeSizeMode: 'connections',
        focusedFile: undefined,
        hasWorkspace: true,
        firstAnalysis: true,
        readyNotified: false,
      },
      handlers
    );

    expect(handlers.waitForFirstWorkspaceReady).toHaveBeenCalledOnce();
  });

  it('skips workspace readiness waiting outside the initial workspace pass', async () => {
    const handlers = createHandlers();

    await applyWebviewReady(
      {
        maxFiles: 500,
        playbackSpeed: 1,
        dagMode: null,
        nodeSizeMode: 'connections',
        focusedFile: undefined,
        hasWorkspace: true,
        firstAnalysis: false,
        readyNotified: false,
      },
      handlers
    );

    expect(handlers.waitForFirstWorkspaceReady).not.toHaveBeenCalled();
  });

  it('does not notify readiness twice', async () => {
    const handlers = createHandlers();

    const readyNotified = await applyWebviewReady(
      {
        maxFiles: 500,
        playbackSpeed: 1,
        dagMode: null,
        nodeSizeMode: 'connections',
        focusedFile: undefined,
        hasWorkspace: false,
        firstAnalysis: false,
        readyNotified: true,
      },
      handlers
    );

    expect(handlers.notifyWebviewReady).not.toHaveBeenCalled();
    expect(readyNotified).toBe(true);
  });

  it('waits for cached timeline replay before notifying readiness', async () => {
    const events: string[] = [];
    const handlers = createHandlers();
    handlers.sendCachedTimeline.mockImplementation(async () => {
      events.push('timeline:start');
      await Promise.resolve();
      events.push('timeline:end');
    });
    handlers.notifyWebviewReady.mockImplementation(() => {
      events.push('ready');
    });

    await applyWebviewReady(
      {
        maxFiles: 500,
        playbackSpeed: 1,
        dagMode: null,
        nodeSizeMode: 'connections',
        focusedFile: undefined,
        hasWorkspace: false,
        firstAnalysis: false,
        readyNotified: false,
      },
      handlers
    );

    expect(events).toEqual(['timeline:start', 'timeline:end', 'ready']);
  });
});

