  it('omits image urls when there is no workspace webview context', () => {
    const message = buildGraphViewLegendsUpdatedMessage(
      [{ id: 'user-group', pattern: '*.png', color: '#112233', imagePath: '.codegraphy/assets/icon.png' }],
