import { describe, expect, it, vi } from 'vitest';
import type { ICommitInfo } from '../../../../src/shared/timeline/types';
import {
  invalidateGraphViewTimelineCache,
  sendCachedGraphViewTimeline,
  sendGraphViewPlaybackSpeed,
  type GraphViewTimelinePlaybackState,
} from '../../../../src/extension/graphView/timeline/playback';

function createState(
  overrides: Partial<GraphViewTimelinePlaybackState> = {},
): GraphViewTimelinePlaybackState {
  return {
    timelineActive: false,
    currentCommitSha: undefined,
    ...overrides,
  };
}

const cachedCommits: ICommitInfo[] = [
  { sha: 'a1', author: 'A', message: 'one', timestamp: 1, parents: [] },
  { sha: 'b2', author: 'B', message: 'two', timestamp: 2, parents: ['a1'] },
];

describe('graphView/timeline/playback', () => {
  it('does not send cached timeline data when no analyzer is available', () => {
    const sendMessage = vi.fn();
    const state = createState({
      timelineActive: true,
      currentCommitSha: 'existing',
    });

    sendCachedGraphViewTimeline(undefined, state, sendMessage);

    expect(state.timelineActive).toBe(true);
    expect(state.currentCommitSha).toBe('existing');
    expect(sendMessage).not.toHaveBeenCalled();
  });

  it('does not send cached timeline data when the cache is empty', () => {
    const sendMessage = vi.fn();
    const state = createState({
      timelineActive: true,
      currentCommitSha: 'existing',
    });

    sendCachedGraphViewTimeline(
      {
        getCachedCommitList() {
          return [];
        },
      },
      state,
      sendMessage,
    );

    expect(state.timelineActive).toBe(true);
    expect(state.currentCommitSha).toBe('existing');
    expect(sendMessage).not.toHaveBeenCalled();
  });

  it('sends cached timeline data and updates the active commit state', () => {
    const sendMessage = vi.fn();
    const state = createState();

    sendCachedGraphViewTimeline(
      {
        getCachedCommitList() {
          return cachedCommits;
        },
      },
      state,
      sendMessage,
    );

    expect(state.timelineActive).toBe(true);
    expect(state.currentCommitSha).toBe('b2');
    expect(sendMessage).toHaveBeenCalledWith({
      type: 'TIMELINE_DATA',
      payload: { commits: cachedCommits, currentSha: 'b2' },
    });
  });

  it('sends the current playback speed', () => {
    const sendMessage = vi.fn();

    sendGraphViewPlaybackSpeed(1.5, sendMessage);

    expect(sendMessage).toHaveBeenCalledWith({
      type: 'PLAYBACK_SPEED_UPDATED',
      payload: { speed: 1.5 },
    });
  });

  it('invalidates the timeline cache and clears the active commit', async () => {
    const invalidateCache = vi.fn(async () => undefined);
    const sendMessage = vi.fn();
    const state = createState({
      timelineActive: true,
      currentCommitSha: 'b2',
    });

    const nextAnalyzer = await invalidateGraphViewTimelineCache(
      {
        invalidateCache,
      },
      state,
      sendMessage,
    );

    expect(state.timelineActive).toBe(false);
    expect(state.currentCommitSha).toBeUndefined();
    expect(nextAnalyzer).toBeUndefined();
    expect(invalidateCache).toHaveBeenCalledOnce();
    expect(sendMessage).toHaveBeenCalledWith({ type: 'CACHE_INVALIDATED' });
  });

  it('clears timeline state and notifies the webview even without an analyzer', async () => {
    const sendMessage = vi.fn();
    const state = createState({
      timelineActive: true,
      currentCommitSha: 'b2',
    });

    await expect(
      invalidateGraphViewTimelineCache(undefined, state, sendMessage),
    ).resolves.toBeUndefined();

    expect(state.timelineActive).toBe(false);
    expect(state.currentCommitSha).toBeUndefined();
    expect(sendMessage).toHaveBeenCalledWith({ type: 'CACHE_INVALIDATED' });
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IGraphControlsSnapshot } from '../../../../src/shared/graphControls/types';
import {
  buildGraphControlsUpdatedMessage,
  sendGraphControlsUpdated,
} from '../../../../src/extension/graphView/controls/send';

describe('extension/graphView/controls/send', () => {
  it('ignores invalid registry node and edge definitions when building the snapshot message', () => {
    const sendMessage = vi.fn();

    sendGraphControlsUpdated(
      {
        nodes: [{ id: 'src/app.ts', label: 'App', color: '#111111', nodeType: 'file' }],
        edges: [{ id: 'src/app.ts->src/lib.ts#import', from: 'src/app.ts', to: 'src/lib.ts', kind: 'import', sources: [] }],
      },
      {
        registry: {
          listNodeTypes: () => [
            null,
            { id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true },
            { id: 'bad-node', label: 'Bad Node', defaultColor: '#22C55E', defaultVisible: 'yes' },
          ],
          listEdgeTypes: () => [
            undefined,
            { id: 'plugin:route', label: 'Route', defaultColor: '#10B981', defaultVisible: true },
            { id: 'bad-edge', label: 'Bad Edge', defaultColor: '#10B981', defaultVisible: 'yes' },
          ],
        },
      },
      sendMessage,
      { get: <T>(_key: string, defaultValue: T): T => defaultValue },
    );

    expect(sendMessage).toHaveBeenCalledWith(expect.objectContaining({
      type: 'GRAPH_CONTROLS_UPDATED',
      payload: expect.objectContaining({
        nodeTypes: expect.arrayContaining([
          expect.objectContaining({ id: 'route' }),
        ]),
        edgeTypes: expect.arrayContaining([
          expect.objectContaining({ id: 'plugin:route' }),
        ]),
      }),
    }));

    const payload = sendMessage.mock.calls[0][0].payload;
    expect(payload).toBeDefined();
    expect(payload.nodeTypes.some((nodeType: { id: string }) => nodeType.id === 'bad-node')).toBe(false);
    expect(payload.edgeTypes.some((edgeType: { id: string }) => edgeType.id === 'bad-edge')).toBe(false);
  });

  it('treats missing registry methods and non-array results as no plugin definitions', () => {
    const sendMessage = vi.fn();

    sendGraphControlsUpdated(
      {
        nodes: [{ id: 'src/app.ts', label: 'App', color: '#111111', nodeType: 'file' }],
        edges: [{ id: 'src/app.ts->src/lib.ts#import', from: 'src/app.ts', to: 'src/lib.ts', kind: 'import', sources: [] }],
      },
      {
        registry: {
          listNodeTypes: 'not-a-function',
          listEdgeTypes: () => 'not-an-array',
        },
      },
      sendMessage,
      { get: <T>(_key: string, defaultValue: T): T => defaultValue },
    );

    const payload = sendMessage.mock.calls[0][0].payload;
    expect(payload).toBeDefined();
    expect(payload.nodeTypes.map((nodeType: { id: string }) => nodeType.id)).toEqual([
      'file',
      'folder',
      'package',
    ]);
    expect(payload.edgeTypes.some((edgeType: { id: string }) => edgeType.id === 'plugin:route')).toBe(false);
  });

  it('uses only core definitions when the analyzer is absent', () => {
    const sendMessage = vi.fn();

    expect(() =>
      sendGraphControlsUpdated(
        {
          nodes: [{ id: 'src/app.ts', label: 'App', color: '#111111', nodeType: 'file' }],
          edges: [{ id: 'src/app.ts->src/lib.ts#import', from: 'src/app.ts', to: 'src/lib.ts', kind: 'import', sources: [] }],
        },
        undefined,
        sendMessage,
        { get: <T>(_key: string, defaultValue: T): T => defaultValue },
      ),
    ).not.toThrow();

    expect(sendMessage).toHaveBeenCalledOnce();
    expect(sendMessage.mock.calls[0][0].type).toBe('GRAPH_CONTROLS_UPDATED');

    const payload = sendMessage.mock.calls[0][0].payload;
    expect(payload).toBeDefined();
    expect(payload.nodeTypes.map((nodeType: { id: string }) => nodeType.id)).toEqual([
      'file',
      'folder',
      'package',
    ]);
    expect(payload.edgeTypes.some((edgeType: { id: string }) => edgeType.id === 'plugin:route')).toBe(false);
  });

  it('keeps the snapshot payload intact when building the outbound message', () => {
    const snapshot: IGraphControlsSnapshot = {
      nodeTypes: [{ id: 'file', label: 'File', defaultColor: '#A1A1AA', defaultVisible: true }],
      edgeTypes: [{ id: 'import', label: 'Import', defaultColor: '#60A5FA', defaultVisible: true }],
      nodeColors: { file: '#A1A1AA' },
      nodeVisibility: { file: true },
      edgeVisibility: { import: true },
      edgeColors: { import: '#60A5FA' },
    };

    expect(buildGraphControlsUpdatedMessage(snapshot)).toStrictEqual({
      type: 'GRAPH_CONTROLS_UPDATED',
      payload: snapshot,
    });
  });
});

