import { describe, expect, it, vi } from 'vitest';
import type { IDiscoveredFile } from '../../../../src/core/discovery/contracts';
import type { IProjectedConnection, IPlugin, IPluginInfo } from '../../../../src/core/plugins/types/contracts';
import { buildWorkspacePluginStatuses } from '../../../../src/extension/pipeline/plugins/statusBuilder';

function createPluginInfo(overrides: Partial<IPlugin>): IPluginInfo {
  const plugin: IPlugin = {
    id: 'test.plugin',
    name: 'Test Plugin',
    version: '1.0.0',
    apiVersion: '^2.0.0',
    supportedExtensions: ['.ts'],
    analyzeFile: vi.fn(async (filePath: string) => ({ filePath, relations: [] })),
    ...overrides,
  } as IPlugin;

  return {
    plugin,
    builtIn: true,
  };
}

describe('pipeline/plugins/statusBuilder', () => {
  it('preserves plugin order and classifies plugins as active, installed, or inactive', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.python',
        name: 'Python',
        supportedExtensions: ['.py'],
      }),
      createPluginInfo({
        id: 'plugin.alpha',
        name: 'Alpha',
        supportedExtensions: ['.ts'],
      }),
      createPluginInfo({
        id: 'plugin.markdown',
        name: 'Markdown',
        supportedExtensions: ['.md'],
      }),
    ];
    const discoveredFiles: Pick<IDiscoveredFile, 'relativePath'>[] = [
      { relativePath: 'src/index.ts' },
      { relativePath: 'README.md' },
    ];
    const fileConnections = new Map<string, IProjectedConnection[]>([
      ['src/index.ts', [{ specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , pluginId: 'plugin.alpha', sourceId: 'test-source', kind: 'import' }]],
      ['README.md', [{ specifier: './guide', resolvedPath: null, type: 'static' , pluginId: 'plugin.markdown', sourceId: 'test-source', kind: 'import' }]],
    ]);

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles,
      fileConnections,
      pluginInfos,
    });

    expect(statuses.map((status) => status.name)).toEqual(['Python', 'Alpha', 'Markdown']);
    expect(statuses.find((status) => status.id === 'plugin.alpha')?.status).toBe('active');
    expect(statuses.find((status) => status.id === 'plugin.markdown')?.status).toBe('installed');
    expect(statuses.find((status) => status.id === 'plugin.python')?.status).toBe('inactive');
  });

  it('counts resolved plugin connections and marks disabled plugins', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.typescript',
        name: 'TypeScript',
        supportedExtensions: ['.ts'],
      }),
    ];
    const fileConnections = new Map<string, IProjectedConnection[]>([
      ['src/index.ts', [
        { specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static', sourceId: 'es6-import' , kind: 'import', pluginId: 'plugin.typescript' },
        { specifier: './lazy', resolvedPath: '/workspace/src/lazy.ts', type: 'dynamic', sourceId: 'dynamic-import' , kind: 'import', pluginId: 'plugin.typescript' },
        { specifier: 'external-package', resolvedPath: null, type: 'static', sourceId: 'es6-import' , kind: 'import', pluginId: 'plugin.typescript' },
      ]],
    ]);

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(['plugin.typescript']),
      discoveredFiles: [{ relativePath: 'src/index.ts' }],
      fileConnections,
      pluginInfos,
    });

    expect(statuses[0]).toMatchObject({
      id: 'plugin.typescript',
      enabled: false,
      connectionCount: 2,
    });
  });

  it('ignores connections that belong to other plugins', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.typescript',
        name: 'TypeScript',
        supportedExtensions: ['.ts'],
      }),
      createPluginInfo({
        id: 'plugin.python',
        name: 'Python',
        supportedExtensions: ['.py'],
      }),
    ];
    const fileConnections = new Map<string, IProjectedConnection[]>([
      ['src/index.ts', [{ specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , pluginId: 'plugin.typescript', sourceId: 'test-source', kind: 'import' }]],
      ['main.py', [{ specifier: 'config', resolvedPath: '/workspace/config.py', type: 'static' , pluginId: 'plugin.python', sourceId: 'test-source', kind: 'import' }]],
    ]);

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles: [{ relativePath: 'src/index.ts' }, { relativePath: 'main.py' }],
      fileConnections,
      pluginInfos,
    });

    expect(statuses.find((status) => status.id === 'plugin.typescript')?.connectionCount).toBe(1);
    expect(statuses.find((status) => status.id === 'plugin.python')?.connectionCount).toBe(1);
  });

  it('treats legacy connections without plugin provenance as unowned', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.typescript',
        name: 'TypeScript',
        supportedExtensions: ['.ts'],
      }),
    ];

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles: [{ relativePath: 'src/index.ts' }],
      fileConnections: new Map<string, IProjectedConnection[]>([
        ['src/index.ts', [{ specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , sourceId: 'test-source', kind: 'import' }]],
      ]),
      pluginInfos,
    });

    expect(statuses[0].connectionCount).toBe(0);
    expect(statuses[0].status).toBe('installed');
  });

  it('counts connections without rule ids toward plugin totals', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.typescript',
        name: 'TypeScript',
        supportedExtensions: ['.ts'],
      }),
    ];

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles: [{ relativePath: 'src/index.ts' }],
      fileConnections: new Map<string, IProjectedConnection[]>([
        ['src/index.ts', [{ specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , sourceId: 'test-source', kind: 'import', pluginId: 'plugin.typescript' }]],
      ]),
      pluginInfos,
    });

    expect(statuses[0].connectionCount).toBe(1);
  });

  it('does not expose source status data when a plugin declares sources', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.markdown',
        name: 'Markdown',
        supportedExtensions: ['.md'],
        sources: [
          {
            id: 'wiki-link',
            name: 'Wiki Link',
            description: 'Tracks wiki links.',
          },
        ],
      }),
    ];

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles: [{ relativePath: 'README.md' }],
      fileConnections: new Map<string, IProjectedConnection[]>([
        ['README.md', []],
      ]),
      pluginInfos,
    });

    expect(statuses[0]).not.toHaveProperty('sources');
  });

  it('ignores disabled sources when building plugin-only statuses', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.typescript',
        name: 'TypeScript',
        supportedExtensions: ['.ts'],
      }),
    ];

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles: [{ relativePath: 'src/index.ts' }],
      fileConnections: new Map<string, IProjectedConnection[]>([
        ['src/index.ts', [{ specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static', sourceId: 'dynamic-import' , kind: 'import', pluginId: 'plugin.typescript' }]],
      ]),
      pluginInfos,
    });
    const disabledSourceStatuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles: [{ relativePath: 'src/index.ts' }],
      fileConnections: new Map<string, IProjectedConnection[]>([
        ['src/index.ts', [{ specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static', sourceId: 'dynamic-import' , kind: 'import', pluginId: 'plugin.typescript' }]],
      ]),
      pluginInfos,
    });

    expect(disabledSourceStatuses).toEqual(statuses);
  });

  it('keeps unknown plugin ids out of ordering and appends unconfigured plugins', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.markdown',
        name: 'Markdown',
        supportedExtensions: ['.md'],
      }),
      createPluginInfo({
        id: 'plugin.typescript',
        name: 'TypeScript',
        supportedExtensions: ['.ts'],
      }),
    ];

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      fileConnections: new Map<string, IProjectedConnection[]>([
        ['README.md', []],
        ['src/index.ts', []],
      ]),
      discoveredFiles: [{ relativePath: 'README.md' }, { relativePath: 'src/index.ts' }],
      pluginInfos: [pluginInfos[1], pluginInfos[0]],
    });

    expect(statuses.map((status) => status.id)).toEqual([
      'plugin.typescript',
      'plugin.markdown',
    ]);
  });

  it('counts enrichment plugin connections on the same file extension independently', () => {
    const pluginInfos = [
      createPluginInfo({
        id: 'plugin.base',
        name: 'Base',
        supportedExtensions: ['.ts'],
      }),
      createPluginInfo({
        id: 'plugin.enricher',
        name: 'Enricher',
        supportedExtensions: ['.ts'],
      }),
    ];

    const statuses = buildWorkspacePluginStatuses({
      disabledPlugins: new Set(),
      discoveredFiles: [{ relativePath: 'src/index.ts' }],
      fileConnections: new Map<string, IProjectedConnection[]>([
        ['src/index.ts', [
          {
            specifier: './utils',
            resolvedPath: '/workspace/src/utils.ts',
            type: 'static',
            sourceId: 'base-import',
            kind: 'import',
            pluginId: 'plugin.base',
          },
          {
            specifier: './framework',
            resolvedPath: '/workspace/src/framework.ts',
            type: 'static',
            sourceId: 'framework-call',
            kind: 'call',
            pluginId: 'plugin.enricher',
          },
        ]],
      ]),
      pluginInfos,
    });

    expect(statuses).toEqual([
      expect.objectContaining({
        id: 'plugin.base',
        status: 'active',
        connectionCount: 1,
      }),
      expect.objectContaining({
        id: 'plugin.enricher',
        status: 'active',
        connectionCount: 1,
      }),
    ]);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
  hasWorkspacePipelineIndex,
  persistWorkspacePipelineIndexMetadata,
} from '../../../../src/extension/pipeline/service/index';
import {
  readCodeGraphyRepoMeta,
  writeCodeGraphyRepoMeta,
} from '../../../../src/extension/repoSettings/meta';
import type { ICodeGraphyRepoMeta } from '../../../../src/extension/repoSettings/meta';

vi.mock('../../../../src/extension/repoSettings/meta', () => ({
  readCodeGraphyRepoMeta: vi.fn(),
  writeCodeGraphyRepoMeta: vi.fn(),
}));

describe('pipeline/service/index', () => {
  const meta = (overrides: Partial<ICodeGraphyRepoMeta> = {}): ICodeGraphyRepoMeta => ({
    version: 1,
    lastIndexedAt: '2026-01-01T00:00:00.000Z',
    lastIndexedCommit: 'abc123',
    pluginSignature: 'plugin-signature',
    settingsSignature: 'settings-signature',
    pendingChangedFiles: [],
    ...overrides,
  });

  beforeEach(() => {
    vi.clearAllMocks();
    vi.useRealTimers();
    vi.mocked(readCodeGraphyRepoMeta).mockReturnValue(meta());
  });

  it('returns false when no workspace root or no persisted index timestamp exists', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(),
      getPluginSignature: vi.fn(() => 'plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    expect(hasWorkspacePipelineIndex(undefined, dependencies)).toBe(false);
    expect(readCodeGraphyRepoMeta).not.toHaveBeenCalled();

    vi.mocked(readCodeGraphyRepoMeta).mockReturnValueOnce(
      meta({ lastIndexedAt: null, lastIndexedCommit: null }),
    );

    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
    expect(dependencies.getCurrentCommitShaSync).not.toHaveBeenCalled();
  });

  it('returns false when persisted signatures do not match the current signatures', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(() => 'abc123'),
      getPluginSignature: vi.fn(() => 'different-plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
    expect(dependencies.getCurrentCommitShaSync).not.toHaveBeenCalled();
  });

  it('treats a missing current commit as matching only when the persisted commit is also null', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(() => null),
      getPluginSignature: vi.fn(() => 'plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    vi.mocked(readCodeGraphyRepoMeta).mockReturnValueOnce(
      meta({ lastIndexedCommit: null }),
    );
    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(true);

    vi.mocked(readCodeGraphyRepoMeta).mockReturnValueOnce(meta());
    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
  });

  it('matches the stored commit when signatures are current', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(() => 'abc123'),
      getPluginSignature: vi.fn(() => 'plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(true);

    dependencies.getCurrentCommitShaSync.mockReturnValueOnce('def456');
    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
  });

  it('writes updated index metadata when a workspace root is available', async () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date('2026-04-16T08:45:00.000Z'));

    const warn = vi.fn();
    const dependencies = {
      getCurrentCommitSha: vi.fn(async () => 'def456'),
      getPluginSignature: vi.fn(() => 'next-plugin-signature'),
      getSettingsSignature: vi.fn(() => 'next-settings-signature'),
      warn,
    };

    await persistWorkspacePipelineIndexMetadata('/workspace', dependencies);

    expect(writeCodeGraphyRepoMeta).toHaveBeenCalledWith('/workspace', {
      version: 1,
      lastIndexedAt: '2026-04-16T08:45:00.000Z',
      lastIndexedCommit: 'def456',
      pluginSignature: 'next-plugin-signature',
      settingsSignature: 'next-settings-signature',
      pendingChangedFiles: [],
    });
    expect(warn).not.toHaveBeenCalled();
  });

  it('skips writes without a workspace root and warns on persistence failures', async () => {
    const warn = vi.fn();
    const dependencies = {
      getCurrentCommitSha: vi.fn(async () => 'def456'),
      getPluginSignature: vi.fn(() => 'next-plugin-signature'),
      getSettingsSignature: vi.fn(() => 'next-settings-signature'),
      warn,
    };

    await persistWorkspacePipelineIndexMetadata(undefined, dependencies);
    expect(writeCodeGraphyRepoMeta).not.toHaveBeenCalled();

    const error = new Error('disk full');
    vi.mocked(readCodeGraphyRepoMeta).mockImplementationOnce(() => {
      throw error;
    });

    await persistWorkspacePipelineIndexMetadata('/workspace', dependencies);

    expect(warn).toHaveBeenCalledWith(
      '[CodeGraphy] Failed to update repo index metadata.',
      error,
    );
  });
});

