import { describe, expect, it, vi } from 'vitest';
import {
  createEmptyWorkspaceAnalysisCache,
  loadWorkspaceAnalysisCache,
  saveWorkspaceAnalysisCache,
  WORKSPACE_ANALYSIS_CACHE_KEY,
  WORKSPACE_ANALYSIS_CACHE_VERSION,
} from '../../../src/extension/pipeline/cache';

describe('pipeline/cache', () => {
  it('creates an empty cache with the current version', () => {
    expect(createEmptyWorkspaceAnalysisCache()).toEqual({
      version: WORKSPACE_ANALYSIS_CACHE_VERSION,
      files: {},
    });
  });

  it('returns the stored cache when the version matches', () => {
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => {});
    const cached = {
      version: WORKSPACE_ANALYSIS_CACHE_VERSION,
      files: {
        'src/index.ts': {
          mtime: 10,
          analysis: {
            filePath: '/workspace/src/index.ts',
            relations: [],
          },
          size: 42,
        },
      },
    };

    expect(loadWorkspaceAnalysisCache(cached)).toBe(cached);
    expect(logSpy).toHaveBeenCalledWith('[CodeGraphy] Loaded cache: 1 files');
  });

  it('creates an empty cache when the stored version differs', () => {
    expect(loadWorkspaceAnalysisCache({
      version: '0.0.0',
      files: {
        'src/index.ts': {
          mtime: 10,
          analysis: {
            filePath: '/workspace/src/index.ts',
            relations: [],
          },
        },
      },
    })).toEqual({
      version: WORKSPACE_ANALYSIS_CACHE_VERSION,
      files: {},
    });
  });

  it('saves the cache through the provided update callback', () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    const update = vi.fn();

    saveWorkspaceAnalysisCache(update, cache);

    expect(update).toHaveBeenCalledWith(WORKSPACE_ANALYSIS_CACHE_KEY, cache);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import type Parser from 'tree-sitter';
import { collectImportBindings } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseBindings';
import { applyImportClauseBinding } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseBindingHelpers';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseBindingHelpers', () => ({
  applyImportClauseBinding: vi.fn(),
}));

function createNode({
  type = 'statement',
  namedChildren = [],
}: {
  type?: string;
  namedChildren?: Parser.SyntaxNode[];
} = {}): Parser.SyntaxNode {
  return {
    type,
    namedChildren,
  } as unknown as Parser.SyntaxNode;
}

describe('pipeline/plugins/treesitter/runtime/analyze/importClauseBindings', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('returns early when the statement has no import clause child', () => {
    const importedBindings = new Map();

    collectImportBindings(
      createNode({
        namedChildren: [createNode({ type: 'string' })],
      }),
      'react',
      '/workspace/node_modules/react/index.js',
      importedBindings,
    );

    expect(applyImportClauseBinding).not.toHaveBeenCalled();
  });

  it('delegates each import clause child in order with the provided binding context', () => {
    const importedBindings = new Map();
    const defaultImport = createNode({ type: 'identifier' });
    const namedImports = createNode({ type: 'named_imports' });

    collectImportBindings(
      createNode({
        namedChildren: [
          createNode({ type: 'comment' }),
          createNode({
            type: 'import_clause',
            namedChildren: [defaultImport, namedImports],
          }),
        ],
      }),
      './lib',
      '/workspace/src/lib.ts',
      importedBindings,
    );

    expect(applyImportClauseBinding).toHaveBeenCalledTimes(2);
    expect(applyImportClauseBinding).toHaveBeenNthCalledWith(
      1,
      defaultImport,
      importedBindings,
      './lib',
      '/workspace/src/lib.ts',
    );
    expect(applyImportClauseBinding).toHaveBeenNthCalledWith(
      2,
      namedImports,
      importedBindings,
      './lib',
      '/workspace/src/lib.ts',
    );
  });
});

