    const items = collectGraphViewContextMenuItems(
      [{ plugin: { id: 'plugin.test' } }, { plugin: { id: 'plugin.other' } }],
      (pluginId) => {
        if (pluginId !== 'plugin.test') return undefined;
        return {
          contextMenuItems: [
            { label: 'Open', when: 'node' as const },
