      },
    );

    expect(items).toEqual([
      {
        label: 'Open',
        when: 'node',
        icon: undefined,
        group: undefined,
        pluginId: 'plugin.test',
        index: 0,
      },
      {
        label: 'Inspect',
        when: 'edge',
        icon: 'search',
        group: 'analysis',
        pluginId: 'plugin.test',
        index: 1,
      },
    ]);
  });

  it('collects plugin exporters with plugin-scoped indexes', () => {
