import { describe, expect, it, vi } from 'vitest';
import {
  applyNodeFileNavigationMessage,
  type GraphViewNodeFileNavigationHandlers,
} from '../../../../../src/extension/graphView/webview/nodeFile/navigation';

function createHandlers(
  overrides: Partial<GraphViewNodeFileNavigationHandlers> = {},
): GraphViewNodeFileNavigationHandlers {
  return {
    revealInExplorer: vi.fn(() => Promise.resolve()),
    copyToClipboard: vi.fn(() => Promise.resolve()),
    indexGraph: vi.fn(() => Promise.resolve()),
    refreshGraph: vi.fn(() => Promise.resolve()),
    getFileInfo: vi.fn(() => Promise.resolve()),
    ...overrides,
  };
}

describe('graph view node/file navigation message', () => {
  it('reveals a file in the explorer', async () => {
    const handlers = createHandlers();

    const handled = await applyNodeFileNavigationMessage(
      { type: 'REVEAL_IN_EXPLORER', payload: { path: 'src/app.ts' } },
      handlers,
    );

    expect(handled).toBe(true);
    expect(handlers.revealInExplorer).toHaveBeenCalledWith('src/app.ts');
  });

  it('copies text to the clipboard', async () => {
    const handlers = createHandlers();

    const handled = await applyNodeFileNavigationMessage(
      { type: 'COPY_TO_CLIPBOARD', payload: { text: 'src/app.ts' } },
      handlers,
    );

    expect(handled).toBe(true);
    expect(handlers.copyToClipboard).toHaveBeenCalledWith('src/app.ts');
  });

  it('awaits graph refresh requests', async () => {
    let finished = false;
    const handlers = createHandlers({
      refreshGraph: vi.fn(async () => {
        await Promise.resolve();
        finished = true;
      }),
    });

    const handled = await applyNodeFileNavigationMessage({ type: 'REFRESH_GRAPH' }, handlers);

    expect(handled).toBe(true);
    expect(finished).toBe(true);
  });

  it('awaits graph index requests', async () => {
    let finished = false;
    const handlers = createHandlers({
      indexGraph: vi.fn(async () => {
        await Promise.resolve();
        finished = true;
      }),
    });

    const handled = await applyNodeFileNavigationMessage({ type: 'INDEX_GRAPH' }, handlers);

    expect(handled).toBe(true);
    expect(finished).toBe(true);
  });

  it('requests file info', async () => {
    const handlers = createHandlers();

    const handled = await applyNodeFileNavigationMessage(
      { type: 'GET_FILE_INFO', payload: { path: 'src/app.ts' } },
      handlers,
    );

    expect(handled).toBe(true);
    expect(handlers.getFileInfo).toHaveBeenCalledWith('src/app.ts');
  });

  it('returns false for unrelated messages', async () => {
    const handlers = createHandlers();

    const handled = await applyNodeFileNavigationMessage(
      { type: 'OPEN_FILE', payload: { path: 'src/app.ts' } },
      handlers,
    );

    expect(handled).toBe(false);
  });
});

import { describe, expect, it } from 'vitest';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import { filterGraphViewTimelineEdges } from '../../../../../src/extension/graphView/timeline/indexing/edgeFiltering';

const rawGraphData: IGraphData = {
  nodes: [
    { id: 'src/a.ts', label: 'a.ts', color: '#111111' },
    { id: 'src/b.ts', label: 'b.ts', color: '#222222' },
    { id: 'src/c.ts', label: 'c.ts', color: '#333333' },
  ],
  edges: [
    {
      id: 'src/a.ts->src/b.ts#import',
      from: 'src/a.ts',
      to: 'src/b.ts',
      kind: 'import',
      sources: [{ id: 'codegraphy.typescript:import', pluginId: 'codegraphy.typescript', sourceId: 'import', label: 'Import' }],
    },
    {
      id: 'src/c.ts->src/b.ts#import',
      from: 'src/c.ts',
      to: 'src/b.ts',
      kind: 'import',
      sources: [{ id: 'codegraphy.python:import', pluginId: 'codegraphy.python', sourceId: 'import', label: 'Import' }],
    },
  ],
};

describe('filterGraphViewTimelineEdges', () => {
  it('filters out edges from disabled plugins', () => {
    const edges = filterGraphViewTimelineEdges(rawGraphData, {
      disabledPlugins: new Set(['codegraphy.typescript']),
      showOrphans: true,
    });

    expect(edges).toEqual([
      {
        id: 'src/c.ts->src/b.ts#import',
        from: 'src/c.ts',
        to: 'src/b.ts',
        kind: 'import',
        sources: [{ id: 'codegraphy.python:import', pluginId: 'codegraphy.python', sourceId: 'import', label: 'Import' }],
      },
    ]);
  });

  it('keeps edges when only source ids would previously have been disabled', () => {
    const edges = filterGraphViewTimelineEdges(rawGraphData, {
      disabledPlugins: new Set<string>(),
      showOrphans: true,
    });

    expect(edges).toEqual([
      {
        id: 'src/a.ts->src/b.ts#import',
        from: 'src/a.ts',
        to: 'src/b.ts',
        kind: 'import',
        sources: [{ id: 'codegraphy.typescript:import', pluginId: 'codegraphy.typescript', sourceId: 'import', label: 'Import' }],
      },
      {
        id: 'src/c.ts->src/b.ts#import',
        from: 'src/c.ts',
        to: 'src/b.ts',
        kind: 'import',
        sources: [{ id: 'codegraphy.python:import', pluginId: 'codegraphy.python', sourceId: 'import', label: 'Import' }],
      },
    ]);
  });

  it('returns the original edge array when no plugin or rule filters are disabled', () => {
    const edges = filterGraphViewTimelineEdges(rawGraphData, {
      disabledPlugins: new Set<string>(),
      showOrphans: true,
    });

    expect(edges).toBe(rawGraphData.edges);
  });

  it('keeps source-less edges even when a plugin is disabled', () => {
    const edges = filterGraphViewTimelineEdges(rawGraphData, {
      disabledPlugins: new Set(['codegraphy.typescript']),
      showOrphans: true,
    });

    expect(edges).toEqual([
      {
        id: 'src/c.ts->src/b.ts#import',
        from: 'src/c.ts',
        to: 'src/b.ts',
        kind: 'import',
        sources: [{ id: 'codegraphy.python:import', pluginId: 'codegraphy.python', sourceId: 'import', label: 'Import' }],
      },
    ]);
  });

  it('returns source-less edges unchanged when they have no provenance to filter', () => {
    const edges = filterGraphViewTimelineEdges({
      ...rawGraphData,
      edges: [
        ...rawGraphData.edges,
        {
          id: 'src/a.ts->src/c.ts#reference',
          from: 'src/a.ts',
          to: 'src/c.ts',
          kind: 'reference',
          sources: [],
        },
      ],
    }, {
      disabledPlugins: new Set(['codegraphy.typescript']),
      showOrphans: true,
    });

    expect(edges).toEqual([
      {
        id: 'src/c.ts->src/b.ts#import',
        from: 'src/c.ts',
        to: 'src/b.ts',
        kind: 'import',
        sources: [{ id: 'codegraphy.python:import', pluginId: 'codegraphy.python', sourceId: 'import', label: 'Import' }],
      },
      {
        id: 'src/a.ts->src/c.ts#reference',
        from: 'src/a.ts',
        to: 'src/c.ts',
        kind: 'reference',
        sources: [],
      },
    ]);
  });
});

import { describe, expect, it } from 'vitest';
import type { NodeShape2D, NodeShape3D } from '@/shared/settings/modes';
import * as vscode from 'vscode';
import { getGraphViewPluginDefaultGroups } from '../../../../../src/extension/graphView/groups/defaults/plugin';

describe('graphView/pluginDefaultGroups', () => {
  type PluginInfoLike = {
    builtIn?: boolean;
    plugin: {
      id: string;
      name: string;
      fileColors?: Record<
        string,
        string | { color: string; shape2D?: NodeShape2D; shape3D?: NodeShape3D; imagePath?: string }
      >;
    };
  };

  it('returns no plugin default groups when the analyzer is unavailable', () => {
    expect(
      getGraphViewPluginDefaultGroups(
        undefined,
        new Set<string>(),
        new Map<string, vscode.Uri>(),
        vscode.Uri.file('/test/extension'),
      ),
    ).toEqual([]);
  });

  it('builds plugin default groups and registers known built-in asset roots', () => {
    const pluginExtensionUris = new Map<string, vscode.Uri>();

    const groups = getGraphViewPluginDefaultGroups(
      {
        registry: {
          list: () => [
            {
              builtIn: true,
              plugin: {
                id: 'codegraphy.markdown',
                name: 'Markdown',
                fileColors: {
                  '*.md': '#577590',
                  '*.mdx': {
                    color: '#577590',
                    shape2D: 'hexagon',
                    imagePath: 'assets/markdown.svg',
                  },
                },
              },
            },
          ],
        },
      },
      new Set<string>(),
      pluginExtensionUris,
      vscode.Uri.file('/test/extension'),
    );

    expect(groups).toEqual([
      {
        id: 'plugin:codegraphy.markdown:*.md',
        pattern: '*.md',
        color: '#577590',
        isPluginDefault: true,
        pluginName: 'Markdown',
      },
      {
        id: 'plugin:codegraphy.markdown:*.mdx',
        pattern: '*.mdx',
        color: '#577590',
        isPluginDefault: true,
        pluginName: 'Markdown',
        shape2D: 'hexagon',
        imagePath: 'assets/markdown.svg',
      },
    ]);
    expect(pluginExtensionUris.get('codegraphy.markdown')?.fsPath).toBe(
      '/test/extension/packages/plugin-markdown',
    );
  });

  it('reuses an existing built-in plugin root registration', () => {
    const existingUri = vscode.Uri.file('/custom/plugin-typescript');
    const pluginExtensionUris = new Map<string, vscode.Uri>([
      ['codegraphy.typescript', existingUri],
    ]);

    const groups = getGraphViewPluginDefaultGroups(
      {
        registry: {
          list: () => [
            {
              builtIn: true,
              plugin: {
                id: 'codegraphy.typescript',
                name: 'TypeScript',
                fileColors: { '*.ts': '#3178C6' },
              },
            },
          ],
        },
      },
      new Set<string>(),
      pluginExtensionUris,
      vscode.Uri.file('/test/extension'),
    );

    expect(groups).toEqual([
      {
        id: 'plugin:codegraphy.typescript:*.ts',
        pattern: '*.ts',
        color: '#3178C6',
        isPluginDefault: true,
        pluginName: 'TypeScript',
      },
    ]);
    expect(pluginExtensionUris.get('codegraphy.typescript')).toBe(existingUri);
  });

  it('keeps unknown built-in plugins unregistered while still returning their groups', () => {
    const pluginExtensionUris = new Map<string, vscode.Uri>();

    const groups = getGraphViewPluginDefaultGroups(
      {
        registry: {
          list: () => [
            {
              builtIn: true,
              plugin: {
                id: 'codegraphy.unknown',
                name: 'Unknown',
                fileColors: { '*.unknown': '#999999' },
              },
            },
          ],
        },
      },
      new Set<string>(),
      pluginExtensionUris,
      vscode.Uri.file('/test/extension'),
    );

    expect(groups).toEqual([
      {
        id: 'plugin:codegraphy.unknown:*.unknown',
        pattern: '*.unknown',
        color: '#999999',
        isPluginDefault: true,
        pluginName: 'Unknown',
      },
    ]);
    expect(pluginExtensionUris.has('codegraphy.unknown')).toBe(false);
  });

  it('copies 3d shape metadata from plugin color definitions', () => {
    const groups = getGraphViewPluginDefaultGroups(
      {
        registry: {
          list: () => [
            {
              plugin: {
                id: 'codegraphy.godot',
                name: 'Godot',
                fileColors: {
                  '*.gd': {
                    color: '#478CBF',
                    shape3D: 'sphere',
                  },
                },
              },
            },
          ],
        },
      },
      new Set<string>(),
      new Map<string, vscode.Uri>(),
      vscode.Uri.file('/test/extension'),
    );

    expect(groups).toEqual([
      {
        id: 'plugin:codegraphy.godot:*.gd',
        pattern: '*.gd',
        color: '#478CBF',
        isPluginDefault: true,
        pluginName: 'Godot',
        shape3D: 'sphere',
      },
    ]);
  });

  it('does not add optional metadata keys when a plugin color definition only provides a color', () => {
    const groups = getGraphViewPluginDefaultGroups(
      {
        registry: {
          list: () => [
            {
              plugin: {
                id: 'codegraphy.rust',
                name: 'Rust',
                fileColors: {
                  '*.rs': {
                    color: '#DEA584',
                  },
                },
              },
            },
          ],
        },
      },
      new Set<string>(),
      new Map<string, vscode.Uri>(),
      vscode.Uri.file('/test/extension'),
    );

    expect(groups).toHaveLength(1);
    expect(groups[0]).toEqual({
      id: 'plugin:codegraphy.rust:*.rs',
      pattern: '*.rs',
      color: '#DEA584',
      isPluginDefault: true,
      pluginName: 'Rust',
    });
    expect(groups[0]).not.toHaveProperty('shape2D');
    expect(groups[0]).not.toHaveProperty('shape3D');
    expect(groups[0]).not.toHaveProperty('imagePath');
  });

  it('skips disabled plugins and deduplicates duplicate patterns', () => {
    const groups = getGraphViewPluginDefaultGroups(
      {
        registry: {
          list: (): PluginInfoLike[] => [
            {
              plugin: {
                id: 'codegraphy.typescript',
                name: 'TypeScript',
                fileColors: { '*.ts': '#3178C6' },
              },
            },
            {
              plugin: {
                id: 'codegraphy.typescript',
                name: 'TypeScript',
                fileColors: { '*.ts': '#3178C6' },
              },
            },
            {
              plugin: {
                id: 'codegraphy.python',
                name: 'Python',
                fileColors: { '*.py': '#3776AB' },
              },
            },
          ],
        },
      },
      new Set(['codegraphy.typescript']),
      new Map<string, vscode.Uri>(),
      vscode.Uri.file('/test/extension'),
    );

    expect(groups).toEqual([
      {
        id: 'plugin:codegraphy.python:*.py',
        pattern: '*.py',
        color: '#3776AB',
        isPluginDefault: true,
        pluginName: 'Python',
      },
    ]);
  });

  it('deduplicates repeated plugin patterns and only copies defined metadata', () => {
    const groups = getGraphViewPluginDefaultGroups(
      {
        registry: {
          list: (): PluginInfoLike[] => [
            {
              plugin: {
                id: 'codegraphy.godot',
                name: 'Godot',
                fileColors: {
                  '*.gd': {
                    color: '#478CBF',
                    shape3D: 'sphere',
                  },
                  '*.godot': {
                    color: '#6A9FB5',
                  },
                },
              },
            },
            {
              plugin: {
                id: 'codegraphy.godot',
                name: 'Godot',
                fileColors: {
                  '*.gd': {
                    color: '#111111',
                    shape2D: 'hexagon',
                    imagePath: 'duplicate.svg',
                  },
                },
              },
            },
          ],
        },
      },
      new Set<string>(),
      new Map<string, vscode.Uri>(),
      vscode.Uri.file('/test/extension'),
    );

    expect(groups).toEqual([
      {
        id: 'plugin:codegraphy.godot:*.gd',
        pattern: '*.gd',
        color: '#478CBF',
        isPluginDefault: true,
        pluginName: 'Godot',
        shape3D: 'sphere',
      },
      {
        id: 'plugin:codegraphy.godot:*.godot',
        pattern: '*.godot',
        color: '#6A9FB5',
        isPluginDefault: true,
        pluginName: 'Godot',
      },
    ]);
  });
});

