import { describe, expect, it, vi } from 'vitest';
import { applyPluginInteraction } from '../../../../../src/extension/graphView/webview/pluginMessages/interaction';

describe('graph view plugin interaction message', () => {
	it('routes plugin graph interactions to the plugin api', () => {
		const deliverWebviewMessage = vi.fn();

		applyPluginInteraction(
			{ event: 'plugin:test.plugin:ping', data: { ok: true } },
			{
				getPluginApi: () => ({ deliverWebviewMessage }),
				emitEvent: vi.fn(),
			},
		);

		expect(deliverWebviewMessage).toHaveBeenCalledWith({
			type: 'ping',
			data: { ok: true },
		});
	});

	it('preserves nested plugin event names when forwarding to the plugin api', () => {
		const deliverWebviewMessage = vi.fn();

		applyPluginInteraction(
			{ event: 'plugin:test.plugin:graph:event', data: { ok: true } },
			{
				getPluginApi: () => ({ deliverWebviewMessage }),
				emitEvent: vi.fn(),
			},
		);

		expect(deliverWebviewMessage).toHaveBeenCalledWith({
			type: 'graph:event',
			data: { ok: true },
		});
	});

	it('emits non-plugin graph interactions on the event bus', () => {
		const emitEvent = vi.fn();

		applyPluginInteraction(
			{ event: 'graph:nodeClick', data: { nodeId: 'src/app.ts' } },
			{
				getPluginApi: vi.fn(),
				emitEvent,
			},
		);

		expect(emitEvent).toHaveBeenCalledWith('graph:nodeClick', { nodeId: 'src/app.ts' });
	});

	it('ignores malformed plugin graph interactions', () => {
		const emitEvent = vi.fn();
		const getPluginApi = vi.fn();

		applyPluginInteraction(
			{ event: 'plugin:test.plugin', data: { ok: true } },
			{
				getPluginApi,
				emitEvent,
			},
		);

		expect(getPluginApi).not.toHaveBeenCalled();
		expect(emitEvent).not.toHaveBeenCalled();
	});

	it('ignores plugin graph interactions when no plugin api is available', () => {
		expect(() =>
			applyPluginInteraction(
				{ event: 'plugin:test.plugin:ping', data: { ok: true } },
				{
					getPluginApi: () => undefined,
					emitEvent: vi.fn(),
				},
			),
		).not.toThrow();
	});
});

import { describe, expect, it, vi } from 'vitest';
import { createGraphViewProviderPluginMethodDelegates } from '../../../../../src/extension/graphView/provider/source/pluginDelegates';

function createOwner() {
  const pluginMethods = {
    _sendGraphControls: vi.fn(),
    _sendPluginStatuses: vi.fn(),
    _sendDecorations: vi.fn(),
    _sendContextMenuItems: vi.fn(),
    _sendPluginExporters: vi.fn(),
    _sendPluginToolbarActions: vi.fn(),
    _sendPluginWebviewInjections: vi.fn(),
    _sendGroupsUpdated: vi.fn(),
    registerExternalPlugin: vi.fn(async (plugin, options) => ({ plugin, options })),
  };

  return {
    _methodContainers: {
      plugin: pluginMethods,
    },
  } as const;
}

describe('graphView/provider/source/pluginDelegates', () => {
  it('creates delegates for every plugin method container entry', async () => {
    const owner = createOwner();
    const delegates = createGraphViewProviderPluginMethodDelegates(owner as never);
    const plugin = { id: 'external.plugin' };
    const options = { extensionUri: '/extension' };

    delegates._sendGraphControls();
    delegates._sendPluginStatuses();
    delegates._sendDecorations();
    delegates._sendContextMenuItems();
    delegates._sendPluginExporters();
    delegates._sendPluginToolbarActions();
    delegates._sendPluginWebviewInjections();
    delegates._sendGroupsUpdated();
    const registration = await delegates.registerExternalPlugin(plugin as never, options as never);

    expect(owner._methodContainers.plugin._sendGraphControls).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin._sendPluginStatuses).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin._sendDecorations).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin._sendContextMenuItems).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin._sendPluginExporters).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin._sendPluginToolbarActions).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin._sendPluginWebviewInjections).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin._sendGroupsUpdated).toHaveBeenCalledOnce();
    expect(owner._methodContainers.plugin.registerExternalPlugin).toHaveBeenCalledWith(
      plugin,
      options,
    );
    expect(registration).toEqual({ plugin, options });
  });
});

import { describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import { openGraphViewProviderWebviewInEditor } from '../../../../../src/extension/graphView/provider/webview/editor';

describe('graphView/provider/webview/editor', () => {
  it('opens a graph webview panel and keeps panel state in sync', () => {
    const panel = {
      id: 'panel-1',
      webview: {
        onDidReceiveMessage: vi.fn(() => ({ dispose: vi.fn() })),
      },
      onDidDispose: vi.fn(listener => {
        listener();
        return { dispose: vi.fn() };
      }),
    } as unknown as vscode.WebviewPanel;
    const createPanel = vi.fn(() => panel);
    const createHtml = vi.fn(() => '<graph html />');
    const setWebviewMessageListener = vi.fn();
    const openInEditor = vi.fn(options => {
      const nextPanel = options.createPanel('codegraphy.graphView', 'CodeGraphy', vscode.ViewColumn.Beside, {
        enableScripts: true,
        localResourceRoots: [{ fsPath: '/test/root' }],
        retainContextWhenHidden: true,
      } as never);
      options.setWebviewMessageListener(nextPanel.webview as never);
      options.getHtmlForWebview(nextPanel.webview as never);
      options.registerPanel(nextPanel);
      options.unregisterPanel(nextPanel);
    });
    const source = {
      _extensionUri: vscode.Uri.file('/test/extension'),
      _view: undefined,
      _timelineView: undefined,
      _panels: [],
      _getLocalResourceRoots: vi.fn(() => [vscode.Uri.file('/test/root')]),
    };

    openGraphViewProviderWebviewInEditor(source as never, {
      viewType: 'codegraphy.graphView',
      createHtml,
      createPanel,
      openInEditor,
      setWebviewMessageListener,
    });

    expect(openInEditor).toHaveBeenCalledOnce();
    expect(createPanel).toHaveBeenCalledWith(
      'codegraphy.graphView',
      'CodeGraphy',
      vscode.ViewColumn.Beside,
      expect.objectContaining({
        enableScripts: true,
        localResourceRoots: expect.arrayContaining([
          expect.objectContaining({ fsPath: '/test/root' }),
        ]),
        retainContextWhenHidden: true,
      }),
    );
    expect(setWebviewMessageListener).toHaveBeenCalledWith(panel.webview, source);
    expect(createHtml).toHaveBeenCalledWith(source._extensionUri, panel.webview, 'graph');
    expect(source._panels).toEqual([]);
  });

  it('reuses an existing registered panel when opening from the sidebar again', () => {
    const existingPanel = {
      reveal: vi.fn(),
    } as unknown as vscode.WebviewPanel;
    const createPanel = vi.fn();
    const openInEditor = vi.fn(options => {
      options.getPanels()[0]?.reveal?.(vscode.ViewColumn.Beside);
    });
    const source = {
      _extensionUri: vscode.Uri.file('/test/extension'),
      _view: undefined,
      _timelineView: undefined,
      _panels: [existingPanel],
      _getLocalResourceRoots: vi.fn(() => [vscode.Uri.file('/test/root')]),
    };

    openGraphViewProviderWebviewInEditor(source as never, {
      viewType: 'codegraphy.graphView',
      createHtml: vi.fn(() => '<graph html />'),
      createPanel,
      openInEditor,
      setWebviewMessageListener: vi.fn(),
    });

    expect(openInEditor).toHaveBeenCalledOnce();
    expect(existingPanel.reveal).toHaveBeenCalledWith(vscode.ViewColumn.Beside);
    expect(createPanel).not.toHaveBeenCalled();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import type { ExtensionToWebviewMessage } from '../../../../../src/shared/protocol/extensionToWebview';
import {
  applyTimelineCommitGraph,
  buildTimelineCommitGraphData,
} from '../../../../../src/extension/graphView/timeline/provider/commitData';

describe('timeline commit data', () => {
  function createGraphNode(id: string) {
    return { id, label: id, color: '#ffffff' };
  }

  it('builds the commit graph with the current timeline filters', async () => {
    const graphData = { nodes: [createGraphNode('src/index.ts')], edges: [] } satisfies IGraphData;
    const getGraphDataForCommit = vi.fn(async () => ({ nodes: [], edges: [] }));
    const buildTimelineGraphData = vi.fn(() => graphData);
    const source = {
      _analyzer: { registry: { kind: 'registry' } },
      _gitAnalyzer: { getGraphDataForCommit },
      _disabledPlugins: new Set(['plugin.test']),
    };

    await expect(buildTimelineCommitGraphData(source as never, 'sha-1', {
      getWorkspaceFolder: vi.fn(() => ({ uri: { fsPath: '/workspace' } })),
      getShowOrphans: vi.fn(() => false),
      buildTimelineGraphData,
    } as never)).resolves.toBe(graphData);

    expect(getGraphDataForCommit).toHaveBeenCalledWith('sha-1');
    expect(buildTimelineGraphData).toHaveBeenCalledWith(
      { nodes: [], edges: [] },
      {
        disabledPlugins: source._disabledPlugins,
        showOrphans: false,
        workspaceRoot: '/workspace',
        registry: source._analyzer.registry,
      },
    );
  });

  it('applies the commit graph through the current view transform', () => {
    const graphData = { nodes: [createGraphNode('src/index.ts')], edges: [] } satisfies IGraphData;
    const transformedGraph = { nodes: [createGraphNode('folder/src')], edges: [] } satisfies IGraphData;
    const applyViewTransform = vi.fn(function applyViewTransform(this: {
      _rawGraphData: IGraphData;
      _graphData: IGraphData;
    }) {
      expect(this._rawGraphData).toBe(graphData);
      this._graphData = transformedGraph;
    });
    const sendMessage = vi.fn();
    const source = {
      _currentCommitSha: undefined,
      _rawGraphData: { nodes: [], edges: [] } satisfies IGraphData,
      _graphData: { nodes: [], edges: [] } satisfies IGraphData,
      _applyViewTransform: applyViewTransform,
      _sendMessage: sendMessage,
    };

    applyTimelineCommitGraph(source as never, 'sha-1', graphData);

    expect(source._currentCommitSha).toBe('sha-1');
    expect(source._rawGraphData).toBe(graphData);
    expect(source._graphData).toBe(transformedGraph);
    expect(applyViewTransform).toHaveBeenCalledOnce();
    expect(sendMessage).toHaveBeenCalledWith({
      type: 'COMMIT_GRAPH_DATA',
      payload: { sha: 'sha-1', graphData: transformedGraph },
    } satisfies ExtensionToWebviewMessage);
  });
});

import { describe, expect, it, vi } from 'vitest';
import { createGraphViewProviderCommandMethods } from '../../../../src/extension/graphView/provider/commands';

describe('graphView/provider/commands', () => {
  it('sends graph commands and export requests through the provider message bridge', () => {
    const sendMessage = vi.fn();
    const emit = vi.fn();
    const methods = createGraphViewProviderCommandMethods(
      {
        _eventBus: { emit },
        _sendMessage: sendMessage,
      },
      {
        getUndoManager: () => ({
          undo: vi.fn(async () => undefined),
          redo: vi.fn(async () => undefined),
          canUndo: vi.fn(() => false),
          canRedo: vi.fn(() => false),
        }),
      },
    );

    methods.sendCommand('FIT_VIEW');
    methods.emitEvent('analysis:completed', { graph: { nodes: [], edges: [] }, duration: 1 });
    methods.requestExportPng();
    methods.requestExportSvg();
    methods.requestExportJpeg();
    methods.requestExportJson();
    methods.requestExportMarkdown();

    expect(sendMessage.mock.calls).toEqual([
      [{ type: 'FIT_VIEW' }],
      [{ type: 'REQUEST_EXPORT_PNG' }],
      [{ type: 'REQUEST_EXPORT_SVG' }],
      [{ type: 'REQUEST_EXPORT_JPEG' }],
      [{ type: 'REQUEST_EXPORT_JSON' }],
      [{ type: 'REQUEST_EXPORT_MD' }],
    ]);
    expect(emit).toHaveBeenCalledWith('analysis:completed', {
      graph: { nodes: [], edges: [] },
      duration: 1,
    });
  });

  it('delegates undo and redo operations to the undo manager', async () => {
    const undo = vi.fn(async () => 'Undo delete');
    const redo = vi.fn(async () => 'Redo delete');
    const methods = createGraphViewProviderCommandMethods(
      { _eventBus: { emit: vi.fn() }, _sendMessage: vi.fn() },
      {
        getUndoManager: () => ({
          undo,
          redo,
          canUndo: vi.fn(() => true),
          canRedo: vi.fn(() => true),
        }),
      },
    );

    await expect(methods.undo()).resolves.toBe('Undo delete');
    await expect(methods.redo()).resolves.toBe('Redo delete');

    expect(undo).toHaveBeenCalledOnce();
    expect(redo).toHaveBeenCalledOnce();
  });

  it('delegates undo availability checks to the undo manager', () => {
    const canUndo = vi.fn(() => true);
    const canRedo = vi.fn(() => false);
    const methods = createGraphViewProviderCommandMethods(
      { _eventBus: { emit: vi.fn() }, _sendMessage: vi.fn() },
      {
        getUndoManager: () => ({
          undo: vi.fn(async () => undefined),
          redo: vi.fn(async () => undefined),
          canUndo,
          canRedo,
        }),
      },
    );

    expect(methods.canUndo()).toBe(true);
    expect(methods.canRedo()).toBe(false);
    expect(canUndo).toHaveBeenCalledOnce();
    expect(canRedo).toHaveBeenCalledOnce();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IGroup } from '../../../../../src/shared/settings/groups';
import {
  applyLegendMessage,
  type GraphViewLegendMessageHandlers,
  type GraphViewLegendMessageState,
} from '../../../../../src/extension/graphView/webview/messages/legends';

function createState(
  overrides: Partial<GraphViewLegendMessageState> = {},
): GraphViewLegendMessageState {
  return {
    userLegends: [],
    ...overrides,
  };
}

function createHandlers(
  overrides: Partial<GraphViewLegendMessageHandlers> = {},
): GraphViewLegendMessageHandlers {
  return {
    persistLegends: vi.fn(() => Promise.resolve()),
    persistDefaultLegendVisibility: vi.fn(() => Promise.resolve()),
    persistLegendOrder: vi.fn(() => Promise.resolve()),
    recomputeGroups: vi.fn(),
    sendGroupsUpdated: vi.fn(),
    ...overrides,
  };
}

describe('graph view legend message', () => {
  it('persists updated legends without transient webview fields', async () => {
    const incomingGroups: IGroup[] = [
      {
        id: 'user-group',
        pattern: 'src/**',
        color: '#112233',
        imagePath: '.codegraphy/assets/icon.png',
        imageUrl: 'webview://icon.png',
        isPluginDefault: true,
        pluginName: 'TypeScript',
      },
    ];
    const state = createState();
    const handlers = createHandlers();

    await expect(
      applyLegendMessage(
        { type: 'UPDATE_LEGENDS', payload: { legends: incomingGroups } },
        state,
        handlers,
      ),
    ).resolves.toBe(true);

    expect(state.userLegends).toEqual([
      {
        id: 'user-group',
        pattern: 'src/**',
        color: '#112233',
        imagePath: '.codegraphy/assets/icon.png',
      },
    ]);
    expect(handlers.persistLegends).toHaveBeenCalledWith(state.userLegends);
  });

  it('returns false for unrelated messages', async () => {
    const state = createState();
    const handlers = createHandlers();

    await expect(
      applyLegendMessage(
        { type: 'UPDATE_SHOW_LABELS', payload: { showLabels: false } },
        state,
        handlers,
      ),
    ).resolves.toBe(false);
  });

  it('persists plugin-default visibility overrides and resends groups', async () => {
    const state = createState({
      userLegends: [{ id: 'user-group', pattern: 'src/**', color: '#112233' }],
    });
    const handlers = createHandlers();

    await expect(
      applyLegendMessage(
        {
          type: 'UPDATE_DEFAULT_LEGEND_VISIBILITY',
          payload: { legendId: 'plugin:codegraphy.typescript:*.ts', visible: false },
        },
        state,
        handlers,
      ),
    ).resolves.toBe(true);

    expect(handlers.persistDefaultLegendVisibility).toHaveBeenCalledWith(
      'plugin:codegraphy.typescript:*.ts',
      false,
    );
    expect(handlers.recomputeGroups).toHaveBeenCalledOnce();
    expect(handlers.sendGroupsUpdated).toHaveBeenCalledOnce();
    expect(state.userLegends).toEqual([{ id: 'user-group', pattern: 'src/**', color: '#112233' }]);
  });

  it('persists legend ordering and resends groups', async () => {
    const state = createState();
    const handlers = createHandlers();

    await expect(
      applyLegendMessage(
        {
          type: 'UPDATE_LEGEND_ORDER',
          payload: { legendIds: ['plugin:codegraphy.typescript:*.ts', 'legend:user'] },
        },
        state,
        handlers,
      ),
    ).resolves.toBe(true);

    expect(handlers.persistLegendOrder).toHaveBeenCalledWith([
      'plugin:codegraphy.typescript:*.ts',
      'legend:user',
    ]);
    expect(handlers.recomputeGroups).toHaveBeenCalledOnce();
    expect(handlers.sendGroupsUpdated).toHaveBeenCalledOnce();
  });
});

