import { addInheritRelation, createSymbol } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/results';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/csharpResolution', () => ({
  getCSharpTypeDeclarationKind: vi.fn(),
  resolveCSharpUsingImport: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/nodes', () => ({
  getIdentifierText: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/results', () => ({
  addInheritRelation: vi.fn(),
  createSymbol: vi.fn(),
}));

function createNode(overrides: Partial<{
  type: string;
  text: string;
  parent: unknown;
  namedChildren: unknown[];
  childForFieldName: (name: string) => unknown;
  descendantsOfType: (types: string[]) => Array<{ text: string; parent?: { type?: string } }>;
}> = {}) {
  return {
    type: 'class_declaration',
    text: '',
    parent: null,
    namedChildren: [],
    childForFieldName: () => null,
    descendantsOfType: () => [],
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/csharpDeclarations', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('creates type symbols and inherit relations for base-list entries', () => {
    const state = { currentNamespace: 'CodeGraphy.App' };
    const importTargetsByNamespace = new Map<string, Set<string>>();
    vi.mocked(getIdentifierText).mockReturnValue('Program');
    vi.mocked(getCSharpTypeDeclarationKind).mockReturnValue('class');
    vi.mocked(resolveCSharpUsingImport).mockReturnValue('/workspace/src/BaseController.cs');
    vi.mocked(createSymbol).mockReturnValue({ id: 'csharp:Program' } as never);

    handleCSharpTypeDeclaration(
      createNode({
        childForFieldName: (name: string) => {
          expect(name).toBe('name');
          return createNode({ type: 'identifier' });
        },
        descendantsOfType: (types: string[]) => {
          expect(types).toEqual(['identifier', 'qualified_name']);
          return [
            { text: 'BaseController', parent: { type: 'base_list' } },
            { text: 'Ignored', parent: { type: 'argument_list' } },
            { text: 'Contracts.ITracked', parent: { type: 'base_list' } },
            { text: 'Detached', parent: undefined },
          ];
        },
      }) as never,
      state as never,
      '/workspace/src/Program.cs',
      '/workspace',
      [] as never[],
      [] as never[],
      new Set(['CodeGraphy.Contracts']),
      importTargetsByNamespace,
    );

    expect(createSymbol).toHaveBeenCalledWith('/workspace/src/Program.cs', 'class', 'Program', expect.anything());
    expect(addInheritRelation).toHaveBeenCalledTimes(2);
    expect(resolveCSharpUsingImport).toHaveBeenNthCalledWith(
      1,
      '/workspace',
      '/workspace/src/Program.cs',
      new Set(['CodeGraphy.Contracts']),
      importTargetsByNamespace,
      'BaseController',
      'CodeGraphy.App',
    );
  });

  it('skips symbol creation when the type declaration name is missing', () => {
    vi.mocked(getIdentifierText).mockReturnValue(null);

    handleCSharpTypeDeclaration(
      createNode({
        childForFieldName: (name: string) => {
          expect(name).toBe('name');
          return null;
        },
      }) as never,
      { currentNamespace: null } as never,
      '/workspace/src/Missing.cs',
      '/workspace',
      [] as never[],
      [] as never[],
      new Set(),
      new Map(),
    );

    expect(createSymbol).not.toHaveBeenCalled();
  });

  it('skips inheritance work for enums but still records the symbol when named', () => {
    vi.mocked(getIdentifierText).mockReturnValue('Status');
    vi.mocked(getCSharpTypeDeclarationKind).mockReturnValue('enum');
    const descendantsOfType = vi.fn(() => [{ text: 'Ignored', parent: { type: 'base_list' } }]);

    handleCSharpTypeDeclaration(
      createNode({
        type: 'enum_declaration',
        childForFieldName: (name: string) => {
          expect(name).toBe('name');
          return createNode({ type: 'identifier' });
        },
        descendantsOfType,
      }) as never,
      { currentNamespace: null } as never,
      '/workspace/src/Status.cs',
      '/workspace',
      [] as never[],
      [] as never[],
      new Set(),
      new Map(),
    );

    expect(createSymbol).toHaveBeenCalledWith('/workspace/src/Status.cs', 'enum', 'Status', expect.anything());
    expect(addInheritRelation).not.toHaveBeenCalled();
    expect(descendantsOfType).not.toHaveBeenCalled();
  });

  it('walks method bodies with the current symbol id, skips unnamed methods, and ignores missing bodies', () => {
    const symbols: Array<{ id: string }> = [];
    const symbol = { id: 'csharp:Run' };
    const walk = vi.fn();
    const body = createNode({ type: 'block' });
    vi.mocked(createSymbol).mockReturnValue(symbol as never);
    vi.mocked(getIdentifierText)
      .mockReturnValueOnce(null)
      .mockReturnValueOnce('Run')
      .mockReturnValueOnce('Render')
      .mockReturnValueOnce('NoBody');

    expect(
      handleCSharpMethodDeclaration(
        createNode({
          childForFieldName: (name: string) => {
            expect(name).toBe('name');
            return null;
          },
        }) as never,
        { currentSymbolId: null } as never,
        '/workspace/src/Program.cs',
        symbols as never,
        walk,
      ),
    ).toBeUndefined();
    expect(
      handleCSharpMethodDeclaration(
        createNode({
          childForFieldName: (name: string) => {
            if (name === 'name') {
              return createNode({ type: 'identifier' });
            }

            expect(name).toBe('body');
            return body;
          },
        }) as never,
        { currentSymbolId: null } as never,
        '/workspace/src/Program.cs',
        symbols as never,
        walk,
      ),
    ).toEqual({ skipChildren: true });
    expect(
      handleCSharpMethodDeclaration(
        createNode({
          namedChildren: [body],
          childForFieldName: (name: string) => {
            expect(['name', 'body']).toContain(name);
            return name === 'name' ? createNode({ type: 'identifier' }) : null;
          },
        }) as never,
        { currentSymbolId: null } as never,
        '/workspace/src/Program.cs',
        symbols as never,
        walk,
      ),
    ).toEqual({ skipChildren: true });
    expect(
      handleCSharpMethodDeclaration(
        createNode({
          childForFieldName: (name: string) => {
            expect(['name', 'body']).toContain(name);
            return name === 'name' ? createNode({ type: 'identifier' }) : null;
          },
        }) as never,
        { currentSymbolId: null } as never,
        '/workspace/src/Program.cs',
        symbols as never,
        walk,
      ),
    ).toEqual({ skipChildren: true });

    expect(createSymbol).toHaveBeenNthCalledWith(1, '/workspace/src/Program.cs', 'method', 'Run', expect.anything());
    expect(createSymbol).toHaveBeenNthCalledWith(2, '/workspace/src/Program.cs', 'method', 'Render', expect.anything());
    expect(createSymbol).toHaveBeenNthCalledWith(3, '/workspace/src/Program.cs', 'method', 'NoBody', expect.anything());
    expect(walk).toHaveBeenCalledTimes(2);
    expect(walk).toHaveBeenCalledWith(body, { currentSymbolId: 'csharp:Run' });
  });
});

import { afterEach, describe, expect, it, vi } from 'vitest';
import type { IDiscoveredFile } from '../../../../src/core/discovery/contracts';
import type { IFileAnalysisResult } from '../../../../src/core/plugins/types/contracts';
import {
  analyzeWorkspacePipelineFiles,
  analyzeWorkspacePipelineSourceFiles,
} from '../../../../src/extension/pipeline/analysis/files';
import * as workspaceFileAnalysisModule from '../../../../src/extension/pipeline/fileAnalysis';

function createDiscoveredFile(relativePath: string): IDiscoveredFile {
  const extensionIndex = relativePath.lastIndexOf('.');
  const slashIndex = relativePath.lastIndexOf('/');

  return {
    absolutePath: `/workspace/${relativePath}`,
    extension: extensionIndex >= 0 ? relativePath.slice(extensionIndex) : '',
    name: slashIndex >= 0 ? relativePath.slice(slashIndex + 1) : relativePath,
    relativePath,
  };
}

describe('pipeline/analysis/files', () => {
  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('logs cache hit and miss counts from workspace file analysis', async () => {
    vi.spyOn(workspaceFileAnalysisModule, 'analyzeWorkspaceFiles').mockResolvedValue({
      cacheHits: 2,
      cacheMisses: 3,
      fileAnalysis: new Map([
        ['src/index.ts', { filePath: '/workspace/src/index.ts', relations: [] }],
      ]),
      fileConnections: new Map([['src/index.ts', []]]),
    });
    const logInfo = vi.fn();

    const result = await analyzeWorkspacePipelineFiles({
      analyzeFile: vi.fn(async (): Promise<IFileAnalysisResult> => ({
        filePath: '/workspace/src/index.ts',
        relations: [],
      })),
      cache: { files: {}, version: '1' } as never,
      files: [],
      getFileStat: vi.fn(async () => null),
      logInfo,
      readContent: vi.fn(async () => ''),
      workspaceRoot: '/workspace',
    });

    expect(result).toEqual({
      cacheHits: 2,
      cacheMisses: 3,
      fileAnalysis: new Map([
        ['src/index.ts', { filePath: '/workspace/src/index.ts', relations: [] }],
      ]),
      fileConnections: new Map([['src/index.ts', []]]),
    });
    expect(logInfo).toHaveBeenCalledWith(
      '[CodeGraphy] Analysis: 2 cache hits, 3 misses',
    );
  });

  it('creates source-backed adapters for file analysis and event emission', async () => {
    const source = {
      _cache: { files: {}, version: '1' },
      _discovery: {
        readContent: vi.fn(async () => "import './utils'"),
      },
      _eventBus: {
        emit: vi.fn(),
      },
      _getFileStat: vi.fn(async () => ({ mtime: 10, size: 5 })),
      _registry: {
        analyzeFileResult: vi.fn(async (): Promise<IFileAnalysisResult> => ({
          filePath: '/workspace/src/index.ts',
          relations: [],
        })),
      },
    };
    const analyzeWorkspaceFilesSpy = vi
      .spyOn(workspaceFileAnalysisModule, 'analyzeWorkspaceFiles')
      .mockResolvedValue({
        cacheHits: 1,
        cacheMisses: 0,
        fileAnalysis: new Map(),
        fileConnections: new Map(),
      });

    await analyzeWorkspacePipelineSourceFiles(
      source as never,
      [
        createDiscoveredFile('src/index.ts'),
      ],
      '/workspace',
      vi.fn(),
    );

    const options = analyzeWorkspaceFilesSpy.mock.calls[0][0];
    await options.analyzeFile('/workspace/src/index.ts', "import './utils'", '/workspace');
    expect(source._registry.analyzeFileResult).toHaveBeenCalledWith(
      '/workspace/src/index.ts',
      "import './utils'",
      '/workspace',
    );
    await options.readContent({
      absolutePath: '/workspace/src/index.ts',
      extension: '.ts',
      name: 'index.ts',
      relativePath: 'src/index.ts',
    });
    expect(source._discovery.readContent).toHaveBeenCalledOnce();
    await options.getFileStat('/workspace/src/index.ts');
    expect(source._getFileStat).toHaveBeenCalledWith('/workspace/src/index.ts');
    options.emitFileProcessed?.({
      filePath: 'src/index.ts',
      connections: [],
    });
    expect(source._eventBus.emit).toHaveBeenCalledWith(
      'analysis:fileProcessed',
      {
        filePath: 'src/index.ts',
        connections: [],
      },
    );
  });

  it('falls back to an empty relation set when the registry returns no analysis result', async () => {
    const source = {
      _cache: { files: {}, version: '1' },
      _discovery: {
        readContent: vi.fn(async () => "import './utils'"),
      },
      _getFileStat: vi.fn(async () => ({ mtime: 10, size: 5 })),
      _registry: {
        analyzeFileResult: vi.fn(async (): Promise<IFileAnalysisResult | null> => null),
      },
    };
    const analyzeWorkspaceFilesSpy = vi
      .spyOn(workspaceFileAnalysisModule, 'analyzeWorkspaceFiles')
      .mockResolvedValue({
        cacheHits: 0,
        cacheMisses: 1,
        fileAnalysis: new Map(),
        fileConnections: new Map(),
      });

    await analyzeWorkspacePipelineSourceFiles(
      source as never,
      [createDiscoveredFile('src/index.ts')],
      '/workspace',
      vi.fn(),
    );

    const options = analyzeWorkspaceFilesSpy.mock.calls[0][0];
    await expect(
      options.analyzeFile('/workspace/src/index.ts', "import './utils'", '/workspace'),
    ).resolves.toEqual({
      filePath: '/workspace/src/index.ts',
      relations: [],
    });
    expect(options.emitFileProcessed).toBeUndefined();
  });
});

