  it('awaits commit jumps', async () => {
    const handlers = createHandlers();

    await expect(
      applyTimelineMessage(
        { type: 'JUMP_TO_COMMIT', payload: { sha: 'abc123' } },
        handlers,
      ),
    ).resolves.toBe(true);

    expect(handlers.jumpToCommit).toHaveBeenCalledWith('abc123');
