import { describe, expect, it, vi } from 'vitest';
import type { DirectionMode } from '@/shared/settings/modes';
import {
  applySettingsDirectionMessage,
} from '../../../../../src/extension/graphView/webview/settingsMessages/direction';
import type {
  GraphViewSettingsMessageHandlers,
  GraphViewSettingsMessageState,
} from '../../../../../src/extension/graphView/webview/settingsMessages/router';

function createState(
  overrides: Partial<GraphViewSettingsMessageState> = {},
): GraphViewSettingsMessageState {
  return {
    disabledPlugins: new Set<string>(),
    filterPatterns: [],
    ...overrides,
  };
}

function createHandlers(
  initialConfig: Record<string, unknown> = {},
  overrides: Partial<GraphViewSettingsMessageHandlers> = {},
): GraphViewSettingsMessageHandlers {
  const config = new Map<string, unknown>([
    ['directionMode', 'arrows'],
    ['particleSpeed', 0.005],
    ['particleSize', 4],
    ['directionColor', '#475569'],
    ...Object.entries(initialConfig),
  ]);

  const handlers = {
    getConfig: vi.fn(<T>(key: string, defaultValue: T): T =>
      config.has(key) ? (config.get(key) as T) : defaultValue,
    ),
    updateConfig: vi.fn((key: string, value: unknown) => {
      config.set(key, value);
      return Promise.resolve();
    }),
    getPluginFilterPatterns: vi.fn(() => []),
    sendGraphControls: vi.fn(),
    sendMessage: vi.fn(),
    resetAllSettings: vi.fn(() => Promise.resolve()),
    ...overrides,
  };

  handlers.sendGraphControls ??= vi.fn();

  return handlers as GraphViewSettingsMessageHandlers;
}

describe('graph view settings direction message', () => {
  it('updates direction mode and publishes the full direction payload', async () => {
    const state = createState();
    const handlers = createHandlers({
      particleSpeed: 0.1,
      particleSize: 8,
      directionColor: 'bad-color',
    });

    await applySettingsDirectionMessage(
      { type: 'UPDATE_DIRECTION_MODE', payload: { directionMode: 'particles' } },
      state,
      handlers,
    );

    expect(handlers.updateConfig).toHaveBeenCalledWith('directionMode', 'particles');
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'DIRECTION_SETTINGS_UPDATED',
      payload: {
        directionMode: 'particles',
        particleSpeed: 0.1,
        particleSize: 8,
        directionColor: '#475569',
      },
    });
  });

  it('normalizes direction color updates before persisting them', async () => {
    const state = createState();
    const handlers = createHandlers({
      directionMode: 'none' satisfies DirectionMode,
      particleSpeed: 0.2,
      particleSize: 6,
    });

    await applySettingsDirectionMessage(
      { type: 'UPDATE_DIRECTION_COLOR', payload: { directionColor: '  #aa00cc ' } },
      state,
      handlers,
    );

    expect(handlers.updateConfig).toHaveBeenCalledWith('directionColor', '#AA00CC');
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'DIRECTION_SETTINGS_UPDATED',
      payload: {
        directionMode: 'none',
        particleSpeed: 0.2,
        particleSize: 6,
        directionColor: '#AA00CC',
      },
    });
  });

  it('returns false for unrelated messages', async () => {
    const state = createState();
    const handlers = createHandlers();

    await expect(
      applySettingsDirectionMessage({ type: 'UPDATE_MAX_FILES', payload: { maxFiles: 42 } }, state, handlers),
    ).resolves.toBe(false);
  });
});

import { describe, expect, it } from 'vitest';
import {
  readEdgeTypes,
  readNodeTypes,
  readRegistryDefinitions,
} from '../../../../src/extension/graphView/controls/send/registry';

describe('extension/graphView/controls/registry', () => {
  it('returns an empty list without throwing when the registry is missing or malformed', () => {
    expect(readNodeTypes(undefined)).toEqual([]);
    expect(readEdgeTypes(null)).toEqual([]);
    expect(readNodeTypes('not-an-object')).toEqual([]);
    expect(
      readNodeTypes(
        Object.assign(() => undefined, {
          listNodeTypes: () => [{ id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true }],
        }),
      ),
    ).toEqual([]);

    expect(() =>
      readNodeTypes({
        listNodeTypes: 'not-a-function',
      }),
    ).not.toThrow();
    expect(
      readNodeTypes({
        listNodeTypes: 'not-a-function',
      }),
    ).toEqual([]);

    expect(() =>
      readEdgeTypes({
        listEdgeTypes: () => 'not-an-array',
      }),
    ).not.toThrow();
    expect(
      readEdgeTypes({
        listEdgeTypes: () => 'not-an-array',
      }),
    ).toEqual([]);
  });

  it('calls registry reader methods with the registry as this and without arguments', () => {
    const registry = {
      listNodeTypes(this: unknown, ...args: unknown[]) {
        expect(this).toBe(registry);
        expect(args).toEqual([]);
        return [{ id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true }];
      },
    };

    expect(readNodeTypes(registry)).toEqual([
      { id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true },
    ]);
  });

  it('reads node and edge definitions from their matching registry methods', () => {
    expect(
      readNodeTypes({
        listNodeTypes: () => [{ id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true }],
        listEdgeTypes: () => [{ id: 'wrong', label: 'Wrong', defaultColor: '#F97316', defaultVisible: true }],
      }),
    ).toEqual([
      { id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true },
    ]);

    expect(
      readEdgeTypes({
        listNodeTypes: () => [{ id: 'wrong', label: 'Wrong', defaultColor: '#22C55E', defaultVisible: true }],
        listEdgeTypes: () => [{ id: 'plugin:route', label: 'Route', defaultColor: '#F97316', defaultVisible: true }],
      }),
    ).toEqual([
      { id: 'plugin:route', label: 'Route', defaultColor: '#F97316', defaultVisible: true },
    ]);
  });

  it('filters registry definitions through the provided type guard', () => {
    const definitions = readRegistryDefinitions(
      {
        listNodeTypes: () => [
          null,
          { id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true },
          { id: 'bad-node', label: 'Bad Node', defaultColor: '#22C55E', defaultVisible: 'yes' },
        ],
      },
      'listNodeTypes',
      (
        definition,
      ): definition is { id: string; label: string; defaultColor: string; defaultVisible: boolean } =>
        Boolean(
          definition
          && typeof definition === 'object'
          && typeof (definition as Record<string, unknown>).id === 'string'
          && typeof (definition as Record<string, unknown>).label === 'string'
          && typeof (definition as Record<string, unknown>).defaultColor === 'string'
          && typeof (definition as Record<string, unknown>).defaultVisible === 'boolean',
        ),
    );

    expect(definitions).toEqual([
      { id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true },
    ]);
  });
});

