import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
  handleCSharpNamespaceNode,
  handleCSharpUsingDirective,
} from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/csharpNamespace';
import { getResolvedNamespaceName } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/csharpNamespaceNames';
import { getNodeText } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/nodes';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/csharpNamespaceNames', () => ({
  getResolvedNamespaceName: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/nodes', () => ({
  getNodeText: vi.fn((node?: { text?: string } | null) => node?.text ?? null),
}));

function createNode(overrides: Partial<{
  type: string;
  namedChildren: Array<{ type: string; text?: string }>;
}> = {}) {
  return {
    type: 'namespace_declaration',
    namedChildren: [],
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/csharpNamespace', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('skips children for file-scoped namespace declarations', () => {
    const walk = vi.fn();

    expect(
      handleCSharpNamespaceNode(
        createNode({ type: 'file_scoped_namespace_declaration' }) as never,
        { currentNamespace: 'CodeGraphy' } as never,
        walk,
      ),
    ).toEqual({ skipChildren: true });
    expect(walk).not.toHaveBeenCalled();
    expect(getResolvedNamespaceName).not.toHaveBeenCalled();
  });

  it('walks named children with the resolved namespace for regular declarations', () => {
    vi.mocked(getResolvedNamespaceName).mockReturnValue('CodeGraphy.Runtime');
    const walk = vi.fn();
    const state = { currentNamespace: 'CodeGraphy' };
    const node = createNode({
      namedChildren: [{ type: 'class_declaration' }, { type: 'method_declaration' }],
    });

    expect(handleCSharpNamespaceNode(node as never, state as never, walk)).toEqual({
      skipChildren: true,
    });
    expect(getResolvedNamespaceName).toHaveBeenCalledWith(node, 'CodeGraphy');
    expect(walk).toHaveBeenNthCalledWith(
      1,
      node.namedChildren[0],
      expect.objectContaining({ currentNamespace: 'CodeGraphy.Runtime' }),
    );
    expect(walk).toHaveBeenNthCalledWith(
      2,
      node.namedChildren[1],
      expect.objectContaining({ currentNamespace: 'CodeGraphy.Runtime' }),
    );
  });

  it('adds non-empty using directive specifiers and skips empty ones', () => {
    const usingNamespaces = new Set<string>();

    handleCSharpUsingDirective(
      createNode({ namedChildren: [{ type: 'qualified_name', text: 'System.Linq' }] }) as never,
      usingNamespaces,
    );
    handleCSharpUsingDirective(createNode() as never, usingNamespaces);

    expect(getNodeText).toHaveBeenCalledWith({ type: 'qualified_name', text: 'System.Linq' });
    expect(getNodeText).toHaveBeenCalledWith(undefined);
    expect([...usingNamespaces]).toEqual(['System.Linq']);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import * as fs from 'node:fs';
import { readWorkspaceAnalysisDatabaseSnapshot } from '../../../../src/extension/pipeline/database/cacheSnapshot';
import { readRowsSync, withConnection } from '../../../../src/extension/pipeline/database/cacheConnection';
import { getWorkspaceAnalysisDatabasePath } from '../../../../src/extension/pipeline/database/cachePaths';
import {
  createSnapshotFileEntry,
  createSnapshotRelationEntry,
  createSnapshotSymbolEntry,
} from '../../../../src/extension/pipeline/database/cacheRows';
import {
  FILE_ANALYSIS_ROWS_QUERY,
  RELATION_ROWS_QUERY,
  SYMBOL_ROWS_QUERY,
} from '../../../../src/extension/pipeline/database/cacheStatements';

vi.mock('node:fs', async (importOriginal) => {
  const actual = await importOriginal<typeof import('node:fs')>();
  return {
    ...actual,
    existsSync: vi.fn(),
  };
});

vi.mock('../../../../src/extension/pipeline/database/cacheConnection', () => ({
  readRowsSync: vi.fn(),
  withConnection: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/database/cachePaths', () => ({
  getWorkspaceAnalysisDatabasePath: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/database/cacheRows', () => ({
  createSnapshotFileEntry: vi.fn(),
  createSnapshotRelationEntry: vi.fn(),
  createSnapshotSymbolEntry: vi.fn(),
}));

describe('pipeline/database/cacheSnapshot', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(getWorkspaceAnalysisDatabasePath).mockReturnValue('/workspace/.codegraphy/graph.lbug');
  });

  it('returns an empty snapshot when the repo-local database does not exist', () => {
    vi.mocked(fs.existsSync).mockReturnValue(false);

    expect(readWorkspaceAnalysisDatabaseSnapshot('/workspace')).toEqual({
      files: [],
      symbols: [],
      relations: [],
    });
    expect(withConnection).not.toHaveBeenCalled();
  });

  it('reads rows through the database connection and drops invalid snapshot entries', () => {
    vi.mocked(fs.existsSync).mockReturnValue(true);
    vi.mocked(withConnection).mockImplementation((_path, callback) => callback('connection' as never));
    vi.mocked(readRowsSync)
      .mockReturnValueOnce([{ id: 'file-1' }, { id: 'file-2' }] as never)
      .mockReturnValueOnce([{ id: 'symbol-1' }] as never)
      .mockReturnValueOnce([{ id: 'relation-1' }, { id: 'relation-2' }] as never);
    vi.mocked(createSnapshotFileEntry)
      .mockReturnValueOnce({ filePath: 'src/file.ts', mtime: 1, analysis: { filePath: 'src/file.ts', relations: [] } } as never)
      .mockReturnValueOnce(undefined);
    vi.mocked(createSnapshotSymbolEntry).mockReturnValueOnce({ id: 'symbol-1', filePath: 'src/file.ts', name: 'render', kind: 'function' } as never);
    vi.mocked(createSnapshotRelationEntry)
      .mockReturnValueOnce({ kind: 'import', sourceId: 'source', fromFilePath: 'src/file.ts' } as never)
      .mockReturnValueOnce(undefined);

    expect(readWorkspaceAnalysisDatabaseSnapshot('/workspace')).toEqual({
      files: [{ filePath: 'src/file.ts', mtime: 1, analysis: { filePath: 'src/file.ts', relations: [] } }],
      symbols: [{ id: 'symbol-1', filePath: 'src/file.ts', name: 'render', kind: 'function' }],
      relations: [{ kind: 'import', sourceId: 'source', fromFilePath: 'src/file.ts' }],
    });

    expect(readRowsSync).toHaveBeenNthCalledWith(1, 'connection', FILE_ANALYSIS_ROWS_QUERY);
    expect(readRowsSync).toHaveBeenNthCalledWith(2, 'connection', SYMBOL_ROWS_QUERY);
    expect(readRowsSync).toHaveBeenNthCalledWith(3, 'connection', RELATION_ROWS_QUERY);
  });

  it('warns and falls back to an empty snapshot when reading the database fails', () => {
    vi.mocked(fs.existsSync).mockReturnValue(true);
    const warning = vi.spyOn(console, 'warn').mockImplementation(() => undefined);
    const error = new Error('corrupt database');
    vi.mocked(withConnection).mockImplementation(() => {
      throw error;
    });

    expect(readWorkspaceAnalysisDatabaseSnapshot('/workspace')).toEqual({
      files: [],
      symbols: [],
      relations: [],
    });
    expect(warning).toHaveBeenCalledWith(
      '[CodeGraphy] Failed to read structured analysis snapshot.',
      error,
    );
  });
});

