import { describe, expect, it, vi } from 'vitest';
import { walkSymbolBody, walkTree } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/walk';

function createNode(overrides: Partial<{
  type: string;
  namedChildren: unknown[];
  childForFieldName: (name: string) => unknown;
}> = {}) {
  return {
    type: 'node',
    namedChildren: [],
    childForFieldName: () => null,
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/walk', () => {
  it('recursively walks child nodes with the current or updated context', () => {
    const child = createNode({ type: 'child' });
    const grandchild = createNode({ type: 'grandchild' });
    const root = createNode({ type: 'root', namedChildren: [createNode({ type: 'middle', namedChildren: [grandchild] }), child] });
    const visits: string[] = [];

    walkTree(root as never, 'root-context', (node, context) => {
      visits.push(`${node.type}:${context}`);
      if (node.type === 'root') {
        return { nextContext: 'nested-context' };
      }

      return undefined;
    });

    expect(visits).toEqual([
      'root:root-context',
      'middle:nested-context',
      'grandchild:nested-context',
      'child:nested-context',
    ]);
  });

  it('skips children when the visitor requests it', () => {
    const visits: string[] = [];

    walkTree(
      createNode({ type: 'root', namedChildren: [createNode({ type: 'child' })] }) as never,
      null,
      (node) => {
        visits.push(node.type);
        return { skipChildren: true };
      },
    );

    expect(visits).toEqual(['root']);
  });

  it('walks symbol bodies through the body field or final named child', () => {
    const walk = vi.fn();
    const fieldBody = createNode({ type: 'block' });
    const fallbackBody = createNode({ type: 'fallback-block' });

    expect(
      walkSymbolBody(
        createNode({ childForFieldName: (name: string) => (name === 'body' ? fieldBody : null) }) as never,
        'symbol-id',
        walk,
      ),
    ).toEqual({ skipChildren: true });
    expect(
      walkSymbolBody(
        createNode({ namedChildren: [fallbackBody], childForFieldName: () => null }) as never,
        'symbol-id',
        walk,
      ),
    ).toEqual({ skipChildren: true });
    expect(
      walkSymbolBody(createNode() as never, 'symbol-id', walk),
    ).toEqual({ skipChildren: true });

    expect(walk).toHaveBeenCalledTimes(2);
    expect(walk).toHaveBeenNthCalledWith(1, fieldBody, { currentSymbolId: 'symbol-id' });
    expect(walk).toHaveBeenNthCalledWith(2, fallbackBody, { currentSymbolId: 'symbol-id' });
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { applyImportClauseBinding } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseBindingHelpers';
import { addCollectedImportBinding } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseCollectedBinding';
import { addNamedImportBindings } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseNamedBindings';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseCollectedBinding', () => ({
  addCollectedImportBinding: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseNamedBindings', () => ({
  addNamedImportBindings: vi.fn(),
}));

function createNode(overrides: Partial<{
  type: string;
  text: string;
  namedChildren: Array<{ type: string; text?: string }>;
}> = {}) {
  return {
    type: 'identifier',
    text: 'binding',
    namedChildren: [],
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/importClauseBindingHelpers', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('adds default bindings for identifier clauses', () => {
    const importedBindings = new Map();

    applyImportClauseBinding(
      createNode({ type: 'identifier', text: 'React' }) as never,
      importedBindings,
      'react',
      '/workspace/node_modules/react/index.js',
    );

    expect(addCollectedImportBinding).toHaveBeenCalledWith(
      importedBindings,
      'React',
      'default',
      'react',
      '/workspace/node_modules/react/index.js',
    );
    expect(addNamedImportBindings).not.toHaveBeenCalled();
  });

  it('delegates named imports to the named-binding helper', () => {
    const importedBindings = new Map();
    const node = createNode({ type: 'named_imports' });

    applyImportClauseBinding(node as never, importedBindings, './lib', null);

    expect(addNamedImportBindings).toHaveBeenCalledWith(node, importedBindings, './lib', null);
    expect(addCollectedImportBinding).not.toHaveBeenCalled();
  });

  it('adds namespace imports from the local identifier and ignores unsupported clauses', () => {
    const importedBindings = new Map();

    applyImportClauseBinding(
      createNode({
        type: 'namespace_import',
        namedChildren: [
          { type: 'operator', text: '*' },
          { type: 'identifier', text: 'services' },
        ],
      }) as never,
      importedBindings,
      './services',
      '/workspace/src/services.ts',
    );

    applyImportClauseBinding(
      createNode({
        type: 'namespace_import',
        namedChildren: [{ type: 'string', text: 'ignored' }],
      }) as never,
      importedBindings,
      './services',
      '/workspace/src/services.ts',
    );

    applyImportClauseBinding(
      createNode({ type: 'string' }) as never,
      importedBindings,
      './services',
      '/workspace/src/services.ts',
    );

    expect(addCollectedImportBinding).toHaveBeenCalledTimes(1);
    expect(addCollectedImportBinding).toHaveBeenCalledWith(
      importedBindings,
      'services',
      '*',
      './services',
      '/workspace/src/services.ts',
    );
  });
});

