import { describe, expect, it } from 'vitest';
import {
  deepClone,
  deepMerge,
  isPlainObject,
} from '../../../src/extension/repoSettings/storeObjects';

describe('extension/repoSettings/storeObjects', () => {
  it('deep clones nested objects and arrays without preserving references', () => {
    const original = {
      legend: [{ id: 'legend-rule', pattern: 'src/**', color: '#123456' }],
      timeline: { maxCommits: 500, playbackSpeed: 1 },
    };

    const cloned = deepClone(original);
    cloned.legend[0].color = '#abcdef';
    cloned.timeline.playbackSpeed = 2;

    expect(cloned).toEqual({
      legend: [{ id: 'legend-rule', pattern: 'src/**', color: '#abcdef' }],
      timeline: { maxCommits: 500, playbackSpeed: 2 },
    });
    expect(original).toEqual({
      legend: [{ id: 'legend-rule', pattern: 'src/**', color: '#123456' }],
      timeline: { maxCommits: 500, playbackSpeed: 1 },
    });
  });

  it('recognizes only plain objects', () => {
    expect(isPlainObject({ legend: [] })).toBe(true);
    expect(isPlainObject(null)).toBe(false);
    expect(isPlainObject(['legend'])).toBe(false);
    expect(isPlainObject('settings')).toBe(false);
    expect(isPlainObject(42)).toBe(false);
  });

  it('deep merges nested objects while replacing arrays and scalar values', () => {
    const merged = deepMerge(
      {
        legend: [{ id: 'default', pattern: 'src/**', color: '#123456' }],
        nodeColors: { file: '#111111', folder: '#222222' },
        timeline: { maxCommits: 500, playbackSpeed: 1 },
      },
      {
        legend: [{ id: 'override', pattern: 'tests/**', color: '#abcdef' }],
        nodeColors: { folder: '#654321' },
        timeline: { playbackSpeed: 2 },
      },
    );

    expect(merged).toEqual({
      legend: [{ id: 'override', pattern: 'tests/**', color: '#abcdef' }],
      nodeColors: { file: '#111111', folder: '#654321' },
      timeline: { maxCommits: 500, playbackSpeed: 2 },
    });
  });

  it('returns the override when either side is not a plain object', () => {
    expect(deepMerge({ timeline: { playbackSpeed: 1 } }, null)).toEqual({ timeline: { playbackSpeed: 1 } });
    expect(deepMerge({ timeline: { playbackSpeed: 1 } }, ['override'])).toEqual(['override']);
    expect(deepMerge('base', { playbackSpeed: 2 })).toEqual({ playbackSpeed: 2 });
  });
});

import { describe, expect, it } from 'vitest';
import { createDefaultCodeGraphyRepoSettings } from '../../../src/extension/repoSettings/defaults';
import { serializeSettings } from '../../../src/extension/repoSettings/storeSerialization';

type LegacySettingsShape = ReturnType<typeof createDefaultCodeGraphyRepoSettings> & {
  exclude?: string[];
  folderNodeColor?: string;
  nodeColors?: unknown;
};

describe('extension/repoSettings/storeSerialization', () => {
  it('removes legacy fields and backfills folder node colors into nodeColors', () => {
    const settings: LegacySettingsShape = createDefaultCodeGraphyRepoSettings();
    settings.exclude = ['legacy'];
    settings.folderNodeColor = '#445566';
    settings.nodeColors = { file: '#111111' };

    const serialized = serializeSettings(settings);
    const parsed = JSON.parse(serialized) as Record<string, unknown>;

    expect(serialized.endsWith('\n')).toBe(true);
    expect(parsed.exclude).toBeUndefined();
    expect(parsed.folderNodeColor).toBeUndefined();
    expect(parsed.nodeColors).toEqual({
      file: '#111111',
      folder: '#445566',
    });
    expect(settings.exclude).toEqual(['legacy']);
    expect(settings.folderNodeColor).toBe('#445566');
  });

  it('prefers an explicit folder color over the legacy folderNodeColor alias', () => {
    const settings: LegacySettingsShape = createDefaultCodeGraphyRepoSettings();
    settings.folderNodeColor = '#445566';
    settings.nodeColors = { folder: '#123456', file: '#111111' };

    const parsed = JSON.parse(serializeSettings(settings)) as Record<string, unknown>;

    expect(parsed.nodeColors).toEqual({
      folder: '#123456',
      file: '#111111',
    });
  });

  it('writes an empty nodeColors object when the persisted value is malformed', () => {
    const settings = createDefaultCodeGraphyRepoSettings() as Omit<LegacySettingsShape, 'nodeColors'> & {
      nodeColors: unknown;
    };
    settings.nodeColors = 'invalid';
    settings.folderNodeColor = '';

    const parsed = JSON.parse(
      serializeSettings(settings as ReturnType<typeof createDefaultCodeGraphyRepoSettings>),
    ) as Record<string, unknown>;

    expect(parsed.nodeColors).toEqual({ folder: '' });
  });
});

