import { beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import type { IGraphData } from '../../src/shared/graph/types';
import { GraphViewProvider } from '../../src/extension/graphViewProvider';
import { getGraphViewProviderInternals } from './graphViewProvider/internals';

let workspaceFoldersValue:
  | Array<{ uri: { fsPath: string; path: string }; name: string; index: number }>
  | undefined;

Object.defineProperty(vscode.workspace, 'workspaceFolders', {
  get: () => workspaceFoldersValue,
  configurable: true,
});

function createContext() {
  return {
    subscriptions: [],
    extensionUri: vscode.Uri.file('/test/extension'),
    workspaceState: {
      get: vi.fn(() => undefined),
      update: vi.fn(() => Promise.resolve()),
    },
  };
}

describe('GraphViewProvider error handling', () => {
  beforeEach(() => {
    workspaceFoldersValue = [
      { uri: vscode.Uri.file('/test/workspace'), name: 'workspace', index: 0 },
    ];
    vi.clearAllMocks();
  });

  it('logs unexpected analysis errors and clears the active controller', async () => {
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const consoleErrorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

    (provider as unknown as { _analyzerInitialized: boolean })._analyzerInitialized = true;
    (provider as unknown as {
      _analyzer: {
        analyze: () => Promise<IGraphData>;
        hasIndex(): boolean;
        initialize(): Promise<void>;
        discoverGraph(): Promise<IGraphData>;
        registry: { notifyPostAnalyze(graph: IGraphData): void };
      };
    })._analyzer = {
      analyze: vi.fn().mockRejectedValueOnce(new Error('boom')),
      hasIndex: () => true,
      initialize: vi.fn().mockResolvedValue(undefined),
      discoverGraph: vi.fn().mockResolvedValue({ nodes: [], edges: [] }),
      registry: {
        notifyPostAnalyze: () => {},
      },
    };

    await internals._analysisMethods._analyzeAndSendData();

    expect(consoleErrorSpy).toHaveBeenCalledWith('[CodeGraphy] Analysis failed:', expect.any(Error));
    expect((provider as unknown as { _analysisController?: AbortController })._analysisController).toBeUndefined();
  });

  it('sends empty graph data when workspace analysis throws a non-abort error', async () => {
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const consoleErrorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

    (provider as unknown as { _analysisRequestId: number })._analysisRequestId = 1;
    (provider as unknown as { _analyzerInitialized: boolean })._analyzerInitialized = true;
    (provider as unknown as {
      _analyzer: {
        analyze: () => Promise<IGraphData>;
        registry: { list(): unknown[]; notifyPostAnalyze(graph: IGraphData): void };
      };
    })._analyzer = {
      analyze: vi.fn().mockRejectedValueOnce(new Error('analysis failed')),
      registry: {
        list: () => [],
        notifyPostAnalyze: () => {},
      },
    };
    vi.spyOn(internals._pluginResourceMethods, '_computeMergedGroups').mockImplementation(() => {});
    vi.spyOn(internals._pluginMethods, '_sendGroupsUpdated').mockImplementation(() => {});
    const sendMessageSpy = vi
      .spyOn(internals._webviewMethods, '_sendMessage')
      .mockImplementation(() => {});
    const sendDepthStateSpy = vi
      .spyOn(internals._viewContextMethods, '_sendDepthState')
      .mockImplementation(() => {});
    const sendPluginStatusesSpy = vi
      .spyOn(internals._pluginMethods, '_sendPluginStatuses')
      .mockImplementation(() => {});
    const sendPluginExportersSpy = vi
      .spyOn(internals._pluginMethods, '_sendPluginExporters')
      .mockImplementation(() => {});
    const markWorkspaceReadySpy = vi
      .spyOn(internals._analysisMethods, '_markWorkspaceReady')
      .mockImplementation(() => {});

    await internals._analysisMethods._doAnalyzeAndSendData(new AbortController().signal, 1);

    expect(consoleErrorSpy).toHaveBeenCalledWith('[CodeGraphy] Analysis failed:', expect.any(Error));
    expect((provider as unknown as { _graphData: IGraphData })._graphData).toEqual({ nodes: [], edges: [] });
    expect(sendMessageSpy).toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
    expect(sendDepthStateSpy).toHaveBeenCalledTimes(1);
    expect(sendPluginStatusesSpy).toHaveBeenCalledTimes(1);
    expect(sendPluginExportersSpy).toHaveBeenCalledTimes(1);
    expect(markWorkspaceReadySpy).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('recognizes abort errors without treating other errors as aborted', () => {
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const abortError = new Error('cancelled');
    abortError.name = 'AbortError';

    expect(internals._analysisMethods._isAbortError(abortError)).toBe(true);
    expect(internals._analysisMethods._isAbortError(new Error('boom'))).toBe(false);
    expect(internals._analysisMethods._isAbortError('AbortError')).toBe(false);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import { GraphViewProvider } from '../../src/extension/graphViewProvider';
import { getGraphViewProviderInternals } from './graphViewProvider/internals';

let workspaceFoldersValue:
  | Array<{ uri: { fsPath: string; path: string }; name: string; index: number }>
  | undefined;

Object.defineProperty(vscode.workspace, 'workspaceFolders', {
  get: () => workspaceFoldersValue,
  configurable: true,
});

function createContext(visits: Record<string, number> = {}) {
  return {
    subscriptions: [],
    extensionUri: vscode.Uri.file('/test/extension'),
    workspaceState: {
      get: vi.fn((key: string) => {
        if (key === 'codegraphy.fileVisits') {
          return visits;
        }
        return undefined;
      }),
      update: vi.fn(() => Promise.resolve()),
    },
  };
}

function resolveMessageHandler(provider: GraphViewProvider) {
  let messageHandler: ((message: unknown) => Promise<void>) | null = null;
  const postMessage = vi.fn();
  const mockWebview = {
    options: {},
    html: '',
    onDidReceiveMessage: vi.fn((handler: (message: unknown) => Promise<void>) => {
      messageHandler = handler;
      return { dispose: () => {} };
    }),
    postMessage,
    asWebviewUri: vi.fn((uri: vscode.Uri) => uri),
    cspSource: 'test-csp',
  };
  const mockView = {
    webview: mockWebview,
    visible: true,
    onDidChangeVisibility: vi.fn(() => ({ dispose: () => {} })),
    onDidDispose: vi.fn(() => ({ dispose: () => {} })),
    show: vi.fn(),
  };

  provider.resolveWebviewView(
    mockView as unknown as vscode.WebviewView,
    {} as vscode.WebviewViewResolveContext,
    { isCancellationRequested: false, onCancellationRequested: vi.fn() } as unknown as vscode.CancellationToken
  );

  expect(messageHandler).not.toBeNull();
  return { messageHandler: messageHandler!, postMessage };
}

describe('GraphViewProvider file info and visits', () => {
  beforeEach(() => {
    workspaceFoldersValue = [
      { uri: vscode.Uri.file('/test/workspace'), name: 'workspace', index: 0 },
    ];
    vi.clearAllMocks();
  });

  it('reports connection counts, visits, and plugin names for GET_FILE_INFO', async () => {
    const context = createContext({ 'src/main.py': 4 });
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      context as unknown as vscode.ExtensionContext
    );
    const { messageHandler, postMessage } = resolveMessageHandler(provider);

    provider.updateGraphData({
      nodes: [
        { id: 'src/main.py', label: 'main.py', color: '#ffffff' },
        { id: 'src/config.py', label: 'config.py', color: '#ffffff' },
        { id: 'src/input.py', label: 'input.py', color: '#ffffff' },
        { id: 'src/other.py', label: 'other.py', color: '#ffffff' },
      ],
      edges: [
        { id: 'src/main.py->src/config.py', from: 'src/main.py', to: 'src/config.py' , kind: 'import', sources: [] },
        { id: 'src/input.py->src/main.py', from: 'src/input.py', to: 'src/main.py' , kind: 'import', sources: [] },
        { id: 'src/main.py->src/other.py', from: 'src/main.py', to: 'src/other.py' , kind: 'import', sources: [] },
        { id: 'src/other.py->src/config.py', from: 'src/other.py', to: 'src/config.py' , kind: 'import', sources: [] },
      ],
    });

    const initialize = vi.fn().mockResolvedValue(undefined);
    (provider as unknown as {
      _analyzerInitialized: boolean;
      _analyzer: {
        initialize: () => Promise<void>;
        getPluginNameForFile: (filePath: string) => string;
      };
    })._analyzerInitialized = false;
    (provider as unknown as {
      _analyzer: {
        initialize: () => Promise<void>;
        getPluginNameForFile: (filePath: string) => string;
      };
    })._analyzer = {
      initialize,
      getPluginNameForFile: vi.fn(() => 'Python'),
    };

    const mutableWorkspaceFs = vscode.workspace.fs as unknown as Record<string, unknown>;
    mutableWorkspaceFs.stat = vi.fn().mockResolvedValue({
      mtime: 123,
      size: 456,
    });

    await messageHandler({ type: 'GET_FILE_INFO', payload: { path: 'src/main.py' } });
    await new Promise((resolve) => setTimeout(resolve, 0));

    const fileInfoMessage = postMessage.mock.calls.find(
      (call: unknown[]) => (call[0] as { type?: string }).type === 'FILE_INFO'
    )?.[0] as { payload: Record<string, unknown> } | undefined;

    expect(initialize).toHaveBeenCalledTimes(1);
    expect(fileInfoMessage?.payload).toMatchObject({
      path: 'src/main.py',
      size: 456,
      lastModified: 123,
      incomingCount: 1,
      outgoingCount: 2,
      plugin: 'Python',
      visits: 4,
    });
  });

  it('tracks file visits for visible graph nodes and sends access-count updates', async () => {
    const context = createContext({ 'src/main.py': 2 });
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      context as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const sendMessageSpy = vi.spyOn(
      internals._webviewMethods,
      '_sendMessage'
    ).mockImplementation(() => {});

    provider.updateGraphData({
      nodes: [
        { id: 'src/main.py', label: 'main.py', color: '#ffffff' },
        { id: 'src/other.py', label: 'other.py', color: '#ffffff' },
      ],
      edges: [],
    });

    await provider.trackFileVisit('src/main.py');

    expect(context.workspaceState.update).toHaveBeenCalledWith('codegraphy.fileVisits', {
      'src/main.py': 3,
    });
    expect(sendMessageSpy).toHaveBeenCalledWith({
      type: 'NODE_ACCESS_COUNT_UPDATED',
      payload: { nodeId: 'src/main.py', accessCount: 3 },
    });
  });

  it('ignores tracked file visits for nodes outside the current graph', async () => {
    const context = createContext({ 'src/main.py': 2 });
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      context as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const sendMessageSpy = vi.spyOn(
      internals._webviewMethods,
      '_sendMessage'
    ).mockImplementation(() => {});

    provider.updateGraphData({
      nodes: [{ id: 'src/other.py', label: 'other.py', color: '#ffffff' }],
      edges: [],
    });

    await provider.trackFileVisit('src/main.py');

    expect(context.workspaceState.update).not.toHaveBeenCalledWith(
      'codegraphy.fileVisits',
      expect.anything()
    );
    expect(sendMessageSpy).not.toHaveBeenCalledWith(
      expect.objectContaining({ type: 'NODE_ACCESS_COUNT_UPDATED' })
    );
  });
});

