      payload: { depthLimit: 1 },
    });
    expect(sendMessageSpy).not.toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: expect.anything(),
    });
  });

  it('sends the full settings payload set from configuration', () => {
    (vscode.workspace as unknown as { getConfiguration: ReturnType<typeof vi.fn> }).getConfiguration =
      vi.fn(() =>
        createConfiguration({
          bidirectionalEdges: 'combined',
          showOrphans: false,
          directionMode: 'particles',
          particleSpeed: 0.02,
          particleSize: 7,
          directionColor: '#00ff00',
          showLabels: false,
        })
      );

    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const sendMessageSpy = vi.spyOn(
      internals._webviewMethods,
      '_sendMessage'
    ).mockImplementation(() => {});

    internals._settingsStateMethods._sendSettings();

    expect(sendMessageSpy).toHaveBeenNthCalledWith(1, {
      type: 'SETTINGS_UPDATED',
      payload: { bidirectionalEdges: 'combined', showOrphans: false },
    });
    expect(sendMessageSpy).toHaveBeenNthCalledWith(2, {
      type: 'DIRECTION_SETTINGS_UPDATED',
      payload: {
        directionMode: 'particles',
        particleSpeed: 0.02,
        particleSize: 7,
        directionColor: '#00FF00',
      },
    });
    expect(sendMessageSpy).toHaveBeenNthCalledWith(3, {
      type: 'SHOW_LABELS_UPDATED',
      payload: { showLabels: false },
    });
  });

  it('sends physics settings from configuration', () => {
    (vscode.workspace as unknown as { getConfiguration: ReturnType<typeof vi.fn> }).getConfiguration =
      vi.fn(() =>
        createConfiguration({
          'physics.repelForce': 14,
          'physics.linkDistance': 90,
          'physics.linkForce': 0.25,
          'physics.damping': 0.6,
          'physics.centerForce': 0.2,
        })
      );

    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const sendMessageSpy = vi.spyOn(
      internals._webviewMethods,
      '_sendMessage'
    ).mockImplementation(() => {});

    internals._physicsSettingsMethods._sendPhysicsSettings();

    expect(sendMessageSpy).toHaveBeenCalledWith({
      type: 'PHYSICS_SETTINGS_UPDATED',
      payload: {
        repelForce: 14,
        linkDistance: 90,
        linkForce: 0.25,
        damping: 0.6,
        centerForce: 0.2,
      },
    });
  });

  it('returns no plugin default groups when no analyzer is ready', () => {
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);

    expect(internals._pluginResourceMethods._getPluginDefaultGroups()).toEqual([]);
  });

  it('rebuilds graph data and notifies dependents when analyzer state is available', () => {
    (vscode.workspace as unknown as { getConfiguration: ReturnType<typeof vi.fn> }).getConfiguration =
      vi.fn(() => createConfiguration({ showOrphans: false }));

    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const graphData: IGraphData = {
      nodes: [{ id: 'src/app.ts', label: 'app.ts', color: '#ffffff' }],
      edges: [],
    };
    const rebuildGraph = vi.fn(() => graphData);
    const notifyGraphRebuild = vi.fn();
    (provider as unknown as {
      _analyzer: {
        rebuildGraph: typeof rebuildGraph;
        registry: { notifyGraphRebuild: typeof notifyGraphRebuild };
      };
    })._analyzer = {
      rebuildGraph,
      registry: { notifyGraphRebuild },
    };
    const updateViewContextSpy = vi.spyOn(
      internals._viewContextMethods,
      '_updateViewContext'
    ).mockImplementation(() => {});
    const applySpy = vi.spyOn(
      internals._viewContextMethods,
      '_applyViewTransform'
    ).mockImplementation(() => {});
    const sendViewsSpy = vi.spyOn(
      internals._viewContextMethods,
      '_sendDepthState'
    ).mockImplementation(() => {});
    const sendStatusesSpy = vi.spyOn(
      internals._pluginMethods,
      '_sendPluginStatuses'
    ).mockImplementation(() => {});
    const sendDecorationsSpy = vi.spyOn(
      internals._pluginMethods,
      '_sendDecorations'
    ).mockImplementation(() => {});
    const sendMessageSpy = vi.spyOn(
      internals._webviewMethods,
      '_sendMessage'
    ).mockImplementation(() => {});

    internals._refreshMethods._rebuildAndSend();

    expect(rebuildGraph).toHaveBeenCalledWith(new Set(), false);
    expect((provider as unknown as { _rawGraphData: IGraphData })._rawGraphData).toEqual(graphData);
    expect(updateViewContextSpy).toHaveBeenCalledTimes(1);
    expect(applySpy).toHaveBeenCalledTimes(1);
    expect(sendViewsSpy).toHaveBeenCalledTimes(1);
    expect(sendStatusesSpy).toHaveBeenCalledTimes(1);
    expect(sendDecorationsSpy).toHaveBeenCalledTimes(1);
    expect(sendMessageSpy).toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
    expect(notifyGraphRebuild).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('applies refreshed resource roots to editor panels', () => {
    const provider = new GraphViewProvider(
      vscode.Uri.file('/test/extension'),
      createContext() as unknown as vscode.ExtensionContext
    );
    const internals = getGraphViewProviderInternals(provider);
    const panelWebview = { options: {}, asWebviewUri: vi.fn((uri: vscode.Uri) => uri) };
    (provider as unknown as {
      _view?: unknown;
      _panels: Array<{ webview: typeof panelWebview }>;
    })._panels = [{ webview: panelWebview }];

    internals._pluginResourceMethods._refreshWebviewResourceRoots();

    expect(
      (panelWebview.options as { localResourceRoots?: Array<{ fsPath: string }> }).localResourceRoots?.some(
        (uri) => uri.fsPath === '/test/extension'
      )
    ).toBe(true);
  });
});

/**
 * @fileoverview Additional tests for graphView resources targeting surviving mutants.
 */

import { describe, it, expect, vi } from 'vitest';
import * as vscode from 'vscode';
import {
  normalizeGraphViewExtensionUri,
  resolveGraphViewAssetPath,
  getGraphViewUriKey,
} from '../../../src/extension/graphView/resources';

describe('resolveGraphViewAssetPath (extra mutant coverage)', () => {
  it('passes through http:// URLs unchanged', () => {
    expect(
      resolveGraphViewAssetPath(
        'http://example.com/asset.js',
        vscode.Uri.file('/ext'),
        new Map(),
        undefined
      )
    ).toBe('http://example.com/asset.js');
  });

  it('passes through ftp:// URLs unchanged', () => {
    expect(
      resolveGraphViewAssetPath(
        'ftp://example.com/file',
        vscode.Uri.file('/ext'),
        new Map(),
        undefined
      )
    ).toBe('ftp://example.com/file');
  });

  it('passes through custom-scheme:// URLs unchanged', () => {
    expect(
      resolveGraphViewAssetPath(
        'vscode-resource://ext/file.js',
        vscode.Uri.file('/ext'),
        new Map(),
        undefined
      )
    ).toBe('vscode-resource://ext/file.js');
  });

  it('resolves relative path against extension URI when no pluginId given', () => {
    const result = resolveGraphViewAssetPath(
      'dist/main.js',
      vscode.Uri.file('/my-extension'),
      new Map(),
      undefined
    );
    expect(result).toContain('/my-extension/dist/main.js');
  });

  it('resolves relative path against plugin URI when pluginId is provided', () => {
    const result = resolveGraphViewAssetPath(
      'dist/plugin.js',
      vscode.Uri.file('/my-extension'),
      new Map([['my-plugin', vscode.Uri.file('/plugin-dir')]]),
      undefined,
      'my-plugin'
    );
    expect(result).toContain('/plugin-dir/dist/plugin.js');
  });

  it('falls back to extension URI when pluginId is not found in the map', () => {
    const result = resolveGraphViewAssetPath(
      'dist/asset.js',
      vscode.Uri.file('/my-extension'),
      new Map(),
      undefined,
      'missing-plugin'
    );
    expect(result).toContain('/my-extension/dist/asset.js');
  });

  it('handles absolute paths by creating a file URI', () => {
    const result = resolveGraphViewAssetPath(
      '/absolute/path/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      undefined
    );
    expect(result).toContain('/absolute/path/file.js');
  });

  it('uses webview.asWebviewUri when webview is provided and returns a useful toString', () => {
    const webview = {
      asWebviewUri: vi.fn(() => ({
        toString: () => 'webview://converted-uri',
      })),
    };
    const result = resolveGraphViewAssetPath(
      'dist/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      webview as unknown as vscode.Webview
    );
    expect(result).toBe('webview://converted-uri');
  });

  it('falls back to fsPath when toString returns [object Object]', () => {
    const webview = {
      asWebviewUri: vi.fn(() => ({
        toString: () => '[object Object]',
        fsPath: '/fallback/path.js',
      })),
    };
    const result = resolveGraphViewAssetPath(
      'dist/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      webview as unknown as vscode.Webview
    );
    expect(result).toBe('/fallback/path.js');
  });

  it('falls back to path when toString returns empty string', () => {
    const webview = {
      asWebviewUri: vi.fn(() => ({
        toString: () => '',
        path: '/path-value/file.js',
      })),
    };
    const result = resolveGraphViewAssetPath(
      'dist/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      webview as unknown as vscode.Webview
    );
    expect(result).toBe('/path-value/file.js');
  });

  it('uses String() conversion when webviewUri has no usable properties', () => {
    const webview = {
      asWebviewUri: vi.fn(() => null),
    };
    const result = resolveGraphViewAssetPath(
      'dist/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      webview as unknown as vscode.Webview
    );
    expect(result).toBe('null');
  });

  it('falls back to fsPath when path is undefined', () => {
    const webview = {
      asWebviewUri: vi.fn(() => ({
        toString: () => '[object Object]',
        path: undefined,
        fsPath: '/fs-path/file.js',
      })),
    };
    const result = resolveGraphViewAssetPath(
      'dist/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      webview as unknown as vscode.Webview
    );
    expect(result).toBe('/fs-path/file.js');
  });

  it('prefers path over fsPath when both are available', () => {
    const webview = {
      asWebviewUri: vi.fn(() => ({
        toString: () => '[object Object]',
        path: '/path-value',
        fsPath: '/fsPath-value',
      })),
    };
    const result = resolveGraphViewAssetPath(
      'dist/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      webview as unknown as vscode.Webview
    );
    expect(result).toBe('/path-value');
  });

  it('returns String(webviewUri) when webviewUri has no toString function', () => {
    const webview = {
      asWebviewUri: vi.fn(() => 42),
    };
    const result = resolveGraphViewAssetPath(
      'dist/file.js',
      vscode.Uri.file('/ext'),
      new Map(),
      webview as unknown as vscode.Webview
    );
    // 42 is not a string, but typeof check catches it and skips.
    // Then it checks toString which is inherited from Number.prototype.
    // Number.toString() returns '42' which is non-empty and not '[object Object]'
    expect(result).toBe('42');
  });
});

describe('normalizeGraphViewExtensionUri (extra mutant coverage)', () => {
  it('returns undefined for empty string', () => {
    expect(normalizeGraphViewExtensionUri('')).toBeUndefined();
  });

  it('converts a string path to a vscode.Uri', () => {
    const result = normalizeGraphViewExtensionUri('/some/path');
    expect(result).toBeDefined();
    expect(result!.fsPath).toBe('/some/path');
  });

  it('returns the same URI object when given a URI', () => {
    const uri = vscode.Uri.file('/test');
    const result = normalizeGraphViewExtensionUri(uri);
    expect(result).toBe(uri);
  });
});

describe('getGraphViewUriKey (extra mutant coverage)', () => {
  it('prefers fsPath over path', () => {
    const uri = {
      fsPath: '/fs-path',
      path: '/path',
      toString: () => 'text',
    } as unknown as vscode.Uri;
    expect(getGraphViewUriKey(uri)).toBe('/fs-path');
  });

  it('falls back to path when fsPath is undefined', () => {
    const uri = {
      fsPath: undefined,
      path: '/path-value',
      toString: () => 'text',
    } as unknown as vscode.Uri;
    expect(getGraphViewUriKey(uri)).toBe('/path-value');
  });

  it('falls back to toString when both fsPath and path are undefined', () => {
    const uri = {
      fsPath: undefined,
      path: undefined,
      toString: () => 'stringified',
    } as unknown as vscode.Uri;
    expect(getGraphViewUriKey(uri)).toBe('stringified');
  });
});

