import * as fs from 'node:fs/promises';
import * as os from 'node:os';
import * as path from 'node:path';
import { afterAll, beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import { createCSharpPlugin } from '../../../../plugin-csharp/src/plugin';
import { createGDScriptPlugin } from '../../../../plugin-godot/src/plugin';
import { WorkspacePipeline } from '../../../src/extension/pipeline/service';
import { readWorkspaceAnalysisDatabaseSnapshot } from '../../../src/extension/pipeline/database/cache';

const sourceExamplesRoot = path.resolve(__dirname, '../../../../../examples');
const tempWorkspaceRoots: string[] = [];

let workspaceFoldersValue:
  | Array<{ uri: { fsPath: string; path: string }; name: string; index: number }>
  | undefined;

Object.defineProperty(vscode.workspace, 'workspaceFolders', {
  get: () => workspaceFoldersValue,
  configurable: true,
});

function createContext() {
  return {
    subscriptions: [],
    extensionUri: vscode.Uri.file('/test/extension'),
    workspaceState: {
      get: vi.fn(() => undefined),
      update: vi.fn(() => Promise.resolve()),
    },
  };
}

async function copyExamplesWorkspace(): Promise<string> {
  const workspaceRoot = await fs.mkdtemp(path.join(os.tmpdir(), 'codegraphy-examples-workspace-'));
  const targetPath = path.join(workspaceRoot, 'examples');
  await fs.cp(sourceExamplesRoot, targetPath, { recursive: true });
  tempWorkspaceRoots.push(targetPath);
  return targetPath;
}

afterAll(async () => {
  await Promise.all(
    tempWorkspaceRoots.splice(0).map((workspaceRoot) =>
      fs.rm(path.dirname(workspaceRoot), { recursive: true, force: true }),
    ),
  );
});

describe('WorkspacePipeline examples workspace', { timeout: 30000 }, () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  it('connects nested example projects when the repo-root examples folder is opened', async () => {
    const workspaceRoot = await copyExamplesWorkspace();
    workspaceFoldersValue = [
      { uri: vscode.Uri.file(workspaceRoot), name: 'examples', index: 0 },
    ];

    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );

    await analyzer.initialize();
    analyzer.registry.register(createGDScriptPlugin());

    const graph = await analyzer.analyze();
    const edgeIds = new Set(graph.edges.map((edge) => edge.id));

    const expectedEdgeIds = [
      'example-python/src/main.py->example-python/src/config.py#import',
      'example-python/src/main.py->example-python/src/services/api.py#import',
      'example-go/main.go->example-go/internal/service/service.go#import',
      'example-java/src/com/example/app/App.java->example-java/src/com/example/app/Helper.java#import',
      'example-java/src/com/example/app/App.java->example-java/src/com/example/app/BaseService.java#inherit',
      'example-rust/src/main.rs->example-rust/src/util.rs#import',
      'example-rust/src/main.rs->example-rust/src/inner.rs#import',
      'example-godot/scripts/player.gd->example-godot/scripts/utils/math_helpers.gd#load:static',
      'example-godot/scripts/enemy.gd->example-godot/scripts/base/entity.gd#inherit:static',
      'example-markdown/notes/Home.md->example-markdown/notes/Architecture.md#reference:static',
      'example-markdown/notes/Home.md->example-markdown/src/commented.ts#reference:static',
      'example-markdown/src/commented.ts->example-markdown/notes/Architecture.md#reference:static',
      'example-typescript/packages/app/src/index.ts->example-typescript/packages/app/src/utils.ts#import',
      'example-typescript/packages/app/src/index.ts->example-typescript/packages/shared/src/types.ts#import',
      'example-typescript/packages/app/src/utils.ts->example-typescript/packages/feature-depth/src/deep.ts#import',
    ];

    const missingEdgeIds = expectedEdgeIds.filter((edgeId) => !edgeIds.has(edgeId));
    expect(missingEdgeIds).toEqual([]);

    const persistedSnapshot = readWorkspaceAnalysisDatabaseSnapshot(workspaceRoot);
    const persistedTypeScriptFiles = persistedSnapshot.files
      .map(file => file.filePath)
      .filter(filePath => filePath.startsWith('example-typescript/'));

    expect(persistedTypeScriptFiles).toEqual(
      expect.arrayContaining([
        'example-typescript/packages/app/src/index.ts',
        'example-typescript/packages/app/src/orphan.ts',
        'example-typescript/packages/app/src/utils.ts',
        'example-typescript/packages/feature-depth/src/deep.ts',
        'example-typescript/packages/feature-depth/src/leaf.ts',
        'example-typescript/packages/shared/src/types.ts',
      ]),
    );
  });

  it('does not let plugin default filters hide monorepo source folders like packages', async () => {
    const workspaceRoot = await copyExamplesWorkspace();
    workspaceFoldersValue = [
      { uri: vscode.Uri.file(workspaceRoot), name: 'examples', index: 0 },
    ];

    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );

    await analyzer.initialize();
    analyzer.registry.register(createCSharpPlugin());

    const graph = await analyzer.analyze();
    const nodeIds = new Set(graph.nodes.map((node) => node.id));

    expect(nodeIds.has('example-typescript/packages/app/src/index.ts')).toBe(true);
    expect(nodeIds.has('example-typescript/packages/app/src/utils.ts')).toBe(true);
    expect(nodeIds.has('example-typescript/packages/shared/src/types.ts')).toBe(true);
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IDiscoveredFile } from '../../../src/core/discovery/contracts';
import type { IProjectedConnection, IFileAnalysisResult } from '../../../src/core/plugins/types/contracts';
import { createEmptyWorkspaceAnalysisCache } from '../../../src/extension/pipeline/cache';
import { analyzeWorkspaceFiles } from '../../../src/extension/pipeline/fileAnalysis';

function createFile(relativePath: string): IDiscoveredFile {
  const extensionIndex = relativePath.lastIndexOf('.');
  const slashIndex = relativePath.lastIndexOf('/');

  return {
    absolutePath: `/workspace/${relativePath}`,
    extension: extensionIndex >= 0 ? relativePath.slice(extensionIndex) : '',
    name: slashIndex >= 0 ? relativePath.slice(slashIndex + 1) : relativePath,
    relativePath,
  };
}

function createImportAnalysis(): IFileAnalysisResult {
  return {
    filePath: '/workspace/src/index.ts',
    relations: [
      {
        kind: 'import',
        sourceId: 'test-source',
        specifier: './utils',
        type: 'static',
        resolvedPath: '/workspace/src/utils.ts',
        fromFilePath: '/workspace/src/index.ts',
        toFilePath: '/workspace/src/utils.ts',
      },
    ],
  };
}

function createEmptyAnalysis(
  filePath = '/workspace/src/index.ts',
): IFileAnalysisResult {
  return {
    filePath,
    relations: [],
  };
}

describe('pipeline/fileAnalysis', () => {
  it('reuses cached connections and backfills missing size on cache hits', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    const cachedConnections: IProjectedConnection[] = [
      { specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , sourceId: 'test-source', kind: 'import' },
    ];
    const cachedAnalysis = createImportAnalysis();
    cache.files['src/index.ts'] = {
      mtime: 25,
      analysis: cachedAnalysis,
    };

    const readContent = vi.fn(async () => 'ignored');
    const analyzeFile = vi.fn(async () => ({
      filePath: '/workspace/src/index.ts',
      relations: [],
    }));

    const result = await analyzeWorkspaceFiles({
      analyzeFile,
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 25, size: 99 })),
      readContent,
      workspaceRoot: '/workspace',
    });

    expect(result.cacheHits).toBe(1);
    expect(result.cacheMisses).toBe(0);
    expect(result.fileConnections.get('src/index.ts')).toEqual(cachedConnections);
    expect(result.fileAnalysis.get('src/index.ts')).toEqual(cachedAnalysis);
    expect(cache.files['src/index.ts'].size).toBe(99);
    expect(readContent).not.toHaveBeenCalled();
    expect(analyzeFile).not.toHaveBeenCalled();
  });

  it('keeps the cached size when a cache hit already has size data', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    cache.files['src/index.ts'] = {
      mtime: 25,
      analysis: createEmptyAnalysis(),
      size: 12,
    };

    await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => createEmptyAnalysis()),
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 25, size: 99 })),
      readContent: vi.fn(async () => 'ignored'),
      workspaceRoot: '/workspace',
    });

    expect(cache.files['src/index.ts'].size).toBe(12);
  });

  it('analyzes uncached files and stores the new cache entry', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    const connections: IProjectedConnection[] = [
      { specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , sourceId: 'test-source', kind: 'import' },
    ];
    const analysis = createImportAnalysis();

    const result = await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => analysis),
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 50, size: 12 })),
      readContent: vi.fn(async () => "import './utils'"),
      workspaceRoot: '/workspace',
    });

    expect(result.cacheHits).toBe(0);
    expect(result.cacheMisses).toBe(1);
    expect(result.fileConnections.get('src/index.ts')).toEqual(connections);
    expect(result.fileAnalysis.get('src/index.ts')).toEqual(analysis);
    expect(cache.files['src/index.ts']).toEqual({
      mtime: 50,
      analysis,
      size: 12,
    });
  });

  it('treats stale cached entries as cache misses', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    cache.files['src/index.ts'] = {
      mtime: 25,
      analysis: createEmptyAnalysis(),
      size: 12,
    };
    const readContent = vi.fn(async () => "import './utils'");
    const analyzeFile = vi.fn(async () => ({
      filePath: '/workspace/src/index.ts',
      relations: [],
    }));

    const result = await analyzeWorkspaceFiles({
      analyzeFile,
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 30, size: 99 })),
      readContent,
      workspaceRoot: '/workspace',
    });

    expect(result.cacheHits).toBe(0);
    expect(result.cacheMisses).toBe(1);
    expect(readContent).toHaveBeenCalledTimes(1);
    expect(analyzeFile).toHaveBeenCalledTimes(1);
  });

  it('emits file processed payloads for analyzed files', async () => {
    const emitFileProcessed = vi.fn();
    const analysis = createImportAnalysis();

    await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => analysis),
      cache: createEmptyWorkspaceAnalysisCache(),
      emitFileProcessed,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 10, size: 1 })),
      readContent: vi.fn(async () => "import './utils'"),
      workspaceRoot: '/workspace',
    });

    expect(emitFileProcessed).toHaveBeenCalledWith({
      filePath: 'src/index.ts',
      connections: [
        {
          specifier: './utils',
          resolvedPath: '/workspace/src/utils.ts',
        },
      ],
    });
  });

  it('stores zero mtime when file stats are unavailable', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();

    await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => createEmptyAnalysis()),
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => null),
      readContent: vi.fn(async () => ''),
      workspaceRoot: '/workspace',
    });

    expect(cache.files['src/index.ts']).toEqual({
      mtime: 0,
      analysis: createEmptyAnalysis(),
      size: undefined,
    });
  });

  it('treats cached entries as misses when file stats are unavailable', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    cache.files['src/index.ts'] = {
      mtime: 25,
