          toSymbolId: 'symbol:src/utils/createFolder.ts:createFolder',
        },
      ],
    });

    expect(
      JSON.parse(withStableTimestamp(JSON.stringify(exportData, null, 2))),
    ).toMatchInlineSnapshot(`
      {
        "exportedAt": "<timestamp>",
        "files": [
