      _panels: [{ webview: { options: {} } }] as never,
    };
    const methods = createGraphViewProviderPluginResourceMethods(source as never, {
      registerBuiltInPluginRoots: vi.fn(),
      getPluginDefaultGroups: vi.fn(() => []),
      getBuiltInDefaultGroups: vi.fn(() => []),
