      _disabledPlugins: new Set<string>(),
      _userGroups: [],
      _hiddenPluginGroupIds: new Set<string>(),
      _groups: [],
      _view: undefined,
      _panels: [],
    } as never, {
      registerBuiltInPluginRoots: vi.fn(),
      getPluginDefaultGroups: vi.fn(() => []),
      getBuiltInDefaultGroups: vi.fn(() => []),
