import { beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import { WorkspacePipelineLifecycleFacade } from '../../../../src/extension/pipeline/service/lifecycleFacade';
import type { PluginRegistry } from '../../../../src/core/plugins/registry/manager';
import type { IWorkspaceAnalysisCache } from '../../../../src/extension/pipeline/cache';
import type { IDiscoveredFile } from '../../../../src/core/discovery/contracts';
import type {
  IFileAnalysisResult,
  IProjectedConnection,
} from '../../../../src/core/plugins/types/contracts';
import { clearWorkspacePipelineStoredCache } from '../../../../src/extension/pipeline/service/cachePersistence';
import {
  invalidateWorkspacePipelineFiles,
  resolveWorkspacePipelinePluginFilePaths,
} from '../../../../src/extension/pipeline/service/invalidation';
import {
  getWorkspacePipelinePluginName,
  getWorkspacePipelineStatusList,
} from '../../../../src/extension/pipeline/service/plugins';

vi.mock('../../../../src/extension/pipeline/service/cachePersistence', () => ({
  clearWorkspacePipelineStoredCache: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/service/invalidation', () => ({
  invalidateWorkspacePipelineFiles: vi.fn(),
  resolveWorkspacePipelinePluginFilePaths: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/service/plugins', () => ({
  getWorkspacePipelinePluginName: vi.fn(),
  getWorkspacePipelineStatusList: vi.fn(),
}));

vi.mock('vscode', () => ({
  workspace: {
    workspaceFolders: [{ uri: { fsPath: '/workspace' } }],
    getConfiguration: vi.fn(() => ({
      get: vi.fn(),
      update: vi.fn(),
      inspect: vi.fn(),
    })),
    createFileSystemWatcher: vi.fn(),
    onDidSaveTextDocument: vi.fn(),
    onDidChangeConfiguration: vi.fn(),
  },
}));

class TestLifecycleFacade extends WorkspacePipelineLifecycleFacade {
  readonly syncPluginOrder = vi.fn();
  readonly getWorkspaceRoot = vi.fn<() => string | undefined>(() => '/workspace');
  readonly persistCache = vi.fn();

  constructor() {
    super({
      subscriptions: [],
      workspaceState: {
        get: vi.fn(),
        update: vi.fn(),
      },
    } as never);
  }

  _registry = {
    list: vi.fn(() => []),
    disposeAll: vi.fn(),
    setPluginOrder: vi.fn(),
  } as unknown as PluginRegistry;
  _cache = { files: {} } as unknown as IWorkspaceAnalysisCache;
  _lastDiscoveredFiles = [
    { absolutePath: '/workspace/src/a.ts', relativePath: 'src/a.ts', extension: '.ts', name: 'a.ts' },
  ] as unknown as IDiscoveredFile[];
  _lastFileAnalysis = new Map([['src/a.ts', { id: 'analysis' }]]) as unknown as Map<
    string,
    IFileAnalysisResult
  >;
  _lastFileConnections = new Map([['src/a.ts', [{ id: 'edge' }]]]) as unknown as Map<
    string,
    IProjectedConnection[]
  >;
  _lastWorkspaceRoot = '/workspace';

  protected override _syncPluginOrder(): void {
    this.syncPluginOrder();
  }

  protected override _getWorkspaceRoot(): string | undefined {
    return this.getWorkspaceRoot();
  }

  protected override _persistCache(): void {
    this.persistCache();
  }
}

describe('pipeline/service/lifecycleFacade', () => {
  const lifecycleState = (
    facade: TestLifecycleFacade,
  ): {
    _lastDiscoveredFiles: IDiscoveredFile[];
    _registry: {
      list: ReturnType<typeof vi.fn>;
      disposeAll: ReturnType<typeof vi.fn>;
    };
  } => facade as unknown as {
    _lastDiscoveredFiles: IDiscoveredFile[];
    _registry: {
      list: ReturnType<typeof vi.fn>;
      disposeAll: ReturnType<typeof vi.fn>;
    };
  };

  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(clearWorkspacePipelineStoredCache).mockReturnValue({ files: { 'src/a.ts': { cached: true } } } as never);
    vi.mocked(getWorkspacePipelineStatusList).mockReturnValue([{ id: 'plugin.a' }] as never);
    vi.mocked(getWorkspacePipelinePluginName).mockReturnValue('TypeScript');
    vi.mocked(invalidateWorkspacePipelineFiles).mockReturnValue(['src/a.ts']);
    vi.mocked(resolveWorkspacePipelinePluginFilePaths).mockReturnValue(['/workspace/src/a.ts']);
  });

  it('returns plugin statuses after syncing plugin order', () => {
    const facade = new TestLifecycleFacade();
    const disabledPlugins = new Set(['plugin.disabled']);

    expect(facade.getPluginStatuses(disabledPlugins)).toEqual([{ id: 'plugin.a' }]);
    expect(facade.syncPluginOrder).toHaveBeenCalledOnce();
    expect(getWorkspacePipelineStatusList).toHaveBeenCalledWith(
      facade._registry,
      disabledPlugins,
      facade._lastDiscoveredFiles,
      facade._lastFileConnections,
    );
  });

  it('resolves plugin names using the cached workspace root and vscode workspace folders', () => {
    const facade = new TestLifecycleFacade();

    expect(facade.getPluginNameForFile('src/a.ts')).toBe('TypeScript');
    expect(getWorkspacePipelinePluginName).toHaveBeenCalledWith(
      'src/a.ts',
      '/workspace',
      facade._registry,
      vscode.workspace.workspaceFolders,
    );
  });

  it('replaces the cache through the stored-cache helper and logs its messages', () => {
    const facade = new TestLifecycleFacade();
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => undefined);

    facade.clearCache();

    expect(clearWorkspacePipelineStoredCache).toHaveBeenCalledWith(
      '/workspace',
      expect.any(Function),
    );
    const onMessage = vi.mocked(clearWorkspacePipelineStoredCache).mock.calls[0][1];
    onMessage('cache cleared');
    expect(logSpy).toHaveBeenCalledWith('cache cleared');
    expect(facade._cache).toEqual({ files: { 'src/a.ts': { cached: true } } });
  });

  it('short-circuits file invalidation when no workspace root exists or no files are provided', () => {
    const facade = new TestLifecycleFacade();
    facade.getWorkspaceRoot.mockReturnValue(undefined);

    expect(facade.invalidateWorkspaceFiles(['/workspace/src/a.ts'])).toEqual([]);
    expect(invalidateWorkspacePipelineFiles).not.toHaveBeenCalled();
  });

  it('returns an empty invalidation set when no file paths are provided even with a workspace root', () => {
    const facade = new TestLifecycleFacade();

    expect(facade.invalidateWorkspaceFiles([])).toEqual([]);
    expect(invalidateWorkspacePipelineFiles).not.toHaveBeenCalled();
  });

  it('invalidates workspace files and persists only when files were removed from the cache', () => {
    const facade = new TestLifecycleFacade();
    const toWorkspaceRelativePath = vi
      .spyOn(
        facade as unknown as {
          _toWorkspaceRelativePath: (workspaceRoot: string, filePath: string) => string | undefined;
        },
        '_toWorkspaceRelativePath',
      )
      .mockReturnValue('src/a.ts');

    expect(facade.invalidateWorkspaceFiles(['/workspace/src/a.ts'])).toEqual(['src/a.ts']);
    expect(invalidateWorkspacePipelineFiles).toHaveBeenCalledWith(
      {
        cache: facade._cache,
        lastFileAnalysis: facade._lastFileAnalysis,
        lastFileConnections: facade._lastFileConnections,
      },
      '/workspace',
      ['/workspace/src/a.ts'],
      expect.any(Function),
    );
    const relativePathResolver = vi.mocked(invalidateWorkspacePipelineFiles).mock.calls[0][3];
    expect(relativePathResolver('/workspace', '/workspace/src/a.ts')).toBe('src/a.ts');
    expect(toWorkspaceRelativePath).toHaveBeenCalledWith('/workspace', '/workspace/src/a.ts');
    expect(facade.persistCache).toHaveBeenCalledOnce();

    vi.mocked(invalidateWorkspacePipelineFiles).mockReturnValueOnce([]);
    expect(facade.invalidateWorkspaceFiles(['/workspace/src/b.ts'])).toEqual([]);
    expect(facade.persistCache).toHaveBeenCalledOnce();
  });

  it('returns early when plugin invalidation receives no plugin ids', () => {
    const facade = new TestLifecycleFacade();

    expect(facade.invalidatePluginFiles([])).toEqual([]);
    expect(lifecycleState(facade)._registry.list).not.toHaveBeenCalled();
    expect(resolveWorkspacePipelinePluginFilePaths).not.toHaveBeenCalled();
  });

  it('returns early when plugin invalidation has no discovered files', () => {
    const facade = new TestLifecycleFacade();

    lifecycleState(facade)._lastDiscoveredFiles = [];
    expect(facade.invalidatePluginFiles(['plugin.a'])).toEqual([]);
    expect(lifecycleState(facade)._registry.list).not.toHaveBeenCalled();
    expect(resolveWorkspacePipelinePluginFilePaths).not.toHaveBeenCalled();
  });

  it('returns early when plugin invalidation finds no matching plugins', () => {
    const facade = new TestLifecycleFacade();

    lifecycleState(facade)._lastDiscoveredFiles = [
      { absolutePath: '/workspace/src/a.ts', relativePath: 'src/a.ts', extension: '.ts', name: 'a.ts' },
    ];
    lifecycleState(facade)._registry.list.mockReturnValueOnce([
      { plugin: { id: 'plugin.other', supportedExtensions: ['.py'] } },
    ]);
    expect(facade.invalidatePluginFiles(['plugin.a'])).toEqual([]);
    expect(resolveWorkspacePipelinePluginFilePaths).not.toHaveBeenCalled();
  });

  it('resolves plugin file paths and invalidates them through the shared invalidation flow', () => {
    const facade = new TestLifecycleFacade();
    const invalidateWorkspaceFiles = vi.spyOn(facade, 'invalidateWorkspaceFiles');
    lifecycleState(facade)._registry.list.mockReturnValueOnce([
      { plugin: { id: 'plugin.a', supportedExtensions: ['.ts'] } },
      { plugin: { id: 'plugin.b', supportedExtensions: ['.py'] } },
    ]);

    expect(facade.invalidatePluginFiles(['plugin.a'])).toEqual(['src/a.ts']);
    expect(resolveWorkspacePipelinePluginFilePaths).toHaveBeenCalledWith(
      '/workspace',
      facade._lastDiscoveredFiles,
      [{ plugin: { id: 'plugin.a', supportedExtensions: ['.ts'] } }],
    );
    expect(invalidateWorkspaceFiles).toHaveBeenCalledWith(['/workspace/src/a.ts']);
  });

  it('disposes the plugin registry', () => {
    const facade = new TestLifecycleFacade();

    facade.dispose();

    expect(lifecycleState(facade)._registry.disposeAll).toHaveBeenCalledOnce();
  });
});

import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import type { IFileAnalysisResult } from '../../../../src/core/plugins/types/contracts';
import type { IGraphData } from '../../../../src/shared/graph/types';
import { WorkspacePipeline } from '../../../../src/extension/pipeline/service';
import * as pluginModule from '../../../../src/extension/pipeline/plugins/queries';
import * as runModule from '../../../../src/extension/pipeline/analysis/run';
import * as stateModule from '../../../../src/extension/pipeline/analysis/state';
import * as repoMetaModule from '../../../../src/extension/repoSettings/meta';
import * as gitExecModule from '../../../../src/extension/gitHistory/exec';

let workspaceFoldersValue:
  | Array<{ uri: { fsPath: string; path: string }; name: string; index: number }>
  | undefined;

Object.defineProperty(vscode.workspace, 'workspaceFolders', {
  get: () => workspaceFoldersValue,
  configurable: true,
});

function createContext() {
  return {
    subscriptions: [],
    extensionUri: vscode.Uri.file('/test/extension'),
    workspaceState: {
      get: vi.fn(() => undefined),
      update: vi.fn(() => Promise.resolve()),
    },
  };
}

function createGraph(): IGraphData {
  return {
    nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
    edges: [],
  };
}

describe('WorkspacePipeline delegates', () => {
  beforeEach(() => {
    workspaceFoldersValue = [
      { uri: vscode.Uri.file('/test/workspace'), name: 'workspace', index: 0 },
    ];
    vi.clearAllMocks();
    vi.spyOn(repoMetaModule, 'readCodeGraphyRepoMeta').mockReturnValue(
      repoMetaModule.createDefaultCodeGraphyRepoMeta(),
    );
    vi.spyOn(repoMetaModule, 'writeCodeGraphyRepoMeta').mockImplementation(() => {});
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('delegates analyze through the shared runner with the current workspace root', async () => {
    const context = createContext();
    const analyzer = new WorkspacePipeline(
      context as unknown as vscode.ExtensionContext,
    );
    const signal = new AbortController().signal;
    const disabledPlugins = new Set(['plugin.python']);
    const expectedGraph = createGraph();
    vi.spyOn(gitExecModule, 'execGitCommand').mockResolvedValue('abc123\n');
    const runSpy = vi
      .spyOn(runModule, 'runWorkspacePipelineAnalysis')
      .mockImplementation(
        async (
          source,
          cache,
          config,
          discovery,
          getWorkspaceRoot,
          filterPatterns,
          nextDisabledPlugins,
          nextProgress,
          nextSignal,
        ) => {
          expect(cache).toBe((analyzer as unknown as { _cache: unknown })._cache);
          expect(config).toBe((analyzer as unknown as { _config: unknown })._config);
          expect(discovery).toBe((analyzer as unknown as { _discovery: unknown })._discovery);
          expect(source._lastDiscoveredFiles).toBe(
            (analyzer as unknown as { _lastDiscoveredFiles: unknown })._lastDiscoveredFiles,
          );
          expect(source._lastFileAnalysis).toBe(
            (analyzer as unknown as { _lastFileAnalysis: unknown })._lastFileAnalysis,
          );
          expect(source._lastFileConnections).toBe(
            (analyzer as unknown as { _lastFileConnections: unknown })._lastFileConnections,
          );
          expect(source._lastWorkspaceRoot).toBe('');
          expect(getWorkspaceRoot()).toBe('/test/workspace');
          expect(filterPatterns).toEqual(['**/*.generated.ts']);
          expect(nextDisabledPlugins).toBe(disabledPlugins);
          expect(nextProgress).toBeUndefined();
          expect(nextSignal).toBe(signal);
          return expectedGraph;
        },
      );

    await expect(
      analyzer.analyze(['**/*.generated.ts'], disabledPlugins, signal),
    ).resolves.toEqual(expectedGraph);
    expect(runSpy).toHaveBeenCalledOnce();
    expect(repoMetaModule.writeCodeGraphyRepoMeta).toHaveBeenCalledWith(
      '/test/workspace',
      expect.objectContaining({
        lastIndexedAt: expect.any(String),
        lastIndexedCommit: 'abc123',
        pluginSignature: null,
        settingsSignature: expect.any(String),
      }),
    );
  });

  it('updates cached discovered files when the shared runner writes them back', async () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const discoveredFiles = [
      {
        absolutePath: '/test/workspace/src/index.ts',
        extension: '.ts',
        name: 'index.ts',
        relativePath: 'src/index.ts',
      },
    ];

    vi.spyOn(runModule, 'runWorkspacePipelineAnalysis').mockImplementation(async source => {
      source._lastDiscoveredFiles = discoveredFiles;
      return { nodes: [], edges: [] };
    });

    await analyzer.analyze();

    expect(
      (analyzer as unknown as { _lastDiscoveredFiles: unknown })._lastDiscoveredFiles,
    ).toBe(discoveredFiles);
  });

  it('updates cached file analysis and connections when the shared runner writes them back', async () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const fileAnalysis = new Map<string, IFileAnalysisResult>([
      ['src/index.ts', { filePath: '/test/workspace/src/index.ts', relations: [] }],
    ]);
    const fileConnections = new Map([
      [
        'src/index.ts',
        [
          {
            resolvedPath: '/test/workspace/src/utils.ts',
            specifier: './utils',
            type: 'static' as const,
            sourceId: 'import',
            kind: 'import' as const,
          },
        ],
      ],
    ]);

    vi.spyOn(runModule, 'runWorkspacePipelineAnalysis').mockImplementation(async source => {
      source._lastFileAnalysis = fileAnalysis;
      source._lastFileConnections = fileConnections;
      return { nodes: [], edges: [] };
    });

    await analyzer.analyze();

    expect(
      (analyzer as unknown as { _lastFileAnalysis: unknown })._lastFileAnalysis,
    ).toBe(fileAnalysis);
    expect(
      (analyzer as unknown as { _lastFileConnections: unknown })._lastFileConnections,
    ).toBe(fileConnections);
  });

  it('updates the cached workspace root when the shared runner writes it back', async () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const workspaceRoot = '/test/workspace';

    vi.spyOn(runModule, 'runWorkspacePipelineAnalysis').mockImplementation(async source => {
      source._lastWorkspaceRoot = workspaceRoot;
      return { nodes: [], edges: [] };
    });

    await analyzer.analyze();

    expect(
      (analyzer as unknown as { _lastWorkspaceRoot: unknown })._lastWorkspaceRoot,
    ).toBe(workspaceRoot);
  });

  it('delegates rebuildGraph through the cached rebuild source', () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const disabledPlugins = new Set(['plugin.python']);
    const expectedGraph = createGraph();
    const rebuildSpy = vi
      .spyOn(stateModule, 'rebuildWorkspacePipelineGraphForSource')
      .mockReturnValue(expectedGraph);

    expect(
      analyzer.rebuildGraph(disabledPlugins, false),
    ).toEqual(expectedGraph);
    const [source, nextDisabledPlugins, nextShowOrphans] =
      rebuildSpy.mock.calls[0];
    expect(source._lastFileAnalysis).toBe(
      (analyzer as unknown as { _lastFileAnalysis: unknown })._lastFileAnalysis,
    );
    expect(source._lastFileConnections).toBe(
      (analyzer as unknown as { _lastFileConnections: unknown })._lastFileConnections,
    );
    expect(source._lastWorkspaceRoot).toBe('');
    expect(nextDisabledPlugins).toBe(disabledPlugins);
    expect(nextShowOrphans).toBe(false);
  });

  it('delegates plugin status calculation through the current analyzer state', () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const analyzerPrivate = analyzer as unknown as {
      _lastDiscoveredFiles: Array<{ relativePath: string }>;
      _lastFileConnections: Map<string, never[]>;
      _lastWorkspaceRoot: string;
      _registry: unknown;
    };
    const disabledPlugins = new Set(['plugin.python']);
    const expectedStatuses = [{ id: 'plugin.typescript', status: 'active' }];

    analyzerPrivate._lastDiscoveredFiles = [{ relativePath: 'src/index.ts' }];
    analyzerPrivate._lastFileConnections = new Map([['src/index.ts', []]]);
    analyzerPrivate._lastWorkspaceRoot = '/test/workspace';

    const statusSpy = vi
      .spyOn(pluginModule, 'getWorkspacePipelinePluginStatuses')
      .mockReturnValue(expectedStatuses as never);

    expect(
      analyzer.getPluginStatuses(disabledPlugins),
    ).toEqual(expectedStatuses);
    expect(statusSpy).toHaveBeenCalledWith({
      disabledPlugins,
      discoveredFiles: analyzerPrivate._lastDiscoveredFiles,
      fileConnections: analyzerPrivate._lastFileConnections,
      registry: analyzerPrivate._registry,
    });
  });

  it('delegates plugin name lookup with the live workspace root callback', () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const analyzerPrivate = analyzer as unknown as {
      _lastWorkspaceRoot: string;
      _registry: unknown;
    };

    analyzerPrivate._lastWorkspaceRoot = '';

    const resolveSpy = vi
      .spyOn(pluginModule, 'resolveWorkspacePipelinePluginNameForFile')
      .mockImplementation((relativePath, lastWorkspaceRoot, getWorkspaceRoot, registry) => {
        expect(relativePath).toBe('src/index.ts');
        expect(lastWorkspaceRoot).toBe('');
        expect(getWorkspaceRoot()).toBe('/test/workspace');
        expect(registry).toBe(analyzerPrivate._registry);
        return 'TypeScript';
      });

    expect(analyzer.getPluginNameForFile('src/index.ts')).toBe('TypeScript');
    expect(resolveSpy).toHaveBeenCalledOnce();
  });

  it('delegates cache clearing and replaces the cached analysis state', () => {
    const context = createContext();
    const analyzer = new WorkspacePipeline(
      context as unknown as vscode.ExtensionContext,
    );
    const replacementCache = { version: '1.9.0', files: {} };
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => {});
    const clearSpy = vi
      .spyOn(stateModule, 'clearWorkspacePipelineCache')
      .mockImplementation((workspaceRoot, logInfo: (message: string) => void) => {
        expect(workspaceRoot).toBe('/test/workspace');
        logInfo('[CodeGraphy] Cache cleared');
        return replacementCache as never;
      });

    analyzer.clearCache();

    expect(clearSpy).toHaveBeenCalledOnce();
    expect(logSpy).toHaveBeenCalledWith('[CodeGraphy] Cache cleared');
    expect((analyzer as unknown as { _cache: unknown })._cache).toBe(replacementCache);
  });
});

